INSERT INTO `blogs` (`id`, `title`, `description`, `content`, `image`, `service_category_id`, `slug`, `created_at`, `updated_at`) VALUES
(17, 'เขื่อนกันดินไทรม้า 19 EP.1', 'สร้างเขื่อนกันดินซอยไทรม้า 19 ระยะความยาวทั้งหมด 49.5 เมตร', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    บันทึกหน้างาน EP.1: เริ่มต้นโปรเจกต์สร้างเขื่อนกำแพงกันดิน 49.5 เมตร ซอยไทรม้า 19 พร้อมเจาะลึกอุปสรรคใต้ผิวดิน\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-flag-checkered\"></i> อัปเดตการทำงานวันแรก (Day 1) | <i class=\"fa fa-map-marker\"></i> พิกัด: ซอยไทรม้า 19 จังหวัดนนทบุรี\n                </p>\n            </div>\n\n            <div class=\"lead\" style=\"line-height: 1.8; background-color: #f8f9fa; padding: 25px; border-left: 5px solid #0056b3; border-radius: 4px; margin-bottom: 30px;\">\n                <p style=\"margin-bottom: 0;\">\n                    จุดเริ่มต้นของความมั่นคง เริ่มต้นที่รากฐานที่ดี! วันนี้ทีมงาน <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> ขอพาทุกท่านลงพื้นที่จริง ประเดิมวันแรก (Day 1) ของโปรเจกต์ก่อสร้าง <a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\" style=\"color: #0056b3; font-weight: bold;\">เขื่อนและกำแพงกันดิน</a> โครงการใหญ่ ณ ซอยไทรม้า 19 \n                    <br><br>\n                    ใน EP.1 นี้ เราจะพาไปดูธรรมเนียมปฏิบัติก่อนเริ่มงานก่อสร้าง เจาะลึกสเปกโครงสร้างระดับวิศวกรรมที่ใช้รับมือกับแรงดันดิน และพาวิเคราะห์ <strong>\"2 อุปสรรคสุดหิน\"</strong> ที่ซ่อนอยู่ใต้ผิวดิน ซึ่งทีมงานของเราต้องเตรียมรับมืออย่างเร่งด่วนครับ\n                </p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. ฤกษ์งามยามดี: การบวงสรวงเจ้าที่ เพื่อขวัญกำลังใจและความปลอดภัยสูงสุด (Zero Accident)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ในวงการรับเหมาก่อสร้างของไทย ไม่ว่าเทคโนโลยีและเครื่องจักรจะก้าวล้ำไปไกลแค่ไหน สิ่งหนึ่งที่ทีมงานมืออาชีพไม่เคยละทิ้งคือ <strong>\"ความเคารพต่อสถานที่\"</strong> \n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ก่อนที่เครื่องจักรหนักจะสตาร์ทเครื่องยนต์ ทีมงานธีรพงษ์เซอร์วิสได้จัดเตรียมเครื่องเซ่นไหว้ เพื่อทำพิธีบอกกล่าวและขอขมาเจ้าที่เจ้าทาง สิ่งศักดิ์สิทธิ์ที่ปกปักรักษาพื้นที่บริเวณซอยไทรม้า 19 พิธีกรรมนี้นอกจากจะเป็นสิริมงคลตามความเชื่อแล้ว ในมิติของการทำงาน ยังเป็นการ <strong>\"สร้างขวัญและกำลังใจ\"</strong> ให้กับทีมช่างและพนักงานขับเครื่องจักรทุกคน ให้มีความรอบคอบ มีสติ และตั้งเป้าหมายการทำงานภายใต้มาตรฐานความปลอดภัยสูงสุด (Zero Accident) ตลอดทั้งโครงการครับ\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/28165.webp\" alt=\"พิธีไหว้เจ้าที่ก่อนเริ่มงานก่อสร้างกำแพงกันดิน ซอยไทรม้า 19\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 400px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 1: พิธีไหว้บอกกล่าวสิ่งศักดิ์สิทธิ์ เพื่อความราบรื่นและปลอดภัยก่อนเริ่มลุยหน้างาน</em></p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. สแกนสเปกโครงสร้าง: เขื่อนกันดินยาว 49.5 เมตร พร้อมระบบสเตย์เต็มรูปแบบ\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                สำหรับรายละเอียดของโปรเจกต์ไทรม้า 19 นี้ ถือเป็นงานสเกลระดับกลางค่อนไปทางใหญ่ โดยมีโจทย์คือการสร้างแนวป้องกันดินสไลด์และปรับระดับพื้นที่ให้สวยงาม มั่นคง โดยมีรายละเอียดทางวิศวกรรมที่น่าสนใจดังนี้:\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-6\">\n                    <ul class=\"list-group\" style=\"font-size: 16px;\">\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\"><i class=\"fa fa-arrows-h\"></i> ความยาวรวม 49.5 เมตร</h4>\n                            <p style=\"margin-bottom: 0;\">เป็นระยะทางที่ต้องใช้การวางแผนแนวระดับ (Alignment) ที่แม่นยำ เพื่อไม่ให้กำแพงคดเคี้ยว หรือเกิดการทรุดตัวไม่เท่ากัน (Differential Settlement) ตลอดแนว</p>\n                        </li>\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\"><i class=\"fa fa-anchor\"></i> เสาเข็มไมโครไพล์ I22 (จำนวน 110 ต้น)</h4>\n                            <p style=\"margin-bottom: 0;\">เราเลือกใช้ <strong>เสาเข็มหน้าตัดตัวไอ ขนาด 22x22 ซม. (Micropile I22)</strong> ความยาว 10 เมตร ซึ่งมีข้อดีคือรูปทรงตัวไอจะช่วยเพิ่มพื้นที่ผิวสัมผัส (Surface Area) สร้างค่าความฝืดกับชั้นดินได้มหาศาล รองรับน้ำหนักได้ดีกว่าเข็มหน้าตัดทั่วไป</p>\n                        </li>\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-danger\" style=\"font-weight: bold; margin-top: 0;\"><i class=\"fa fa-link\"></i> ระบบสเตย์ดึงรั้ง \"ทุกต้น\"</h4>\n                            <p style=\"margin-bottom: 0;\">เพื่อความแข็งแกร่งระดับสูงสุด เราไม่ได้ทำสเตย์แบบเว้นระยะ แต่เราออกแบบให้มีการตอกเสาเข็มสเตย์และหล่อคานดึงรั้ง <strong>\"ประกบเสาเข็มหลักทุกต้น\"</strong> เพื่อรับแรงอัดจากมวลดินด้านข้างได้อย่างสมบูรณ์แบบ ไร้กังวลเรื่องกำแพงแบะล้ม 100%</p>\n                        </li>\n                    </ul>\n                </div>\n                <div class=\"col-md-6 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/saima-19-bobby.webp\" alt=\"สภาพหน้างานโครงการสร้างเขื่อนกันดิน ซอยไทรม้า 19\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 10px rgba(0,0,0,0.1); margin-bottom: 15px;\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/28165.webp\" alt=\"เตรียมความพร้อมเครื่องจักรและหน้างาน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 2-3: สภาพหน้างานวันแรก ที่รอการปรับพื้นที่และลงเสาเข็มทั้ง 110 ต้น</em></p>\n                </div>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. ความท้าทายหน้างาน: 2 อุปสรรคใหญ่ที่ซ่อนอยู่ใต้ผิวดิน!\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลังจากทำพิธีเปิดไซต์งานและเตรียมนำเครื่องจักรเข้าพื้นที่ ทีมสำรวจของเราได้ทำการเช็กสภาพพื้นผิวและแนวตอกเข็มอย่างละเอียด ซึ่งก็พบกับ <strong>\"อุปสรรคสุดหิน 2 ประการ\"</strong> ที่ทำให้แผนการทำงานปกติไม่สามารถเดินหน้าได้ทันที:\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-warning\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title\" style=\"font-weight: bold; color: #8a6d3b;\"><i class=\"fa fa-exclamation-triangle\"></i> อุปสรรคที่ 1: สภาพดินเดิมเป็น \"ดินเลน\"</h4></div>\n                        <div class=\"panel-body\" style=\"font-size: 15px; line-height: 1.6;\">\n                            พื้นที่บริเวณนี้เคยมีการนำ <a href=\"https://www.theeraphong.com/รับถมดิน\" target=\"_blank\" style=\"color: #c9302c; font-weight: bold; text-decoration: underline;\">ดินถม</a> มาลงไว้ก่อนหน้านี้ แต่วัสดุที่ใช้ถมกลับมีลักษณะเป็น <strong>\"ดินเลน (Soft Mud)\"</strong> ที่อุ้มน้ำและไม่มีความหนาแน่น <br><br>\n                            <strong>ผลกระทบ:</strong> ดินประเภทนี้ไม่มีกำลังรับน้ำหนัก (Bearing Capacity ต่ำมาก) หากนำรถแบคโฮหรือเครื่องจักรกดเสาเข็มเข้าไปวิ่งโดยตรง รถมีโอกาสจมโคลนลึก หรือพลิกคว่ำได้ ซึ่งอันตรายต่อทั้งทีมงานและเครื่องจักรอย่างยิ่ง\n                        </div>\n                    </div>\n                </div>\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-warning\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title\" style=\"font-weight: bold; color: #8a6d3b;\"><i class=\"fa fa-exclamation-triangle\"></i> อุปสรรคที่ 2: \"หินขนาดใหญ่\" ใต้แนวสันเขื่อนเดิม</h4></div>\n                        <div class=\"panel-body\" style=\"font-size: 15px; line-height: 1.6;\">\n                            เมื่อทำการขุดสำรวจตามแนวพิกัดที่จะต้องกดเสาเข็ม เราพบว่าภายใต้ชั้นดินนั้น มี <strong>แนวหินทิ้งขนาดใหญ่</strong> ที่หลงเหลือมาจากการทำสันเขื่อนหรือการถมในอดีต ซ่อนตัวอยู่เป็นจำนวนมาก <br><br>\n                            <strong>ผลกระทบ:</strong> การกดเสาเข็มไมโครไพล์ I22 หากปลายเข็มปะทะเข้ากับก้อนหินแข็ง จะทำให้เกิดปัญหา \"เสาเข็มหนีศูนย์ (เยื้องศูนย์)\" ทำให้แนวกำแพงบิดเบี้ยว หรือเลวร้ายที่สุดคือเสาเข็มแตกหักใต้ดินจนสูญเสียความแข็งแรง\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <div class=\"alert alert-info\" style=\"margin-top: 40px; border-left: 5px solid #31708f; padding: 25px;\">\n                <h3 style=\"color: #31708f; margin-top: 0;\"><i class=\"fa fa-cogs\"></i> บทสรุป EP.1 และความน่าติดตามในตอนต่อไป</h3>\n                <p style=\"font-size: 16px; line-height: 1.8; margin-bottom: 0;\">\n                    ปัญหา <strong>\"ดินเลนอ่อนยวบ\"</strong> และ <strong>\"กองหินใต้น้ำ\"</strong> คือฝันร้ายที่สามารถทำให้ผู้รับเหมาหลายรายต้องทิ้งงาน แต่สำหรับทีมงานมืออาชีพอย่าง <strong>ธีรพงษ์เซอร์วิส</strong> อุปสรรคเหล่านี้คือความท้าทายที่เราเตรียมแผนสำรองไว้เสมอ! \n                    <br><br>\n                    <strong>วิธีการแก้ไขปัญหา (Problem Solving)</strong> ของทีมวิศวกรและช่างควบคุมเครื่องจักรของเราจะเป็นอย่างไร? เราจะฝ่าด่านดินเลนและจัดการกับหินใต้ดินเพื่อกดเสาเข็มทั้ง 110 ต้นให้สำเร็จได้อย่างไร? <br>\n                    👉 <strong>รอติดตามคำตอบและเทคนิคเชิงช่างสุดเจ๋งได้ใน <a href=\"#\" style=\"color: #c9302c; font-weight: bold;\">อัปเดตงานกำแพงกันดิน ซอยไทรม้า 19 (EP.2)</a> เร็วๆ นี้ครับ!</strong>\n                </p>\n            </div>\n\n            <div style=\"background-color: #f9f9f9; padding: 30px; border-radius: 8px; margin-top: 50px; border: 1px solid #eaeaea;\">\n                <h3 style=\"color: #333; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> ถาม-ตอบ (FAQ) ความรู้ก่อนเริ่มสร้างกำแพงกันดิน</h3>\n                <hr style=\"border-color: #ddd;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: ทำไมต้องใช้ เสาเข็มไมโครไพล์ (Micropile) ในการทำกำแพงกันดิน?</h4>\n                <p style=\"margin-bottom: 20px;\">A: ไมโครไพล์ถูกออกแบบมาเพื่อหน้างานที่มีพื้นที่จำกัด หรือเข้าถึงยากครับ นอกจากนี้ การใช้ระบบ \"กดเข็ม (Hydraulic Static Pile)\" แทนการตอกด้วยตุ้มน้ำหนัก จะช่วยลดแรงสั่นสะเทือน (Low Vibration) ไม่ทำให้บ้านเรือนข้างเคียงเกิดรอยร้าว ซึ่งเหมาะมากสำหรับหน้างานในซอยชุมชนอย่างซอยไทรม้าครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: หากดินถมเดิมเป็นดินเลน สามารถเทคอนกรีตทับเลยได้ไหม?</h4>\n                <p>A: <strong>ไม่ได้เด็ดขาดครับ</strong> ดินเลนมีการทรุดตัวสูงมาก หากเทคอนกรีตทับโดยไม่ปรับปรุงคุณภาพดิน หรือไม่มีเสาเข็มรองรับ ในเวลาไม่นานโครงสร้างคอนกรีตจะเกิดการแตกร้าวและทรุดตามชั้นดินอย่างแน่นอน ต้องมีการปูแผ่นกระจายน้ำหนัก หรือขุดลอกดินเลนออกก่อนเริ่มงานครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-top: 5px solid #0056b3; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #2c3e50; font-weight: bold;\">มองหาทีมงานรับเหมาที่ \"ไม่หนีปัญหา\" ใช่หรือไม่?</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    งานฐานรากและกำแพงกันดิน มักมาพร้อมกับอุปสรรคที่คาดไม่ถึงเสมอ <br>\n                    เลือกทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> ที่มีประสบการณ์ตรง มีเครื่องจักรพร้อมลุย และมีความรับผิดชอบ ไม่ทิ้งงาน!\n                </p>\n                \n                <div class=\"row\">\n                    <div class=\"col-sm-6 text-right\">\n                        <a href=\"https://www.theeraphong.com/retaining-wall\" class=\"btn btn-primary btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px; width: 100%; max-width: 350px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                            <i class=\"fa fa-shield\"></i> บริการรับทำกำแพงกันดิน\n                        </a>\n                    </div>\n                    <div class=\"col-sm-6 text-left\">\n                        <a href=\"https://www.theeraphong.com/images/pile\" class=\"btn btn-info btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px; width: 100%; max-width: 350px; background-color: #17a2b8; border-color: #17a2b8; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                            <i class=\"fa fa-cogs\"></i> บริการกดเสาเข็มไมโครไพล์\n                        </a>\n                    </div>\n                </div>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1710671722259177.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP1', '2021-09-12 05:14:45', '2021-09-12 09:10:06'),
(18, 'เขื่อนกันดินไทรม้า 19 EP.2', 'อัพเดทงานสร้างเขื่อนกันดิน ซอยไทรม้า 19', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    เจาะลึกงานฐานรากเขื่อนกันดิน: ลุยเคลียร์หินใต้น้ำ เตรียมกดเสาเข็มไอ (Micropile) 110 ต้น พร้อมเทคนิคหล่อแผ่นเสียบหน้างาน\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-calendar\"></i> อัปเดตข้อมูลหน้างานประจำวันที่ 14-09-2021 | <i class=\"fa fa-wrench\"></i> หมวดหมู่: อัปเดตผลงาน, เทคนิคงานฐานราก\n                </p>\n            </div>\n\n            <div class=\"lead\" style=\"line-height: 1.8; background-color: #f8fcf8; padding: 25px; border-left: 5px solid #5cb85c; border-radius: 4px; margin-bottom: 30px;\">\n                <p style=\"margin-bottom: 0;\">\n                    การสร้าง <strong>\"เขื่อนกำแพงกันดิน\"</strong> ในพื้นที่ที่อยู่ติดแหล่งน้ำหรือมีระดับดินต่างกันมาก จำเป็นต้องอาศัยรากฐานที่แข็งแกร่งที่สุดเพื่อต้านทานแรงดันมหาศาล วันนี้ทีมงาน <a href=\"https://www.theeraphong.com/\" target=\"_blank\" style=\"color: #2e6da4; font-weight: bold;\">ธีรพงษ์เซอร์วิส (Theeraphong Service)</a> จะพาทุกท่านมาเกาะติดสถานการณ์หน้างานจริง กับภารกิจการเตรียมความพร้อมในขั้นตอนที่สำคัญที่สุด นั่นคือ <strong>\"งานกดเสาเข็มไมโครไพล์ (Micropile)\"</strong> และ <strong>\"การเตรียมโครงเหล็กหล่อแผ่นเสียบ\"</strong> มาดูกันว่าทีมงานมืออาชีพมีวิธีรับมือกับอุปสรรคใต้น้ำ และบริหารเวลาอย่างไรให้งานออกมาได้มาตรฐานและตรงตามกำหนดเวลาครับ!\n                </p>\n            </div>\n\n            <h2 style=\"color: #2e6da4; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. ภารกิจลำเลียง: ขนย้ายเสาเข็มไอ (I-Shape Micropile) ความยาว 10 เมตร เข้าสู่พื้นที่\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เริ่มต้นวันทำงานด้วยการวางแผนด้านโลจิสติกส์ (Logistics) ทางทีมงานได้เริ่มดำเนินการขนย้าย <strong>เสาเข็มหน้าตัดรูปตัวไอ (I-Shape Micropile)</strong> เข้าสู่พื้นที่หน้างานอย่างเป็นระบบ สำหรับโปรเจกต์นี้ เราเลือกใช้เสาเข็มที่มีความยาวถึง <strong>10 เมตร</strong> จำนวนรวมทั้งสิ้น <strong>110 ต้น</strong> \n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-6 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/saima-19-15092021-2.webp\" alt=\"การลำเลียงและเตรียมความพร้อม เสาเข็มไอ (Micropile) ความยาว 10 เมตร\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 10px rgba(0,0,0,0.1); margin-bottom: 15px;\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>ภาพที่ 1: กองเสาเข็มไอ (I-Shape Micropile) ที่ถูกจัดเรียงอย่างเป็นระเบียบ เตรียมพร้อมสำหรับการกดลงดิน</em></p>\n                </div>\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-info\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title\" style=\"font-weight: bold;\"><i class=\"fa fa-info-circle\"></i> ทำไมถึงต้องเป็นเสาเข็มตัวไอ (I-Shape)?</h4></div>\n                        <div class=\"panel-body\" style=\"font-size: 15px; line-height: 1.6;\">\n                            ในงานกำแพงกันดิน เสาเข็มไม่ได้ทำหน้าที่แค่รับน้ำหนักในแนวดิ่ง (Vertical Load) แต่ต้องรับ <strong>แรงดัด (Bending Moment)</strong> และแรงดันดินด้านข้าง (Lateral Earth Pressure) ด้วย <br><br>\n                            เสาเข็มหน้าตัดตัวไอ มีคุณสมบัติเด่นคือมีพื้นที่ผิวสัมผัส (Surface Area) กับดินที่มากกว่าเสาเข็มสี่เหลี่ยมตัน ทำให้เกิด <strong>\"ค่าความฝืด (Skin Friction)\"</strong> ที่สูงมาก ช่วยยึดเกาะกับชั้นดินได้อย่างเหนียวแน่น ป้องกันการเคลื่อนตัวของกำแพงได้อย่างมีประสิทธิภาพสูงสุดครับ\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <h2 style=\"color: #2e6da4; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. เผชิญหน้าอุปสรรค: ภารกิจเคลียร์ \"หินใต้น้ำ\" ก่อนเริ่มกดเข็ม\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ในการทำงานจริงมักไม่ได้โรยด้วยกลีบกุหลาบเสมอไป หลังจากทีมสำรวจได้เช็กระดับและแนวแกนที่จะทำการกดเสาเข็ม เราได้พบกับปัญหาสำคัญคือ <strong>\"แนวหินก้อนใหญ่ที่ทับถมอยู่ด้านล่างใต้น้ำ\"</strong> ซึ่งคาดว่าเป็นเศษวัสดุจากการทำสันเขื่อนหรือการถมที่ในอดีต\n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                <strong>ความเสี่ยงทางวิศวกรรม:</strong> หากเราดึงดันที่จะกดเสาเข็มลงไปโดยไม่นำหินเหล่านี้ออกก่อน ปลายเสาเข็มจะไปปะทะกับก้อนหิน ทำให้เกิดปัญหา <strong>เสาเข็มหนีศูนย์ (Pile Deviation)</strong> หรือเลวร้ายที่สุดคือเสาเข็มหักร้าวใต้ผิวดิน ซึ่งจะทำให้ฐานรากจุดนั้นสูญเสียความสามารถในการรับน้ำหนักไปในทันที\n            </p>\n\n            <div class=\"alert alert-warning\" style=\"margin-top: 20px; border-left: 5px solid #f0ad4e;\">\n                <h4 style=\"color: #c12e2a; margin-top: 0; font-weight: bold;\"><i class=\"fa fa-exclamation-triangle\"></i> วิธีการแก้ปัญหาของทีมงานธีรพงษ์เซอร์วิส</h4>\n                <p style=\"font-size: 16px; margin-bottom: 0; line-height: 1.6;\">\n                    เพื่อความสมบูรณ์แบบของโครงสร้าง เราได้สั่งหยุดการกดเข็มชั่วคราว และปรับแผนโดยนำ <strong>รถแบคโฮ (แมคโคร)</strong> เข้ามาทำการงมและตักหินใต้น้ำในแนวพิกัดเสาเข็มออกให้หมด (Clearing) เพื่อเปิดชั้นดินให้โล่งที่สุด แม้ขั้นตอนนี้จะทำให้เสียเวลาเพิ่มขึ้น แต่เพื่อแลกกับความปลอดภัยและความแข็งแรงร้อยเปอร์เซ็นต์ของกำแพงกันดิน ถือเป็นขั้นตอนที่ \"ข้ามไม่ได้เด็ดขาด\" ครับ\n                </p>\n            </div>\n\n            <h2 style=\"color: #2e6da4; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. แผนการดำเนินงาน: กดเสาเข็ม 110 ต้น ภายใน 4-5 วัน\n            </h2>\n            \n            <p style=\"line-height: 1.8; font-size: 16px; margin-top: 20px;\">\n                หลังจากเคลียร์สิ่งกีดขวางใต้น้ำเสร็จสิ้น ทีมงานจะเข้าสู่กระบวนการนำรถแบคโฮ (แมคโคร) มากดเสาเข็มไอ (Hydraulic Static Pile Driving) การใช้น้ำหนักและระบบไฮดรอลิกของรถแบคโฮในการกดเข็ม มีข้อดีอย่างมหาศาลคือ <strong>\"ก่อให้เกิดแรงสั่นสะเทือนต่ำ (Low Vibration)\"</strong> และไม่มีเสียงดังรบกวนเหมือนการใช้ปั้นจั่นตอก จึงปลอดภัยต่อโครงสร้างบ้านเรือนข้างเคียง\n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ด้วยความชำนาญของทีมช่างและคนขับเครื่องจักร เราได้วางไทม์ไลน์ประเมินการทำงานไว้ว่า การกดเสาเข็มทั้งหมด <strong>110 ต้น</strong> จะใช้เวลาดำเนินการเพียง <strong>4-5 วัน โดยประมาณ</strong> (เฉลี่ยกดได้ 20-25 ต้นต่อวัน) ซึ่งถือเป็นอัตราความเร็วที่ยอดเยี่ยม ช่วยให้เจ้าของโครงการประหยัดเวลาและลดความกังวลเรื่องผลกระทบต่อชุมชนรอบข้างได้อย่างดีครับ\n            </p>\n\n            <h2 style=\"color: #2e6da4; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                4. การบริหารเวลาแบบมืออาชีพ: เตรียมพื้นที่ \"หล่อแผ่นเสียบ\" แบบคู่ขนาน\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เสน่ห์ของการบริหารโครงการก่อสร้าง (Construction Management) คือการไม่ปล่อยให้เวลาสูญเปล่า ในขณะที่ทีมเครื่องจักรกำลังเตรียมการเรื่องการกดเสาเข็ม อีกด้านหนึ่งของพื้นที่หน้างาน <strong>\"ทีมช่างโครงสร้าง\"</strong> ก็ได้ตระเตรียมพื้นที่และอุปกรณ์สำหรับ <strong>การหล่อแผ่นเสียบกำแพงกันดิน (Precast Concrete Panels)</strong> ควบคู่กันไปทันทีครับ\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-6 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/saima-19-15092021-3.webp\" alt=\"การเตรียมพิมพ์หล่อแผ่นเสียบ และโครงเหล็กมาตรฐาน สำหรับงานกำแพงกันดิน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 10px rgba(0,0,0,0.1); margin-bottom: 15px;\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>ภาพที่ 2: พิมพ์หล่อและโครงเหล็กคุณภาพดี ที่เตรียมไว้สำหรับการเทปูนหล่อแผ่นเสียบหน้างาน</em></p>\n                </div>\n                <div class=\"col-md-6\">\n                    <h4 style=\"font-weight: bold; color: #333; margin-top: 0;\">มาตรฐานการหล่อแผ่นเสียบของธีรพงษ์เซอร์วิส</h4>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        หลายคนอาจสงสัยว่าทำไมเราถึงเลือกหล่อแผ่นเสียบที่หน้างาน (On-site Casting) แทนการซื้อแผ่นสำเร็จรูป? เหตุผลคือ:\n                    </p>\n                    <ul style=\"line-height: 1.8; font-size: 16px;\">\n                        <li><strong>การควบคุมคุณภาพเหล็กเสริม:</strong> เราสามารถใช้โครงเหล็กที่มีคุณภาพดี ผูกเหล็กได้ความถี่และระยะหุ้มคอนกรีต (Covering) ตามมาตรฐานวิศวกรรมเป๊ะๆ</li>\n                        <li><strong>ขนาดที่พอดี (Custom Fit):</strong> แผ่นเสียบที่หล่อจากพิมพ์มาตรฐานหน้างาน จะมีความหนาและขนาดที่สอดรับกับร่องของเสาเข็มไอได้สนิทพอดี ป้องกันดินรั่วไหล</li>\n                        <li><strong>จังหวะเวลาที่สมบูรณ์แบบ:</strong> ช่วงเวลาที่เราหล่อแผ่นเสียบทิ้งไว้ จะสอดคล้องกับระยะเวลา 4-5 วันที่ใช้กดเสาเข็มพอดี เมื่อกดเข็มเสร็จ คอนกรีตของแผ่นเสียบก็จะ <strong>เซ็ตตัวและได้ค่าความแข็งแรง (Compressive Strength)</strong> พร้อมนำไปเสียบประกอบได้ทันทีอย่างไร้รอยต่อครับ!</li>\n                    </ul>\n                </div>\n            </div>\n            \n\n            <div style=\"background-color: #f4f8fa; padding: 30px; border-radius: 8px; margin-top: 50px; border: 1px solid #bce8f1;\">\n                <h3 style=\"color: #31708f; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> คำถามที่พบบ่อย (FAQ) งานกดเสาเข็มกำแพงกันดิน</h3>\n                <hr style=\"border-color: #9acfea;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: การกดเสาเข็มด้วยรถแมคโคร แข็งแรงสู้การตอกด้วยปั้นจั่นได้หรือไม่?</h4>\n                <p style=\"margin-bottom: 20px;\">A: แข็งแรงเท่าเทียมกันครับ หากกดจนถึงชั้นดินดานหรือชั้นดินที่ออกแบบไว้ (Pile Blow Count / Refusal) ข้อดีของการใช้แมคโครกดคือ ช่วยลดแรงกระแทกที่อาจทำให้หัวเข็มแตก และไม่สร้างแรงสั่นสะเทือนทำลายโครงสร้างบ้านเรือนที่อยู่ใกล้เคียงครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: แผ่นเสียบกำแพงกันดิน มีอายุการใช้งานนานเท่าไหร่?</h4>\n                <p>A: หากมีการผูกเหล็กเสริมอย่างถูกต้อง และเทคอนกรีตที่มีกำลังอัด (Strength) หนาแน่นเพียงพอ แผ่นเสียบเหล่านี้จะมีอายุการใช้งานทนทานยาวนานหลายสิบปีโดยไม่เปื่อยยุ่ยหรือทะลุครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-top: 5px solid #5cb85c; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #2c3e50; font-weight: bold;\">มาตรฐานงานฐานราก ที่คุณวางใจได้ 100%</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    ไม่ว่าหน้างานจะมีอุปสรรคใต้น้ำ หรือต้องใช้เทคนิคการทำงานที่ซับซ้อน <br>\n                    ทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> มีทั้งเครื่องจักรหนักและทีมช่างประสบการณ์สูง พร้อมลุยทุกสถานการณ์\n                </p>\n                \n                <div class=\"row\">\n                    <div class=\"col-sm-6 text-right\">\n                        <a href=\"https://www.theeraphong.com/retaining-wall\" class=\"btn btn-success btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px; width: 100%; max-width: 350px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                            <i class=\"fa fa-shield\"></i> ดูบริการรับทำกำแพงกันดิน\n                        </a>\n                    </div>\n                    <div class=\"col-sm-6 text-left\">\n                        <a href=\"https://www.theeraphong.com/images/pile\" class=\"btn btn-primary btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px; width: 100%; max-width: 350px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                            <i class=\"fa fa-cogs\"></i> ดูผลงานกดเสาเข็มไมโครไพล์\n                        </a>\n                    </div>\n                </div>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1710950087706025.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP2', '2021-09-15 06:59:15', '2021-09-15 06:59:15'),
(19, 'เขื่อนกันดินไทรม้า 19 EP.3', 'แก้ไขปัญหาหินใต้น้ำ งานสร้างเขื่อนกันดิน ซอยไทรม้า 19', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    เจาะลึกการแก้ปัญหาหน้างาน: ลุยเคลียร์หินใต้น้ำ และกดเสาเข็มไมโครไพล์ (Micropile) งานกำแพงกันดิน\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-wrench\"></i> อัปเดตความคืบหน้าหน้างาน | <i class=\"fa fa-map-marker\"></i> การแก้ปัญหาโครงสร้างและงานฐานราก\n                </p>\n            </div>\n\n            <p class=\"lead\" style=\"line-height: 1.8;\">\n                ในการรับเหมาก่อสร้าง <a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\">กำแพงกันดิน (Retaining Wall)</a> โดยเฉพาะในพื้นที่ริมน้ำหรือแนวเขื่อนเดิม สิ่งที่ทีมงานมักจะต้องเตรียมรับมือเสมอคือ \"อุปสรรคใต้ผิวดิน\" วันนี้ทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> ได้เริ่มนำเครื่องจักรหนักเข้าเคลียร์พื้นที่และเตรียมกดเสาเข็ม แต่ก็ต้องพบกับโจทย์ใหญ่ที่ซ่อนอยู่ใต้น้ำ มาดูกันครับว่าทีมงานของเรามีวิธีรับมือและบริหารจัดการเวลาอย่างไรให้งานยังคงเดินหน้าต่อไปได้ตามแผน!\n            </p>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. อุปสรรคหลัก: แนวหินทิ้งจากสันเขื่อนเดิมใต้น้ำ\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลังจากทีมงานเริ่มเดินเครื่องกดเสาเข็มด้วยรถแบคโฮ (แมคโคร) เราได้พบกับปัญหาหลักคือ <strong>\"แนวหินก้อนใหญ่ที่จมอยู่ใต้น้ำ\"</strong> ซึ่งเป็นหินที่ถูกทิ้งไว้จากโครงสร้างสันเขื่อนเดิมในอดีต ในทางวิศวกรรม หากเราฝืนกดเสาเข็มลงไปปะทะกับแนวหินเหล่านี้โดยตรง อาจส่งผลเสียร้ายแรงได้ เช่น เสาเข็มหนีศูนย์ (เยื้องศูนย์) เสาเข็มหัก หรือกดไม่ลงถึงระดับความลึกที่กำหนด\n            </p>\n\n            <div class=\"alert alert-info\" style=\"margin-top: 20px; border-left: 5px solid #31708f;\">\n                <h4 style=\"color: #31708f; margin-top: 0;\"><i class=\"fa fa-cogs\"></i> วิธีการแก้ปัญหาของทีมงาน</h4>\n                <p style=\"margin-bottom: 0; line-height: 1.6;\">\n                    เราสั่งหยุดการกดเข็มชั่วคราว และปรับแผนโดยนำรถแบคโฮ (แมคโคร) ติดตั้งหัวขุด ลงไปทำการ <strong>\"ตักและเกลี่ยแนวหินที่อยู่ใต้น้ำ\"</strong> ออกให้พ้นจากแนวแกนเสาเข็ม (Pile Line) ก่อน เพื่อเปิดทางให้ชั้นดินโล่งที่สุด แม้ขั้นตอนนี้จะทำให้เสียเวลาเพิ่มขึ้นเล็กน้อย แต่เพื่อความสมบูรณ์ร้อยเปอร์เซ็นต์ของฐานราก ถือเป็นสิ่งที่ข้ามไม่ได้เด็ดขาดครับ\n                </p>\n            </div>\n\n            <div class=\"row\" style=\"margin: 30px 0;\">\n                <div class=\"col-md-6 text-center\" style=\"margin-bottom: 20px;\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/saima-19-15092021-7.webp\" alt=\"แนวหินทิ้งจากเขื่อนเดิมที่จมอยู่ใต้น้ำ อุปสรรคงานกดเสาเข็ม\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>ภาพแนวหินใต้น้ำที่เป็นอุปสรรคต่อการกดเสาเข็ม</em></p>\n                </div>\n                <div class=\"col-md-6\">\n                    <div class=\"embed-responsive embed-responsive-16by9\" style=\"border-radius: 8px; overflow: hidden; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                        <iframe class=\"embed-responsive-item\" src=\"https://www.youtube.com/embed/wSa5U9nbfDI\" allowfullscreen title=\"วิดีโอแมคโครขุดหินที่อยู่ใต้น้ำ งานกำแพงกันดิน\"></iframe>\n                    </div>\n                    <p class=\"text-muted text-center\" style=\"margin-top: 10px; font-size: 14px;\"><em>วิดีโอ: ปฏิบัติการใช้รถแมคโครเคลียร์แนวหินใต้น้ำ</em></p>\n                </div>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. เดินหน้าต่อ: ลุยกดเสาเข็ม Micropile ด้วยรถแบคโฮ Kobelco 135\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลังจากเคลียร์สิ่งกีดขวางใต้น้ำเสร็จสิ้น ทีมงานที่มีความเชี่ยวชาญเฉพาะด้านของเราก็เดินหน้าเข้าสู่กระบวนการ <a href=\"https://www.theeraphong.com/images/pile\" target=\"_blank\">กดเสาเข็มไมโครไพล์ (Micropile)</a> อย่างเต็มกำลัง โดยใช้กำลังอัดจากรถ <strong>Kobelco SK135</strong> ซึ่งมีน้ำหนักกดที่เหมาะสม ทำให้การทำงานรวดเร็วและแม่นยำ \n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ถึงแม้อุปสรรคในช่วงเช้าจะทำให้เวลาล่าช้าไปบ้าง แต่ด้วยประสบการณ์หน้างานและการวางแผนรับความเสี่ยง (Risk Management) ที่เผื่อเวลาไว้แล้ว ทำให้ภาพรวมของงานฐานรากยังคงเป็นไปตามเป้าหมายที่คาดคิดไว้ครับ\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/180921-3.jpg\" alt=\"รถแบคโฮ Kobelco 135 กำลังกดเสาเข็มไมโครไพล์ (Micropile)\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>ภาพการกดเสาเข็ม Micropile อย่างต่อเนื่องและแม่นยำด้วยแบคโฮ Kobelco 135</em></p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. บริหารเวลาอย่างชาญฉลาด: งานหล่อแผ่นเสียบกำแพงกันดิน\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                จุดเด่นของการทำงานแบบมืออาชีพ คือการไม่ปล่อยให้เวลาสูญเปล่า ในขณะที่ทีมเครื่องจักรกำลังลุยกดเสาเข็มอยู่นั้น อีกฝั่งหนึ่งของหน้างาน <strong>\"ทีมช่างโครงสร้าง\"</strong> ก็ได้ดำเนินการเทปูนหล่อ <strong>แผ่นเสียบกำแพงกันดินคอนกรีตเสริมเหล็ก</strong> ควบคู่กันไปเป็นที่เรียบร้อยแล้วครับ\n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                การวางแผนงานคู่ขนานแบบนี้ (Parallel Workflow) ทำให้ <strong>ระยะเวลาที่ใช้ในการกดเสาเข็ม สอดคล้องพอดีกับระยะเวลาที่แผ่นปูนเซ็ตตัว (Curing Time)</strong> จนได้ค่าความแข็งแรง (Compressive Strength) ตามมาตรฐานวิศวกรรม เมื่อกระบวนการกดเสาเข็มเสร็จสิ้น แผ่นเสียบทั้งหมดก็จะแข็งแกร่งพร้อมสำหรับการนำไปเสียบประกอบลงในร่องแนวเสาเข็มได้ทันที ไร้รอยต่อของตารางงานครับ!\n            </p>\n\n            <div class=\"row\" style=\"margin: 30px 0;\">\n                <div class=\"col-sm-6 text-center\" style=\"margin-bottom: 20px;\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/saima-19-15092021-6.webp\" alt=\"ช่างกำลังเทปูนหล่อแผ่นเสียบกำแพงกันดิน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-height: 500px; object-fit: cover; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>เตรียมพร้อมเทคอนกรีตลงบล็อกแผ่นเสียบ</em></p>\n                </div>\n                <div class=\"col-sm-6 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/saima-19-15092021-10.webp\" alt=\"งานหล่อแผ่นเสียบกำแพงกันดินคู่ขนานกับงานกดเข็ม\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-height: 500px; object-fit: cover; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>แผ่นเสียบที่เทเสร็จเรียบร้อย รอเวลาเซ็ตตัว</em></p>\n                </div>\n            </div>\n\n            <hr style=\"margin: 40px 0;\">\n\n            <div class=\"well text-center\" style=\"background-color: #f8f9fa; border-top: 4px solid #0056b3; padding: 30px 20px;\">\n                <h3 style=\"margin-top: 0; color: #333; margin-bottom: 15px;\">พบปัญหาหน้างานก่อสร้าง? ให้ทีมงานมืออาชีพดูแลคุณ</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    ไม่ว่าหน้างานจะยากแค่ไหน หรือมีอุปสรรคที่คาดไม่ถึง <strong>ธีรพงษ์เซอร์วิส</strong> มีทั้งเครื่องจักรหนักที่พร้อมลุย และทีมช่างประสบการณ์สูงที่พร้อมแก้ปัญหาหน้างานให้ลุล่วงตามแผนงาน \n                </p>\n                <div class=\"row\">\n                    <div class=\"col-sm-6\" style=\"margin-bottom: 15px;\">\n                        <a href=\"https://www.theeraphong.com/images/pile\" class=\"btn btn-primary btn-block btn-lg\" style=\"padding: 15px;\">\n                            <i class=\"fa fa-cogs\"></i> บริการกดเสาเข็มไมโครไพล์\n                        </a>\n                    </div>\n                    <div class=\"col-sm-6\">\n                        <a href=\"https://www.theeraphong.com/retaining-wall\" class=\"btn btn-success btn-block btn-lg\" style=\"padding: 15px;\">\n                            <i class=\"fa fa-shield\"></i> บริการรับทำกำแพงกันดิน\n                        </a>\n                    </div>\n                </div>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1710962864135948.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP3', '2021-09-15 10:22:19', '2021-09-15 10:30:48'),
(20, 'เขื่อนกันดินไทรม้า 19 EP.4', 'อัพเดทงานสร้างเขื่อนกันดิน ซอยไทรม้า 19', '<h1><strong>อัพเดทงาน กำแพงกันดิน ซอย ไทรม้า 19</strong></h1>\r\n\r\n<p>หน้างาน ทำกำแพงกันดิน ยังคงเนินการไปได้เรื่อย ๆ แต่ก็ประสบกับปัญหาหลัก ที่ทำให้ล่าช้า คือ หินที่อยู่ใต้น้ำที่มีค่อนข้างมาก รถแบคโฮ จึงต้องทำงานสองอย่าง คือ</p>\r\n\r\n<ol>\r\n	<li>เคลียหิน</li>\r\n	<li>กดเข็ม</li>\r\n</ol>\r\n\r\n<p>&nbsp;</p>\r\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/vmWXNdmQ6qM\" title=\"YouTube video player\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen></iframe>\r\n<p>&nbsp;</p>\r\n\r\n<p>ทั้งนี้ทางทีมงานก็เร่งดำเนินการให้งานจบออกมา แล้วสามารถเสร็จทันตามกำหนดเวลา โดยยังคงไว้ซึ่งมาตรฐานที่เคยทำมาเป็นที่ตั้งสูงสุด</p>\r\n\r\n<p>โดยความคืบหน้าสามารถดำเนินการไปได้ มากกว่า 30% ของงานทั้งหมด&nbsp;</p>\r\n\r\n<blockquote>\r\n<p><strong>&quot;งานยากไม่ว่า เสียหน้า ธีรพงษ์ ไม่ยอม&quot;</strong></p>\r\n</blockquote>\r\n\r\n<p>รวมถึงแผ่นเสียบที่ใช้หล่อสดหน้างาน ซึ่งจะใช้เสียบเข้าระหว่างเสาเข็มเมื่อการกดเข็ม ไอ 22 ด้วยแบคโฮ แล้วเสร็จ สามารถดำเนินการไปได้มากกว่า 25%&nbsp;</p>\r\n\r\n<p><img alt=\"\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/17092021/saima-19-rw-170921-1.webp\" style=\"height:500px; width:375px\" /></p>', 'images/blogs/1711139361714176.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP4', '2021-09-17 09:07:41', '2021-09-17 09:07:41'),
(21, 'กำแพง กัน ดิน ซอยบางกร่าง45/5 EP.1', 'เริ่มงานทำกำแพงกันดิน ซอยบางกร่าง 45/5', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h2 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    Case Study: แก้ปัญหากำแพงกันดินริมคลองพังทลาย ซอยบางกร่าง 45/5 (Day 1)\n                </h2>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-calendar\"></i> อัปเดตข้อมูลหน้างานวันแรก | <i class=\"fa fa-map-marker\"></i> พิกัด: ติดริมคลองบางนางเกริก และคลองอ้อมน้อย จ.นนทบุรี\n                </p>\n            </div>\n\n            <p class=\"lead\" style=\"line-height: 1.8;\">\n                การสร้างกำแพงกันดินริมคลอง ถือเป็นหนึ่งในงานโครงสร้างที่ปราบเซียนและต้องอาศัยการคำนวณที่แม่นยำที่สุด วันนี้ทีมงาน <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> จะพาทุกท่านลงพื้นที่หน้างานจริงในวันแรก (Day 1) กับโปรเจกต์งานแก้ไขและสร้าง <a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\">กำแพงกันดิน</a> ใหม่ทั้งหมด ณ ซอยบางกร่าง 45/5 ซึ่งพื้นที่แห่งนี้มีโจทย์ที่ท้าทายคือทำเลที่ตั้งติดกับ <strong>คลองบางนางเกริก และคลองอ้อมน้อย</strong> \n            </p>\n\n            <div class=\"text-center\" style=\"margin: 35px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/52523.jpg\" alt=\"สภาพแวดล้อมริมคลองบางนางเกริก คลองอ้อมน้อย ซอยบางกร่าง 45/5\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 1: บรรยากาศพื้นที่หน้างาน ติดริมคลองบางนางเกริกและคลองอ้อมน้อย ซึ่งมีระดับน้ำขึ้นลงและกระแสน้ำกัดเซาะตลอดเวลา</em></p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                ความไว้วางใจจากลูกค้า: จุดเริ่มต้นของการแก้ปัญหา\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ก่อนที่จะเริ่มเจาะลึกถึงเนื้องาน ทางทีมงานธีรพงษ์เซอร์วิส ต้องขอขอบพระคุณ <strong>คุณพี่มนัส</strong> เจ้าของพื้นที่เป็นอย่างสูง ที่ให้ความไว้วางใจและเลือกใช้บริการทีมช่างของเราให้เข้ามาดูแลโปรเจกต์นี้ เพื่อคืนความปลอดภัยและทัศนียภาพที่สวยงามให้กับพื้นที่ริมคลองแห่งนี้อีกครั้ง\n            </p>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                วิเคราะห์โครงสร้าง: ทำไมกำแพงกันดินเดิมถึงล้มพัง?\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เมื่อทีมวิศวกรและช่างของเราลงพื้นที่สำรวจ ได้พบกับโครงสร้างกำแพงกันดินเดิมที่อยู่ในสภาพ <strong>\"ชำรุดเสียหายหนักและเอนล้มลงไปทางฝั่งแม่น้ำ\"</strong> ซึ่งจากประสบการณ์งานช่างของเรา สามารถวิเคราะห์สาเหตุหลักของการพังทลายในครั้งนี้ได้ชัดเจนครับ:\n            </p>\n            \n            <div class=\"alert alert-warning\" style=\"margin-top: 20px; border-left: 5px solid #d9534f;\">\n                <h4 style=\"color: #d9534f; margin-top: 0;\"><i class=\"fa fa-exclamation-triangle\"></i> สาเหตุหลักที่ทำให้กำแพงกันดินริมคลองพัง</h4>\n                <p style=\"margin-bottom: 0; line-height: 1.6;\">\n                    ปัญหาไม่ได้อยู่ที่ตัวกำแพงด้านหน้า แต่อยู่ที่ <strong>\"ระบบสเตย์ (Stay) หรือคานดึงรั้งด้านหลัง\"</strong> ของกำแพงเดิม มีการออกแบบขนาดที่ <strong>\"เล็กและตื้นเกินไป\"</strong> เมื่อต้องเผชิญกับแรงดันมหาศาลจากมวลดินด้านใน ประกอบกับการถูกกระแสน้ำในคลองกัดเซาะผิวดินด้านนอก ทำให้ระบบสเตย์เดิมสูญเสียแรงเสียดทานและไม่มีความแข็งแรงเพียงพอที่จะดึงรั้งกำแพงเอาไว้ได้ กำแพงจึงแบะและล้มพังลงสู่คลองในที่สุด\n                </p>\n            </div>\n\n            <div class=\"text-center\" style=\"margin: 35px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/52520.jpg\" alt=\"สภาพกำแพงกันดินริมคลองที่ทรุดและพังทลาย เนื่องจากสเตย์ยึดกำแพงมีขนาดเล็กเกินไป\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 2: สภาพความเสียหายของกำแพงกันดินเดิม ที่ล้มเอนลงไปทางฝั่งแม่น้ำจากปัญหาโครงสร้างสเตย์ไม่ได้มาตรฐาน</em></p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                ภารกิจของเรา: การรื้อถอนและวางระบบกำแพงกันดินใหม่ (เต็มระบบ)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                โจทย์ของทีมงานธีรพงษ์เซอร์วิสในโปรเจกต์นี้ ไม่ใช่แค่การซ่อมแซม แต่คือการ <strong>\"รื้อและสร้างระบบกำแพงกันดินสเตย์ใหม่ทั้งหมด\"</strong> เพื่อให้มั่นใจว่าจะไม่เกิดเหตุการณ์ซ้ำรอยเดิมอีก โดยเราจะเน้นหนักไปที่การขยายขนาดของคานสเตย์ การลงเข็มสเตย์ให้ลึกทะลุชั้นดินอ่อน และผูกเหล็กโครงสร้างให้เป็นเนื้อเดียวกัน (Monolithic) ทนทานต่อแรงต้านของน้ำและดินริมคลองได้อย่างเด็ดขาด\n            </p>\n\n            <p style=\"line-height: 1.8; font-size: 16px; margin-bottom: 20px;\">\n                เชิญรับชมวิดีโอบรรยากาศการประเมินหน้างานในวันแรก และแผนการเตรียมพื้นที่ก่อนลงมือทำงานจริงของทีมงานเราได้ที่คลิปด้านล่างนี้ครับ:\n            </p>\n\n            <div class=\"embed-responsive embed-responsive-16by9\" style=\"margin: 30px 0; border-radius: 8px; overflow: hidden; box-shadow: 0 6px 15px rgba(0,0,0,0.15);\">\n                <iframe class=\"embed-responsive-item\" src=\"https://www.youtube.com/embed/bXvRyK0OZj4\" allowfullscreen title=\"วิดีโอสำรวจหน้างาน กำแพงกันดินพัง ซอยบางกร่าง 45/5\"></iframe>\n            </div>\n\n            <p style=\"line-height: 1.8; font-size: 16px; margin-top: 20px; font-weight: bold; text-align: center;\">\n                รอติดตามชมรายละเอียดขั้นตอนการดำเนินการใน EP. ถัดไป มาคอยดูกันครับว่าทางทีมงานเราจะมีเทคนิคและวิธีการจัดการกับหน้างานที่ท้าทายนี้อย่างไรบ้าง!\n            </p>\n\n            <hr style=\"margin: 40px 0;\">\n\n            <div class=\"well text-center\" style=\"background-color: #f8f9fa; border: none; padding: 30px 20px;\">\n                <h3 style=\"margin-top: 0; color: #333; margin-bottom: 20px;\">สนใจผลงาน หรือต้องการปรึกษาปัญหาเรื่องงานช่าง?</h3>\n                \n                <div class=\"row\">\n                    <div class=\"col-sm-6\" style=\"margin-bottom: 15px;\">\n                        <a href=\"https://www.theeraphong.com/images/retaining-wall\" class=\"btn btn-primary btn-block btn-lg\" style=\"white-space: normal; padding: 15px;\">\n                            <i class=\"fa fa-picture-o\"></i> ดูรวมรูปภาพผลงานกำแพงกันดินทั้งหมด\n                        </a>\n                    </div>\n                    <div class=\"col-sm-6\">\n                        <a href=\"https://www.theeraphong.com/blog\" class=\"btn btn-info btn-block btn-lg\" style=\"white-space: normal; padding: 15px; background-color: #17a2b8; border-color: #17a2b8;\">\n                            <i class=\"fa fa-book\"></i> อ่านบทความและข่าวสารล่าสุดของเรา\n                        </a>\n                    </div>\n                </div>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1711320597112563.webp', 10, 'กำแพงกันดิน-ซอยบางกร่าง45-5-EP1', '2021-09-19 08:43:10', '2021-09-20 00:35:42'),
(22, 'เขื่อนกันดินไทรม้า 19 EP.5', 'อัพเดทงานสร้างเขือนกันดิน ซอยไทรม้า 19 ณ 20 ก.ย. 2564', '<p><strong>อัพเดทงาน ณ วันที่ 20 กันยายน 2564</strong></p>\r\n\r\n<p>วันนี้ ทีมงาน <a href=\"https://www.theeraphong.com/\">ธีรพงษ์ เซอร์วิส</a>&nbsp;ได้ดำเนินการกดเสาเข็ม กำแพง กัน ดิน ทั้งในส่วนของกำแพง และสเตย์ เป็นอันเสร็จเรียบร้อย รวมเป็นจำนวนทั้งสิ้น 110 ต้น</p>\r\n\r\n<p><img alt=\"แม็คโคร กดเข็ม\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/180921/180921-4.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p>รูป แม็คโคร กดเข็ม</p>\r\n\r\n<p>ทั้งนี้ การดำเนินการอาจมีความล่าช้าไปบ้างเล็กน้อยจากการคาดการณ์ไว้ เนื่องจากประสบกับปัญหาเศษหินที่อยู่ใต้น้ำ และสภาพอากาศที่ไม่สามารถควบคุมได้</p>\r\n\r\n<p><img alt=\"เศษหินใต้ดิน\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/180921/180921-1.webp\" style=\"height:500px; width:375px\" /></p>\r\n\r\n<p>รูป หินที่เป็นอุปสรรคหลักสำหรับงานกำแพง กัน ดิน</p>\r\n\r\n<p>แต่ในภาพรวม ก็ยังสามารถดำเนินการไปได้ด้วยดี ทั้งนี้ต้องรอระยะเวลาอีกประมาณ 3 วันเพื่อให้เสาเข็มยึดกับดินได้ดียิ่งขึ้น และจะได้ทำการติดตั้งแผ่นกำแพงกันดินอีกครั้ง ทั้งนี้เสาเข็มไอ 22 ความยาว 10 เมตร ได้ถูกกดลงไปใต้พื้นดินมากกว่ากว่า 8 เมตร ซึ่งสามารถมั่นใจได้ว่า กำแพง กัน ดิน ที่ทางทีมงานเราสร้าง มีความคงทน และแข็งแรงอย่างแน่นอน</p>\r\n\r\n<p><img alt=\"แม็คโครขนย้ายเสาเข็มไอ 22\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/180921/180921-2.webp\" style=\"height:375px; width:500px\" /></p>\r\n\r\n<p>รูป แม็คโครกำลังดำเนินการย้ายเสาเข็มสู่ตำแหน่งที่กำหนด</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>ซึ่งหลังจากนี้ประมาณ 3 วัน ทีมงานจะทำการเสียบแผ่นกำแพงกันดิน แล้วทางทีมงานจะได้ทำการอัพเดทให้ได้ชมในเวลาต่อไป</p>\r\n\r\n<p>อัพเดทงาน ครั้งก่อนหน้า <a href=\"https://www.theeraphong.com/blog/20\">คลิ๊กที่นี่</a></p>\r\n\r\n<p>งานอื่น ๆ <a href=\"https://www.theeraphong.com/\">คลิ๊กที่นี่</a></p>\r\n\r\n<p>&nbsp;</p>', 'images/blogs/1711438109246937.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP5', '2021-09-20 16:12:41', '2021-09-20 16:16:08');
INSERT INTO `blogs` (`id`, `title`, `description`, `content`, `image`, `service_category_id`, `slug`, `created_at`, `updated_at`) VALUES
(23, 'สำรวจกำแพง กั้น ดิน พัง สุพรรณบุรี', 'ลงพื้นหน้าดูหน้างาน สำรวจกำแพง กั้น ดินพัง', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    Case Study: สำรวจวิกฤตหน้างาน กำแพงกั้นดินพังทลาย ริมแม่น้ำท่าจีน จ.สุพรรณบุรี พร้อมวิเคราะห์สาเหตุเชิงลึก\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-exclamation-triangle\"></i> อัปเดตการสำรวจหน้างานฉุกเฉิน | <i class=\"fa fa-map-marker\"></i> พิกัด: พื้นที่ติดริมแม่น้ำท่าจีน จังหวัดสุพรรณบุรี\n                </p>\n            </div>\n\n            <div class=\"lead\" style=\"line-height: 1.8; background-color: #fcf8e3; padding: 25px; border-left: 5px solid #f0ad4e; border-radius: 4px; margin-bottom: 30px;\">\n                <p style=\"margin-bottom: 0;\">\n                    ปัญหา <strong>\"ตลิ่งทรุด\"</strong> และ <strong>\"กำแพงกันดินพัง\"</strong> ถือเป็นฝันร้ายที่สุดสำหรับผู้ที่มีบ้านหรือที่ดินติดริมแม่น้ำ วันนี้ทีมงานวิศวกรและช่างผู้ชำนาญการจาก <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> ได้รับความไว้วางใจให้ลงพื้นที่ด่วน เพื่อประเมินความเสียหายและหาทางแก้ไขปัญหาหน้างานจริง ณ จังหวัดสุพรรณบุรี ซึ่งเหตุการณ์นี้ได้สร้างความเสียหายอย่างหนักให้กับโครงสร้างริมน้ำ บทความนี้เราจะพาไปวิเคราะห์เจาะลึกว่า <em>ทำไมกำแพงถึงพัง?</em> และ <em>เราจะมีวิธีแก้ปัญหาระยะยาวอย่างไรไม่ให้ซ้ำรอยเดิม?</em>\n                </p>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. สำรวจความเสียหาย: วิกฤตแนวกำแพงกั้นดินพังถล่มลงสู่แม่น้ำ\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เมื่อทีมงานของเราเดินทางไปถึงพื้นที่หน้างานที่ติดกับ <strong>แม่น้ำท่าจีน</strong> ภาพที่ปรากฏคือแนวกำแพงกันดินคอนกรีตเดิม ได้เกิดการทรุดตัวและพังทลายลงไปทางฝั่งแม่น้ำเป็นแนวยาวตลอดขอบแนวเขตที่ดิน แรงดึงจากการถล่มของกำแพงได้กระชากเอาพื้นดินด้านบนและสิ่งปลูกสร้างรอบข้างให้สไลด์ตามลงไปด้วย\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/220921/suphan-220921-1.webp\" alt=\"สภาพกำแพงกั้นดินพังทลาย ริมแม่น้ำท่าจีน จ.สุพรรณบุรี\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 1: สภาพแนวกำแพงกั้นดินเดิมที่สูญเสียความสามารถในการรับน้ำหนัก และพังทลายลงสู่แม่น้ำท่าจีน</em></p>\n            </div>\n\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                สิ่งที่น่าเสียดายที่สุดในเหตุการณ์นี้ คือบริเวณจุดที่เกิดการพังทลายอย่างหนัก เป็นที่ตั้งของ <strong>\"บ้านต้นไม้ (Treehouse)\"</strong> ซึ่งเป็นมุมพักผ่อนที่สวยงามของลูกค้า โครงสร้างบ้านต้นไม้ได้รับผลกระทบโดยตรงจากการที่รากฐานดินถูกกัดเซาะจนล้มพังลงมา สร้างความเสียหายทั้งในด้านทรัพย์สินและคุณค่าทางจิตใจต่อเจ้าของพื้นที่เป็นอย่างมาก\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/220921/suphan-220921-3.webp\" alt=\"บ้านต้นไม้พังเสียหายจากเหตุกำแพงกันดินทรุดตัว\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 2: ความเสียหายที่เกิดขึ้นกับบ้านต้นไม้ ซึ่งตั้งอยู่ใกล้แนวตลิ่งที่เกิดการสไลด์ตัว</em></p>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. เจาะลึกทางวิศวกรรม: ทำไมกำแพงกั้นดินริมแม่น้ำถึงล้มพัง?\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                การสร้าง <a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\" style=\"color: #0056b3; font-weight: bold;\">กำแพงกันดิน (Retaining Wall)</a> ริมแม่น้ำใหญ่ ถือเป็นงานที่ปราบเซียนที่สุดในบรรดางานโครงสร้างทั้งหมด เพราะต้องต่อสู้กับแรงดันมหาศาลจากทั้ง 2 ฝั่ง (ฝั่งดินและฝั่งน้ำ) จากการลงพื้นที่ประเมินเบื้องต้น ทีมงานวิเคราะห์สาเหตุหลักของการพังทลายไว้ 3 ประเด็นหลัก ดังนี้ครับ:\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-4\">\n                    <div class=\"panel panel-danger text-center\">\n                        <div class=\"panel-heading\"><h4 style=\"margin: 0; font-weight: bold;\"><i class=\"fa fa-tint\"></i> แรงกัดเซาะของกระแสน้ำ</h4></div>\n                        <div class=\"panel-body\" style=\"font-size: 15px; text-align: left; line-height: 1.6;\">\n                            แม่น้ำท่าจีนมีระดับน้ำขึ้น-ลง และกระแสน้ำไหลเชี่ยวในช่วงฤดูน้ำหลาก หากปลายเสาเข็มกำแพงเดิมไม่ได้หยั่งลึกลงไปเกินกว่า <strong>\"ระดับท้องน้ำที่ถูกกัดเซาะลึกสุด (Scour Depth)\"</strong> กระแสน้ำจะพัดพาดินใต้ท้องกำแพงออกไป ทำให้กำแพงลอยและล้มลง\n                        </div>\n                    </div>\n                </div>\n                <div class=\"col-md-4\">\n                    <div class=\"panel panel-danger text-center\">\n                        <div class=\"panel-heading\"><h4 style=\"margin: 0; font-weight: bold;\"><i class=\"fa fa-anchor\"></i> ขาดระบบสเตย์ (Stay Beam)</h4></div>\n                        <div class=\"panel-body\" style=\"font-size: 15px; text-align: left; line-height: 1.6;\">\n                            กำแพงกั้นดินริมน้ำที่มีความสูงเกิน 1.5 เมตร <strong>จำเป็นต้องมีคานและเสาเข็มสเตย์ด้านหลัง</strong> เพื่อทำหน้าที่ดึงรั้งกำแพงหน้าเอาไว้ หากโครงสร้างเดิมเป็นเพียงกำแพงเสียบแผ่นปูนเปล่าๆ จะไม่สามารถต้านทานแรงดันดินด้านข้าง (Lateral Earth Pressure) ได้เลย\n                        </div>\n                    </div>\n                </div>\n                <div class=\"col-md-4\">\n                    <div class=\"panel panel-danger text-center\">\n                        <div class=\"panel-heading\"><h4 style=\"margin: 0; font-weight: bold;\"><i class=\"fa fa-sort-amount-desc\"></i> แรงดันน้ำสะสมหลังกำแพง</h4></div>\n                        <div class=\"panel-body\" style=\"font-size: 15px; text-align: left; line-height: 1.6;\">\n                            ในช่วงที่ฝนตกหนัก น้ำที่ซึมลงดินจะพยายามหาทางออกสู่แม่น้ำ หากกำแพงกันดินไม่มีระบบรูระบายน้ำ (Weep Holes) ที่มีประสิทธิภาพ น้ำจะขังอยู่หลังกำแพง ก่อให้เกิด <strong>แรงดันอุทกสถิต (Hydrostatic Pressure)</strong> ซึ่งมีพลังมหาศาลพอที่จะผลักให้กำแพงคอนกรีตฉีกขาดได้\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. ก้าวต่อไป: แผนการกู้คืนและแนวทางแก้ไขปัญหาระยะยาว (Long-term Solution)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลังจากสำรวจมิติของความเสียหาย ถ่ายภาพ และเก็บข้อมูลระดับความสูงของชั้นดินอย่างละเอียดเสร็จสิ้น ภารกิจต่อไปของทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> คือการกลับไปออกแบบโครงสร้างใหม่ร่วมกับทีมวิศวกร เพื่อนำเสนอโซลูชันที่ดีที่สุดให้กับคุณลูกค้า โดยมีแนวทางการแก้ไขปัญหาเบื้องต้นดังนี้:\n            </p>\n\n            <ul class=\"list-group\" style=\"font-size: 16px; margin-top: 20px;\">\n                <li class=\"list-group-item\" style=\"padding: 15px;\">\n                    <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\">1. การเคลียร์พื้นที่และรื้อถอน (Clearing & Demolition)</h4>\n                    <p style=\"margin-bottom: 0;\">ต้องนำเครื่องจักรเข้ามารื้อถอนเศษซากกำแพงเดิมและซากบ้านต้นไม้ที่จมอยู่ริมน้ำออกให้หมดก่อน เพื่อลดน้ำหนักกดทับบริเวณตลิ่ง และเปิดทางให้สามารถตอกเสาเข็มใหม่ได้</p>\n                </li>\n                <li class=\"list-group-item\" style=\"padding: 15px;\">\n                    <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\">2. การวางระบบรากฐานใหม่ \"แบบเต็มระบบ\" (Full Retaining System)</h4>\n                    <p style=\"margin-bottom: 0;\">เราจะนำเสนอการใช้ <strong>เสาเข็มไมโครไพล์ (Micropile) ชนิด I-Shape</strong> ที่มีความยาวเพียงพอที่จะทะลุผ่านชั้นดินเลนริมแม่น้ำ ลงไปยึดเกาะกับชั้นดินเหนียวแข็งด้านล่าง พร้อมเสริมความมั่นคงด้วย <strong>\"ระบบเสาเข็มและคานสเตย์ดึงรั้ง\"</strong> เพื่อป้องกันการล้มแบะ 100%</p>\n                </li>\n                <li class=\"list-group-item\" style=\"padding: 15px;\">\n                    <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\">3. งานป้องกันการกัดเซาะ (Erosion Control)</h4>\n                    <p style=\"margin-bottom: 0;\">ออกแบบระบบร่องระบายน้ำและ Weep Holes ให้เหมาะสม เพื่อลดแรงดันน้ำจากฝั่งตัวบ้าน พร้อมแนะนำการเรียงหินป้องกันการกัดเซาะที่บริเวณตีนกำแพงฝั่งแม่น้ำ</p>\n                </li>\n            </ul>\n\n            <p style=\"line-height: 1.8; font-size: 16px; margin-top: 25px; font-weight: bold; color: #333; text-align: center;\">\n                รอติดตามชมความคืบหน้าและการพลิกโฉมแก้ไขปัญหากำแพงกั้นดินริมแม่น้ำท่าจีนโปรเจกต์นี้ ได้ในบทความอัปเดตตอนต่อไปครับ!\n            </p>\n\n            <div style=\"background-color: #f9f9f9; padding: 30px; border-radius: 8px; margin-top: 50px; border: 1px solid #eaeaea;\">\n                <h3 style=\"color: #333; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> ถาม-ตอบ (FAQ) เมื่อพบปัญหากำแพงริมน้ำพังทลาย</h3>\n                <hr style=\"border-color: #ddd;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: เมื่อเห็นกำแพงเริ่มเอียง หรือมีรอยแตกร้าวริมแม่น้ำ ควรทำอย่างไรเป็นอันดับแรก?</h4>\n                <p style=\"margin-bottom: 20px;\">A: สิ่งแรกคือ <strong>\"ความปลอดภัย\"</strong> ครับ ห้ามให้คนหรือสัตว์เลี้ยงเข้าใกล้บริเวณนั้นเด็ดขาด เพราะดินอาจสไลด์ตามลงไปได้ทุกเมื่อ จากนั้นควรรีบติดต่อวิศวกรหรือผู้รับเหมาที่มีประสบการณ์ด้านกำแพงกันดินโดยตรง ให้เข้ามาประเมินความเสี่ยงและหาทางค้ำยันชั่วคราวครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: กำแพงเดิมพัง สามารถเทปูนซ่อมแซมรอยแตกได้หรือไม่?</h4>\n                <p style=\"margin-bottom: 20px;\">A: <strong>ไม่แนะนำครับ</strong> การที่กำแพงเอียงหรือพังทลาย เป็นสัญญาณว่า \"ฐานราก (เสาเข็ม) ด้านล่างได้สูญเสียกำลังรับน้ำหนักไปแล้ว\" การเทปูนฉาบหรือต่อเติมด้านบน จะยิ่งเป็นการเพิ่มน้ำหนักให้ตลิ่งทรุดเร็วขึ้น การแก้ปัญหาที่ถูกต้องคือต้องรื้อและวางระบบเสาเข็มใหม่เท่านั้นครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: สร้างกำแพงกันดินริมแม่น้ำ ต้องขออนุญาตกรมเจ้าท่าหรือไม่?</h4>\n                <p>A: หากแนวกำแพงของคุณมีการล่วงล้ำลงไปในแนวน่านน้ำ หรืออยู่ติดชิดขอบเขตแหล่งน้ำสาธารณะ จำเป็นต้องมีการตรวจสอบโฉนดและยื่นขออนุญาตจากกรมเจ้าท่าและเทศบาลในพื้นที่ให้ถูกต้องตามกฎหมายก่อนเริ่มดำเนินการก่อสร้างครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-top: 5px solid #d9534f; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #2c3e50; font-weight: bold;\">ปัญหาตลิ่งพัง กำแพงทรุด ปรึกษาเราก่อนสายเกินแก้</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    อย่าปล่อยให้ปัญหาโครงสร้างริมน้ำลุกลามจนสร้างความเสียหายแก่บ้านและทรัพย์สินของคุณ <br>\n                    <strong>ธีรพงษ์เซอร์วิส</strong> มีทีมวิศวกรและช่างผู้ชำนาญการ พร้อมลงพื้นที่ประเมินหน้างานจริงเพื่อหาทางออกที่ยั่งยืน\n                </p>\n                \n                <div class=\"row\">\n                    <div class=\"col-sm-6 text-right\">\n                        <a href=\"https://www.theeraphong.com/retaining-wall\" class=\"btn btn-danger btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px; width: 100%; max-width: 350px;\">\n                            <i class=\"fa fa-shield\"></i> บริการรับทำกำแพงกันดิน-เขื่อน\n                        </a>\n                    </div>\n                    <div class=\"col-sm-6 text-left\">\n                        <a href=\"https://www.theeraphong.com/blog\" class=\"btn btn-info btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px; width: 100%; max-width: 350px; background-color: #17a2b8; border-color: #17a2b8;\">\n                            <i class=\"fa fa-book\"></i> รวมข่าวสารและบทความงานช่าง\n                        </a>\n                    </div>\n                </div>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1711592918414737.webp', 10, 'สำรวจกำแพงกั้นดินพัง-สุพรรณบุรี', '2021-09-22 09:15:43', '2021-09-22 09:16:46'),
(24, 'เขื่อนกันดินไทรม้า 19 EP.6', 'ความคืบหน้างานเขือนกันดิน ซอยไทรม้า 19', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h2 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    เจาะลึกงานโครงสร้าง: อัปเดตความคืบหน้า งานติดตั้งแผ่นเสียบ กำแพงกันดิน ลึก 1.50 เมตร โครงการซอยบางกร่าง 45/5\n                </h2>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-calendar\"></i> อัปเดตข้อมูลหน้างาน ณ วันที่ 27 กันยายน 2564 | <i class=\"fa fa-folder-open\"></i> หมวดหมู่: อัปเดตผลงานหน้างาน, ความรู้งานก่อสร้าง\n                </p>\n            </div>\n\n            <p class=\"lead\" style=\"line-height: 1.8;\">\n                การปกป้องหน้าดินจากการพังทลายและการทรุดตัว ถือเป็นหัวใจสำคัญของการปลูกสร้างบ้านและอาคาร โดยเฉพาะในพื้นที่ที่มีสภาพดินอ่อน ทีมงาน <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> ขอพาทุกท่านมาติดตามความคืบหน้าอย่างใกล้ชิด กับโครงการก่อสร้าง <strong>กำแพงกันดิน</strong> ณ พื้นที่ซอยบางกร่าง 45/5 จังหวัดนนทบุรี ซึ่งล่าสุดทางทีมวิศวกรและช่างผู้ชำนาญการของเราได้ดำเนินการ <strong>\"กดแผ่นเสียบคอนกรีตเสริมเหล็ก\"</strong> เสร็จสิ้นเรียบร้อยแล้วตามแผนงานที่วางไว้ บทความนี้เราจะพาไปเจาะลึกถึงเหตุผลทางวิศวกรรมว่าทำไมเราถึงต้องให้ความสำคัญกับขั้นตอนนี้นัก\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 35px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/52540.jpg\" alt=\"การติดตั้งแผ่นเสียบกำแพงกันดิน ลึก 1.5 เมตร ซอยบางกร่าง นนทบุรี\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 900px; box-shadow: 0 6px 15px rgba(0,0,0,0.15);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 1: ทีมช่างธีรพงษ์เซอร์วิส ควบคุมการกดแผ่นเสียบกำแพงกันดินด้วยเครื่องจักรมาตรฐาน ลึกลงไป 1.50 เมตร</em></p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. วิเคราะห์สภาพดินและโจทย์ของโครงการ ซอยบางกร่าง 45/5\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                พื้นที่ในเขตจังหวัดนนทบุรีและปริมณฑลส่วนใหญ่ มีลักษณะทางธรณีวิทยาเป็น <strong>\"ชั้นดินเหนียวอ่อน (Soft Clay)\"</strong> ซึ่งมีความเสี่ยงสูงต่อการสไลด์ตัวของดินเมื่อมีความชื้นสูง หรือเมื่อมีการถมดินใหม่เพื่อปรับระดับพื้นที่ โครงการนี้เจ้าของบ้านมีความต้องการที่จะปรับระดับผิวดินให้สูงขึ้นเพื่อป้องกันปัญหาน้ำท่วมขังและเพิ่มพื้นที่ใช้สอย \n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ดังนั้น การสร้างเพียงรั้วบ้านธรรมดาจึงไม่สามารถตอบโจทย์แรงดันที่มหาศาลจากดินถมใหม่ได้ หากฝืนทำไป รั้วอาจเกิดการแตกร้าว เอนเอียง หรือพังทลายในเวลาเพียงไม่กี่ปี ทางทีมงานจึงได้ออกแบบโครงสร้างเป็นระบบ <strong>กำแพงกันดิน (Retaining Wall)</strong> แบบเต็มระบบ เพื่อรับมือกับปัญหานี้อย่างเด็ดขาด\n            </p>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. ทำไมต้องกดแผ่นเสียบลึกลงไปถึง 1.50 เมตร?\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ในงานวิศวกรรมโยธา ความลึกของการฝังรากฐานเปรียบเสมือนการหยั่งรากแก้วของต้นไม้ใหญ่ ทีมงานของเราได้ลงพื้นที่สำรวจ คำนวณ และตัดสินใจกดแผ่นเสียบคอนกรีตอัดแรงฝังลึกลงไปใต้ระดับผิวดินเดิมถึง <strong>1.50 เมตร</strong> ด้วยเหตุผลทางเทคนิคดังต่อไปนี้:\n            </p>\n            \n            <div class=\"row\" style=\"margin-top: 20px;\">\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-default\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title text-primary\"><i class=\"fa fa-shield\"></i> การต้านทานแรงดันดินด้านข้าง</h4></div>\n                        <div class=\"panel-body\">\n                            <p>แรงดันดินด้านข้าง (Lateral Earth Pressure) คือศัตรูตัวฉกาจของกำแพง การฝังแผ่นเสียบลึก 1.5 เมตร จะช่วยเพิ่มพื้นที่สัมผัสใต้ดิน สร้างมวลต้านทาน (Passive Pressure) ที่แข็งแกร่งพอที่จะยันแผ่นดินถมใหม่ไม่ให้ผลักกำแพงล้ม</p>\n                        </div>\n                    </div>\n                </div>\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-default\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title text-primary\"><i class=\"fa fa-tint\"></i> การป้องกันการกัดเซาะจากน้ำ</h4></div>\n                        <div class=\"panel-body\">\n                            <p>ในช่วงฤดูฝน น้ำที่ซึมลงดินจะทำให้ดินสูญเสียแรงเสียดทาน (Friction) การฝังโครงสร้างลึกผ่านชั้นดินร่วนซุยลงไปถึงชั้นดินที่แน่นกว่า จะช่วยป้องกันปัญหาดินสไลด์ลอดใต้ท้องกำแพง (Piping Effect) ได้อย่างมีประสิทธิภาพ</p>\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. ความชัดเจนในเอกสาร: จากแบบแปลนสู่หน้างานจริง\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ที่ <strong>ธีรพงษ์เซอร์วิส</strong> เราเชื่อว่างานรับเหมาก่อสร้างที่มีคุณภาพ ต้องมาพร้อมกับความโปร่งใสที่ตรวจสอบได้ การทำงานของเราเริ่มต้นตั้งแต่การจัดทำเอกสารข้อเสนอโครงการ (Proposal) ที่ระบุขอบเขตงานอย่างละเอียด สัญญาว่าจ้างที่รัดกุม และเอกสารการเบิกจ่าย (Payment Documents) ที่แบ่งงวดงานอย่างเป็นธรรม \n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ตัวเลขความลึก 1.50 เมตร หรือสเปกของคอนกรีตและเหล็กเส้น ไม่ได้เป็นเพียงการกะเกณฑ์หน้างาน แต่ถูกระบุไว้อย่างชัดเจนในเอกสารประเมินราคา (BOQ) ลูกค้าจึงสามารถตรวจสอบและมั่นใจได้ว่า ทุกงวดงานที่ชำระเงิน จะได้รับผลงานที่ตรงปก ได้มาตรฐานทางวิศวกรรม วัสดุไม่ขาด ไม่มีการลดสเปก เพื่อโครงสร้างที่อยู่คู่บ้านไปอีกนับสิบปี\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 35px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/110516.jpg\" alt=\"การเตรียมงานผูกเหล็กคานทับหลังและคานสเตย์\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 900px; box-shadow: 0 6px 15px rgba(0,0,0,0.15);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 2: แผนการดำเนินงานขั้นต่อไป คือการเตรียมพื้นที่สำหรับผูกเหล็กคานทับหลังและคานสเตย์</em></p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                4. ก้าวต่อไป: โครงสร้างคานรัดหัวและระบบคานสเตย์ (Stay Beam)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลังจากแผ่นเสียบและเสาเข็มถูกติดตั้งและยึดลงดินอย่างมั่นคงแล้ว ขั้นตอนต่อไปที่ทีมงานช่างของเราจะเร่งดำเนินการ คือการ <strong>ผูกเหล็กและเทคอนกรีตคาน</strong> ซึ่งเป็นองค์ประกอบที่ขาดไม่ได้เลยในระบบกำแพงกันดินที่สมบูรณ์แบบ โดยจะแบ่งออกเป็น 2 ส่วนหลักๆ ได้แก่:\n            </p>\n            \n            <ul class=\"list-group\" style=\"margin-top: 25px; font-size: 16px;\">\n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 class=\"list-group-item-heading text-primary\" style=\"font-weight: bold;\"><i class=\"fa fa-cubes\"></i> คานทับหลัง (Top Beam) หรือคานรัดหัวเสา</h4>\n                    <p class=\"list-group-item-text\" style=\"line-height: 1.6; margin-top: 10px;\">ทำหน้าที่เป็นตัวประสาน เสาเข็มและแผ่นเสียบทุกชิ้นให้เชื่อมต่อเป็นโครงสร้างเดียวกัน (Monolithic Structure) ช่วยกระจายน้ำหนักและแรงสั่นสะเทือนไปตลอดแนวระนาบของกำแพง ป้องกันไม่ให้แผ่นเสียบแผ่นใดแผ่นหนึ่งรับภาระหนักเกินไปจนเกิดการปริแตก</p>\n                </li>\n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 class=\"list-group-item-heading text-primary\" style=\"font-weight: bold;\"><i class=\"fa fa-anchor\"></i> คานสเตย์ (Stay Beam) และเสาสเตย์</h4>\n                    <p class=\"list-group-item-text\" style=\"line-height: 1.6; margin-top: 10px;\">นี่คือเคล็ดลับความแข็งแกร่ง! คานสเตย์คือระบบคานดึงรั้งที่ซ่อนอยู่ใต้ดิน ทำหน้าที่เหมือน \"รากแก้ว\" หรือ \"สมอเรือ\" ที่ช่วยดึงรั้งตัวกำแพงแนวหน้าเอาไว้กับผืนดินด้านใน ป้องกันปัญหาพบบ่อยอย่าง \'กำแพงล้มหรือแบะออกด้านนอก\' เมื่อมีแรงดันมหาศาลจากดินและน้ำฝนสะสม</p>\n                </li>\n            </ul>\n\n            <div style=\"background-color: #f9f9f9; padding: 30px; border-radius: 8px; margin-top: 40px; border: 1px solid #eaeaea;\">\n                <h3 style=\"color: #333; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> คำถามที่พบบ่อย (FAQ) เกี่ยวกับการทำกำแพงกันดิน</h3>\n                <hr style=\"border-color: #ddd;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: การทำกำแพงกันดิน ใช้ระยะเวลาดำเนินการนานหรือไม่?</h4>\n                <p style=\"margin-bottom: 20px;\">A: ระยะเวลาขึ้นอยู่กับความยาวและสภาพหน้างานครับ สำหรับหน้างานทั่วไปความยาว 20-30 เมตร อาจใช้เวลาประมาณ 15-20 วันทำการ รวมระยะเวลาการรอให้คอนกรีตเซ็ตตัว (Curing Time) เพื่อให้ได้ความแข็งแรงตามมาตรฐาน</p>\n\n                <h4 style=\"font-weight: bold;\">Q: หน้างานเป็นซอยแคบ เครื่องจักรใหญ่เข้าไม่ได้ สามารถทำได้หรือไม่?</h4>\n                <p style=\"margin-bottom: 20px;\">A: สามารถทำได้ครับ ทางธีรพงษ์เซอร์วิสมีทีมงานประเมินหน้างาน หากเป็นซอยแคบอย่างในบางพื้นที่ของนนทบุรี เรามีเครื่องจักรขนาดเล็ก (Mini Excavator) และเทคนิคการกดเข็มแบบไฮดรอลิกที่ออกแบบมาเพื่อพื้นที่จำกัดโดยเฉพาะ ลดผลกระทบต่อเพื่อนบ้านครับ</p>\n                \n                <h4 style=\"font-weight: bold;\">Q: ค่าใช้จ่ายในการทำกำแพงกันดิน ประเมินจากอะไร?</h4>\n                <p>A: ประเมินจากความยาว (เมตร) ความสูงของดินที่ต้องการถม และสภาพดินเดิมครับ เรายินดีเข้าไปสำรวจหน้างานจริง วัดพื้นที่ และออกใบเสนอราคาให้พิจารณาก่อนตัดสินใจ โดยไม่มีค่าใช้จ่ายแอบแฝงครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-left: 6px solid #0056b3; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #0056b3;\">ปกป้องพื้นที่ของคุณด้วยโครงสร้างที่ได้มาตรฐาน</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    โครงสร้างที่ผสานกันอย่างลงตัว ทั้งการเลือกใช้เสาเข็มที่เหมาะสม แผ่นเสียบที่ฝังลึก 1.5 เมตร คานรัดหัว และระบบคานสเตย์ จะทำให้กำแพงกันดินของท่านมีความมั่นคง พร้อมรับมือกับทุกสภาพอากาศและแรงดันหน้าดินในระยะยาว<br><br>\n                    หากท่านกำลังมองหาผู้รับเหมาที่มีประสบการณ์ ตรงไปตรงมา และมีเอกสารสัญญารัดกุม <strong>ธีรพงษ์เซอร์วิส</strong> พร้อมให้บริการท่านครับ\n                </p>\n                <a href=\"/retaining-wall\" class=\"btn btn-primary btn-lg\" style=\"padding: 15px 30px; font-size: 18px; border-radius: 30px; text-transform: uppercase; font-weight: bold; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                    <i class=\"fa fa-hand-o-right\"></i> ดูบริการรับทำกำแพงกันดิน และขอประเมินราคาฟรี!\n                </a>\n            </div>\n\n        </div>\n    </div>\n</div>\n<img alt=\"\" src=\"https://www.theeraphong.com/image/blogs/blogscontent/270921/saima-1.webp\" style=\"height:500px; width:375px\" />\n\n<p>งานก่อนหน้า <a href=\"https://www.theeraphong.com/blog/22\">คลิ๊กที่นี่</a></p>\n\n<p>รายละเอียดงานกำแพงกันดิน <a href=\"https://www.theeraphong.com/retaining-wall\">คลิ๊กที่นี่&nbsp;</a></p>', 'images/blogs/1712044835626349.webp', 10, 'เขื่อนกันดิน-ไทรม้า19-EP6', '2021-09-27 08:59:48', '2021-09-27 08:59:48'),
(25, 'กำแพง กัน ดิน ซอยบางกร่าง45/5 EP.2', 'อัพเดทงาน กำแพง กัน ดิน ในซอยบางกร่าง 45', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    อัปเดตงานฐานรากเขื่อนกันดิน: ลำเลียงเสาเข็มไอ (I-Shape) 10 เมตร 110 ต้น และเตรียมงานหล่อแผ่นเสียบ\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-calendar\"></i> อัปเดตข้อมูลหน้างาน ณ วันที่ 14 กันยายน 2561 | <i class=\"fa fa-folder-open\"></i> หมวดหมู่: ความรู้งานฐานราก, เขื่อนกันดินริมน้ำ\n                </p>\n            </div>\n\n            <p class=\"lead\" style=\"line-height: 1.8;\">\n                ก้าวเข้าสู่ช่วงสำคัญของงานโครงสร้าง! วันนี้ทีมงาน <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> ขอพาทุกท่านมาเจาะลึกเบื้องหลังการทำงานในเฟสของ <strong>\"งานฐานราก (Foundation Phase)\"</strong> สำหรับโปรเจกต์สร้างเขื่อนและ <a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\">กำแพงกันดิน</a> ซึ่งถือเป็นหัวใจหลักที่จะกำหนดความแข็งแรงของโครงสร้างทั้งหมด บทความนี้เราจะพาไปดูการบริหารจัดการวัสดุชิ้นใหญ่ อย่างเสาเข็มไอความยาว 10 เมตร จำนวนกว่า 110 ต้น พร้อมวิธีรับมือกับอุปสรรคใต้ผิวน้ำที่หลีกเลี่ยงไม่ได้\n            </p>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. การบริหารจัดการหน้างาน: ลำเลียงเสาเข็มไอ (Micropile I-Shape) เข้าสู่พื้นที่\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เริ่มต้นเช้าวันทำงาน ทีมงานได้ดำเนินการประสานงานเพื่อขนย้ายเสาเข็มเข้าสู่พื้นที่หน้างานอย่างเป็นระบบ สำหรับโปรเจกต์เขื่อนกันดินนี้ ทางทีมวิศวกรได้ออกแบบและเลือกใช้ <strong>เสาเข็มรูปตัวไอ (I-Shape Concrete Pile)</strong> หรือที่ในวงการช่างมักเรียกกันว่าไมโครไพล์ตัวไอ ซึ่งมีคุณสมบัติโดดเด่นในการรับน้ำหนักและทนทานต่อแรงดันดินด้านข้างได้ดีเยี่ยม\n            </p>\n            \n            <div class=\"row\" style=\"margin-top: 20px;\">\n                <div class=\"col-md-5 text-center\" style=\"margin-bottom: 20px;\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/saima-19-15092021-2.webp\" alt=\"การลำเลียงเสาเข็มไอ I-Shape Micropile ความยาว 10 เมตร สำหรับงานเขื่อนกันดิน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>ภาพการเตรียมพร้อมเสาเข็มไอ (I-Shape) รอการกดลงดิน</em></p>\n                </div>\n                <div class=\"col-md-7\">\n                    <h4 style=\"font-weight: bold; color: #333;\">ทำไมต้องใช้เสาเข็มยาวถึง 10 เมตร และใช้มากถึง 110 ต้น?</h4>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        การสร้างกำแพงกันดินริมน้ำ มีความเสี่ยงเรื่องการทรุดตัวและดินสไลด์สูงมาก การใช้เสาเข็มความยาว <strong>10 เมตร</strong> คือการคำนวณเผื่อระยะให้ปลายเข็มหยั่งลึกลงไปทะลุชั้นดินอ่อน (Soft Clay) จนถึงชั้นดินที่มีความหนาแน่นและมีค่าความฝืด (Skin Friction) ที่เหมาะสม ช่วยยึดเกาะโครงสร้างเขื่อนทั้งหมดให้ต้านทานกระแสน้ำได้\n                    </p>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        ส่วนจำนวนเสาเข็มที่มากถึง <strong>110 ต้น</strong> นั้น เป็นการออกแบบระยะห่างระหว่างต้น (Spacing) ให้ถี่เพียงพอที่จะรับน้ำหนักของแผ่นเสียบและแรงดันดินด้านหลังกำแพงได้อย่างสมดุล ไม่เกิดการโก่งตัวในอนาคตครับ\n                    </p>\n                </div>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. อุปสรรคที่คาดการณ์ไว้: การเคลียร์ \"หินทิ้งใต้น้ำ\" ก่อนเริ่มกดเข็ม\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                แม้การเตรียมเสาเข็มจะพร้อมร้อยเปอร์เซ็นต์ แต่ในงานก่อสร้างริมน้ำ มักจะมีอุปสรรคที่ซ่อนอยู่ใต้ผิวน้ำเสมอ นั่นคือ <strong>\"แนวหินทิ้งจากเขื่อนเดิม\"</strong> ซึ่งในอดีตมักจะมีการทิ้งก้อนหินขนาดใหญ่ลงไปเพื่อป้องกันตลิ่งพัง \n            </p>\n            \n            <div class=\"alert alert-warning\" style=\"margin-top: 20px; border-left: 5px solid #d9534f;\">\n                <h4 style=\"color: #d9534f; margin-top: 0;\"><i class=\"fa fa-exclamation-triangle\"></i> ผลกระทบหากไม่เคลียร์หินใต้น้ำ</h4>\n                <p style=\"margin-bottom: 0; line-height: 1.6;\">\n                    หากเราฝืนเดินเครื่อง <a href=\"https://www.theeraphong.com/images/pile\" target=\"_blank\">กดเสาเข็ม (Pile Driving)</a> ลงไปปะทะกับก้อนหินเหล่านี้โดยตรง จะทำให้เกิดปัญหา <strong>\"เสาเข็มหนีศูนย์\"</strong> หรือปลายเสาเข็มแตกหักเสียหาย ซึ่งจะส่งผลร้ายแรงต่อความสามารถในการรับน้ำหนัก (Load Bearing Capacity) ของฐานราก\n                </p>\n            </div>\n\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                <strong>วิธีแก้ปัญหา:</strong> ทางทีมงานได้ปรับแผนหน้างานทันที โดยใช้รถแบคโฮ (แมคโคร) เข้ามาทำการขุด เกลี่ย และงมก้อนหินใต้น้ำในแนวที่จะต้องกดเสาเข็มออกให้หมดก่อน ขั้นตอนนี้ต้องอาศัยความชำนาญของคนขับเครื่องจักรอย่างมาก เพื่อให้แนวดินโล่งและปลอดภัยที่สุดสำหรับเสาเข็มทุกต้น\n            </p>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. แผนการดำเนินงาน: กดเสาเข็ม 110 ต้น ด้วยเวลา 4-5 วัน\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลังจากเคลียร์แนวหินใต้น้ำสำเร็จ ทีมงานจะเข้าสู่กระบวนการนำรถแบคโฮมากดเสาเข็ม (ใช้ระบบกดไฮดรอลิกจากน้ำหนักรถ แทนการใช้ปั้นจั่นตอก เพื่อลดแรงสั่นสะเทือนไม่ให้กระทบโครงสร้างบ้านข้างเคียง) \n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ด้วยประสิทธิภาพของเครื่องจักรและทีมช่างที่คุ้นเคยกับงาน เราได้ประเมินไทม์ไลน์ (Timeline) การทำงานไว้ว่า การกดเสาเข็มความยาว 10 เมตร จำนวน 110 ต้นนี้ จะใช้ระยะเวลาดำเนินการเพียง <strong>4-5 วันทำการ</strong> เท่านั้น ซึ่งถือว่าเป็นความเร็วที่อยู่ในเกณฑ์มาตรฐานสูง ทำให้งานเดินหน้าได้รวดเร็ว ลดผลกระทบเรื่องเสียงรบกวนต่อเพื่อนบ้านให้น้อยที่สุดครับ\n            </p>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                4. การบริหารเวลาแบบมืออาชีพ: เตรียมงาน \"หล่อแผ่นเสียบกำแพงกันดิน\" ควบคู่กันไป\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เวลาทุกนาทีในไซต์งานก่อสร้างมีค่า! เพื่อไม่ให้เสียเวลารอคอย ทางทีมงานจึงได้จัดการทำงานแบบคู่ขนาน (Parallel Tasking) โดยในขณะที่เครื่องจักรกำลังจัดการเรื่องการกดเสาเข็มอยู่นั้น อีกมุมหนึ่งของหน้างาน ทีมช่างโครงสร้างได้เริ่มจัดเตรียมพื้นที่และ <strong>\"อุปกรณ์สำหรับหล่อแผ่นเสียบกำแพงกันดิน (Precast Concrete Panels)\"</strong> รอไว้แล้ว\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-7\">\n                    <ul class=\"list-group\" style=\"font-size: 16px;\">\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-primary\" style=\"margin-top: 0; font-weight: bold;\"><i class=\"fa fa-cubes\"></i> การทำพิมพ์หล่อมาตรฐาน</h4>\n                            <p style=\"margin-bottom: 0;\">เราใช้แบบหล่อ (Formwork) ที่ได้มาตรฐาน เพื่อให้แผ่นเสียบทุกแผ่นมีขนาดที่เท่ากันเป๊ะ เมื่อนำไปเสียบลงในร่องของเสาเข็มไอ จะประกบกันสนิท ไม่เกิดช่องโหว่ให้น้ำหรือดินรั่วซึม</p>\n                        </li>\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-primary\" style=\"margin-top: 0; font-weight: bold;\"><i class=\"fa fa-link\"></i> โครงเหล็กคุณภาพสูง (Rebar)</h4>\n                            <p style=\"margin-bottom: 0;\">ภายในแผ่นปูนทุกแผ่น จะถูกผูกด้วยเหล็กเสริมโครงสร้าง (Steel Reinforcement) คุณภาพสูงตามหลักวิศวกรรม เพื่อให้แผ่นเสียบมีความเหนียว รับแรงดัด (Bending Moment) จากแรงดันดินด้านหลังกำแพงได้อย่างมีประสิทธิภาพ</p>\n                        </li>\n                    </ul>\n                </div>\n                <div class=\"col-md-5 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/15092021/saima-19-15092021-3.webp\" alt=\"เตรียมโครงเหล็กและพิมพ์หล่อแผ่นเสียบกำแพงกันดิน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>พิมพ์หล่อแผ่นเสียบ และโครงเหล็กที่เตรียมไว้รอการเทปูน</em></p>\n                </div>\n            </div>\n\n            <p style=\"line-height: 1.8; font-size: 16px; margin-top: 20px;\">\n                เมื่อการกดเสาเข็มทั้ง 110 ต้นเสร็จสิ้นลง แผ่นเสียบเหล่านี้ก็จะถูกบ่มจนได้ค่าความแข็งแรง (Strength) ที่พอดี พร้อมนำมาประกอบเป็นกำแพงกันดินได้ทันทีครับ นี่คือวิธีการทำงานที่ช่วยให้เจ้าของบ้านได้งานที่รวดเร็วและเต็มเปี่ยมไปด้วยคุณภาพ\n            </p>\n\n            <div style=\"background-color: #f9f9f9; padding: 30px; border-radius: 8px; margin-top: 40px; border: 1px solid #eaeaea;\">\n                <h3 style=\"color: #333; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> ถาม-ตอบ (FAQ) ความรู้เรื่องงานเขื่อนกันดิน</h3>\n                <hr style=\"border-color: #ddd;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: การกดเสาเข็มด้วยรถแบคโฮ ดีกว่าการตอกด้วยปั้นจั่นอย่างไร?</h4>\n                <p style=\"margin-bottom: 20px;\">A: การกดเข็มด้วยน้ำหนักของรถแบคโฮ จะก่อให้เกิด <strong>\"แรงสั่นสะเทือนที่ต่ำมาก\" (Low Vibration)</strong> เหมาะสำหรับการทำงานในพื้นที่ชุมชน หรือบ้านริมน้ำที่มีโครงสร้างเก่าอยู่ใกล้เคียง ช่วยลดความเสี่ยงที่บ้านเพื่อนบ้านจะเกิดรอยร้าวครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: ทำไมต้องหล่อแผ่นเสียบที่หน้างาน แทนที่จะซื้อสำเร็จรูป?</h4>\n                <p>A: ในบางพื้นที่ (เช่น ซอยแคบ หรือริมคลอง) การนำรถบรรทุกขนาดใหญ่เข้ามาส่งแผ่นปูนสำเร็จรูปทำได้ยาก การหล่อแผ่นเสียบที่หน้างาน (On-site Casting) จึงช่วยแก้ปัญหาเรื่องการขนส่ง และยังทำให้เราควบคุมคุณภาพของการผูกเหล็กและส่วนผสมคอนกรีตได้ 100% ครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-left: 6px solid #0056b3; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #0056b3;\">สร้างรากฐานที่มั่นคง เพื่อปกป้องทรัพย์สินของคุณ</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    งานเขื่อนและกำแพงกันดินริมน้ำ ไม่ใช่งานที่ใครก็ทำได้ ต้องอาศัยทีมงานที่เข้าใจเรื่องโครงสร้างดิน การรับน้ำหนัก และมีประสบการณ์ในการแก้ปัญหาเฉพาะหน้า <br><br>\n                    หากท่านกำลังประสบปัญหาตลิ่งพัง ดินสไลด์ หรือต้องการสร้างกำแพงกันดินที่แข็งแกร่งทนทาน <strong>ธีรพงษ์เซอร์วิส</strong> ยินดีให้คำปรึกษาและประเมินราคาหน้างานฟรี!\n                </p>\n                <div class=\"row\">\n                    <div class=\"col-sm-6 text-right\">\n                        <a href=\"https://www.theeraphong.com/retaining-wall\" class=\"btn btn-primary btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px;\">\n                            <i class=\"fa fa-shield\"></i> บริการรับทำกำแพงกันดิน\n                        </a>\n                    </div>\n                    <div class=\"col-sm-6 text-left\">\n                        <a href=\"https://www.theeraphong.com/images/pile\" class=\"btn btn-info btn-lg\" style=\"padding: 15px 30px; font-weight: bold; border-radius: 30px; margin-bottom: 10px;\">\n                            <i class=\"fa fa-cogs\"></i> ดูผลงานกดเสาเข็มของเรา\n                        </a>\n                    </div>\n                </div>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1712045863923793.webp', 10, 'กำแพงกันดิน-ซอยบางกร่าง45-5-EP2', '2021-09-27 09:16:08', '2021-09-28 07:18:11'),
(26, 'ขุดบ่อน้ำ ปากน้ำกระโจมทอง', 'งานขุดบ่อน้ำ สถานที่ ที่ปากน้ำกระโจมทอง', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    รีวิวเจาะลึก: งานขุดบ่อน้ำ สระเก็บน้ำการเกษตร (ขนาด 7 x 20 x 2.5 เมตร) เปลี่ยนที่ดินรกร้างให้เกิดมูลค่า\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-calendar\"></i> อัปเดตผลงานหน้างานล่าสุด | <i class=\"fa fa-leaf\"></i> หมวดหมู่: งานขุดบ่อดิน, ปรับภูมิทัศน์ และ โคกหนองนา\n                </p>\n            </div>\n\n            <div class=\"lead\" style=\"line-height: 1.8; background-color: #f8fcf8; padding: 25px; border-left: 5px solid #5cb85c; border-radius: 4px; margin-bottom: 30px;\">\n                <p style=\"margin-bottom: 0;\">\n                    การจัดการแหล่งน้ำคือหัวใจสำคัญของการพัฒนาที่ดิน ไม่ว่าจะเป็นการทำเกษตรกรรม การทำ <strong>\"โคกหนองนาโมเดล\"</strong> หรือการปรับภูมิทัศน์จัดสวน วันนี้ทีมงาน <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> ขอพาทุกท่านมาชมรีวิวผลงาน <strong>การขุดบ่อน้ำบนพื้นที่ดินเปล่า</strong> พร้อมเจาะลึกเทคนิคการทำงาน การคำนวณปริมาตรดิน และการทำสโลป (Slope) เพื่อป้องกันตลิ่งพัง เพื่อเป็นแนวทางสำหรับท่านที่กำลังวางแผนขุดสระเก็บน้ำครับ\n                </p>\n            </div>\n\n            <h2 style=\"color: #2e6da4; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. สำรวจหน้างาน: จากที่ดินเปล่า สู่โปรเจกต์ขุดสระเก็บน้ำ\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เริ่มต้นโปรเจกต์นี้ ทีมงานได้รับการติดต่อจากลูกค้าที่ต้องการพัฒนาที่ดินเปล่าซึ่งมีลักษณะเป็นพื้นที่ราบรกร้าง ให้กลายเป็นแหล่งกักเก็บน้ำสำหรับการใช้งานในพื้นที่ โดยโจทย์ที่ได้รับมอบหมายคือการขุดบ่อน้ำขนาดมาตรฐาน ที่สามารถกักเก็บน้ำได้เพียงพอตลอดทั้งปี และต้องมีความปลอดภัย ไม่เกิดปัญหาดินสไลด์ในภายหลัง\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/270921/garden-2.webp\" alt=\"สภาพที่ดินเปล่าก่อนเริ่มงานขุดบ่อน้ำ ขุดสระ\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 1: สภาพหน้างานก่อนเริ่มดำเนินการ เป็นที่ดินเปล่าที่ต้องทำการเคลียร์ริ่ง (Clearing) ก่อนนำเครื่องจักรเข้าพื้นที่</em></p>\n            </div>\n\n            <h2 style=\"color: #2e6da4; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. การออกแบบและคำนวณปริมาตรดิน (Earthwork Calculation)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                งานขุดบ่อดินไม่ใช่แค่การนำรถแบคโฮมาตักดินออกไปแล้วจบครับ แต่ต้องผ่านการคำนวณทางวิศวกรรมเพื่อให้ได้สัดส่วนที่ถูกต้อง สำหรับโปรเจกต์นี้ สเปกบ่อน้ำที่ลูกค้าต้องการคือ:\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-6\">\n                    <ul class=\"list-group\" style=\"font-size: 16px;\">\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-success\" style=\"font-weight: bold; margin-top: 0;\"><i class=\"fa fa-arrows-h\"></i> ความกว้าง: 7 เมตร</h4>\n                            <p style=\"margin-bottom: 0;\">เป็นระยะที่เหมาะสม ไม่กว้างจนกินพื้นที่ใช้สอยส่วนอื่น และไม่แคบจนแสงแดดส่องไม่ถึงก้นบ่อ</p>\n                        </li>\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-success\" style=\"font-weight: bold; margin-top: 0;\"><i class=\"fa fa-arrows-v\"></i> ความยาว: 20 เมตร</h4>\n                            <p style=\"margin-bottom: 0;\">ความยาวระดับนี้ช่วยให้บ่อมีลักษณะเป็นสี่เหลี่ยมผืนผ้า รับปริมาณน้ำฝนได้ดี และง่ายต่อการปรับภูมิทัศน์ริมขอบบ่อ</p>\n                        </li>\n                        <li class=\"list-group-item\" style=\"padding: 15px;\">\n                            <h4 class=\"text-success\" style=\"font-weight: bold; margin-top: 0;\"><i class=\"fa fa-level-down\"></i> ความลึก: 2.50 เมตร</h4>\n                            <p style=\"margin-bottom: 0;\">ความลึกระดับ 2.5 เมตร ถือเป็นความลึกมาตรฐานที่แสงแดดสามารถส่องทะลุถึง ช่วยให้ระบบนิเวศใต้น้ำสมดุล และลดการระเหยของน้ำในช่วงฤดูแล้ง</p>\n                        </li>\n                    </ul>\n                </div>\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-default\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title\" style=\"font-weight: bold; color: #333;\"><i class=\"fa fa-calculator\"></i> เคล็ดลับจากช่าง: ปริมาตรดินที่ถูกขุดขึ้นมา</h4></div>\n                        <div class=\"panel-body\">\n                            <p style=\"line-height: 1.6;\">\n                                หากคำนวณปริมาตรทรงสี่เหลี่ยมเบื้องต้น (กว้าง x ยาว x ลึก) บ่อนี้จะมีปริมาตรดินที่ต้องขุดออกประมาณ <strong>350 ลูกบาศก์เมตร (คิว)</strong> \n                            </p>\n                            <p style=\"line-height: 1.6; margin-bottom: 0;\">\n                                <strong>คำถามคือ ดินเหล่านี้เอาไปไหน?</strong><br>\n                                ลูกค้าสามารถเลือกได้ว่า จะให้ทางเรานำดินไปทิ้ง (มีค่าขนทิ้ง) หรือจะนำดินที่ขุดได้นี้ ไปทำ <strong>\"คันล้อม\"</strong> รอบบ่อ หรือปั้นเป็น <strong>\"โคก\"</strong> สำหรับปลูกต้นไม้และสร้างบ้านพักตามหลักโคกหนองนาโมเดล ซึ่งวิธีหลังนี้จะช่วยประหยัดงบประมาณและเกิดประโยชน์สูงสุดครับ!\n                            </p>\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <h2 style=\"color: #2e6da4; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. ปฏิบัติการหน้างาน: การขุดและแต่งสโลป (Slope) ป้องกันตลิ่งพัง\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เมื่อแผนงานชัดเจน ทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> ได้นำรถแบคโฮ (แมคโคร) ขนาดที่เหมาะสมเข้าสู่พื้นที่ สิ่งสำคัญที่สุดในการขุดบ่อดินลึก 2.5 เมตร คือ <strong>\"การทำสโลป (Slope) หรือความลาดเอียงของขอบบ่อ\"</strong>\n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หากเราขุดขอบบ่อเป็นแนวตั้งฉาก 90 องศา เมื่อถึงฤดูฝน ดินอุ้มน้ำจะเกิดการสไลด์และพังทลายลงไปอุดก้นบ่ออย่างแน่นอน ทีมพนักงานขับเครื่องจักรของเรามีความชำนาญในการ \"แต่งตลิ่ง\" ให้มีความลาดเอียงในสัดส่วน 1:1 หรือ 1:1.5 (ขึ้นอยู่กับสภาพดิน) เพื่อให้ดินพยุงตัวมันเองได้อย่างมั่นคง\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 35px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/270921/garden-1.webp\" alt=\"ผลงานการขุดบ่อน้ำ สระเก็บน้ำ ขนาด 7x20x2.5 เมตร โดยธีรพงษ์เซอร์วิส\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 2: ผลงานขุดบ่อน้ำเสร็จสมบูรณ์ สังเกตการแต่งขอบสโลปที่สวยงาม ได้มาตรฐาน พร้อมกักเก็บน้ำทันที</em></p>\n            </div>\n\n            <h2 style=\"color: #2e6da4; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                4. ส่งมอบงานตรงเวลา ด้วยคุณภาพที่คุณวางใจ\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                งานขุดบ่อน้ำโปรเจกต์นี้สำเร็จลุล่วงไปได้ด้วยดีตามระยะเวลาที่กำหนดไว้ ทรงบ่อสวยงาม ได้ความกว้าง ความยาว และความลึกตรงตามสเปกที่ตกลงไว้ในสัญญาเป๊ะ ทางทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> ต้องขอขอบพระคุณลูกค้าเป็นอย่างสูง ที่ให้ความไว้วางใจเลือกใช้บริการเครื่องจักรและทีมช่างของเราครับ\n            </p>\n\n            <div style=\"background-color: #f4f8fa; padding: 30px; border-radius: 8px; margin-top: 50px; border: 1px solid #bce8f1;\">\n                <h3 style=\"color: #31708f; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> คำถามที่พบบ่อย (FAQ) เกี่ยวกับงานขุดบ่อน้ำ</h3>\n                <hr style=\"border-color: #9acfea;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: ขุดสระ 1 งาน หรือขุดบ่อเลี้ยงปลา ราคาประเมินจากอะไร?</h4>\n                <p style=\"margin-bottom: 20px;\">A: ราคาค่ารับเหมาขุดสระ จะประเมินจาก 1) ปริมาตรดินที่ขุด (กว้างxยาวxลึก) 2) การจัดการดิน (นำไปทิ้งภายนอก หรือเกลี่ยในพื้นที่) และ 3) สภาพหน้างาน (รถแบคโฮและรถดัมพ์สามารถเข้าออกได้สะดวกหรือไม่) โดยทางเรามีบริการประเมินราคาฟรีครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: ควรขุดบ่อลึกกี่เมตรดี น้ำถึงจะไม่แห้ง?</h4>\n                <p style=\"margin-bottom: 20px;\">A: ตามมาตรฐานทั่วไปแนะนำให้ขุดลึกตั้งแต่ 3-4 เมตรขึ้นไป (หากสภาพดินอำนวย) เพื่อให้ก้นบ่อทะลุไปถึงตาน้ำใต้ดิน และมีความลึกพอที่จะชดเชยน้ำที่ระเหยไปในช่วงฤดูร้อนแดดจัดครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: ขุดบ่อน้ำในที่ดินตัวเอง ต้องขออนุญาตหรือไม่?</h4>\n                <p>A: หากขุดบ่อที่มีความลึกจากระดับพื้นดินเกิน 3 เมตร หรือมีพื้นที่ปากบ่อเกิน 10,000 ตารางเมตร (ตาม พ.ร.บ. การขุดดินและถมดิน) จะต้องทำการแจ้งและขออนุญาตต่อเจ้าพนักงานท้องถิ่นครับ ซึ่งทางทีมงานเราพร้อมให้คำแนะนำในส่วนนี้</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-top: 5px solid #5cb85c; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #2c3e50; font-weight: bold;\">รับเหมาขุดบ่อ ขุดสระ โคกหนองนา ครบวงจร</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    เปลี่ยนที่ดินรกร้าง ให้กลายเป็นแหล่งกักเก็บน้ำเพื่อการเกษตร หรือจัดสวนปรับภูมิทัศน์ <br>ด้วยเครื่องจักรมาตรฐานและทีมงานมืออาชีพที่ไม่ทิ้งงาน\n                </p>\n                \n                <a href=\"https://www.theeraphong.com/garden-plot\" class=\"btn btn-success btn-lg\" style=\"padding: 15px 40px; font-weight: bold; border-radius: 30px; font-size: 18px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                    <i class=\"fa fa-leaf\"></i> ดูผลงานขุดบ่อดิน และงานจัดสวน เพิ่มเติม\n                </a>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1712046972067174.webp', 11, 'ขุดบ่อน้ำ-ปากน้ำกระโจมทอง', '2021-09-27 09:33:45', '2021-09-27 09:33:45');
INSERT INTO `blogs` (`id`, `title`, `description`, `content`, `image`, `service_category_id`, `slug`, `created_at`, `updated_at`) VALUES
(27, 'กำแพง กันดิน ซอยไทรม้า 19', 'ส่งงานก่อสร้างกำแพง กันดินซอยไทรม้ 19', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    เจาะลึกโครงสร้าง: กำแพงกันดินเสริมสเตย์ (Stay Beam) คืออะไร? พร้อมวิธีประเมินราคาและขั้นตอนการสร้างจริง\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-calendar\"></i> อัปเดตผลงานหน้างาน ซอยไทรม้า | <i class=\"fa fa-folder-open\"></i> หมวดหมู่: ความรู้งานฐานราก, เขื่อนกันดิน\n                </p>\n            </div>\n\n            <div class=\"lead\" style=\"line-height: 1.8; background-color: #f4f8fa; padding: 25px; border-left: 5px solid #0056b3; border-radius: 4px; margin-bottom: 30px;\">\n                <p style=\"margin-bottom: 10px;\"><strong>คำถามที่คนทำบ้านริมน้ำหรือที่ดินถมสูงสงสัยมากที่สุด:</strong></p>\n                <ul style=\"margin-bottom: 0;\">\n                    <li><em>\"ทำกำแพงกันดินเสริมสเตย์ ราคาเมตรละเท่าไหร่?\"</em></li>\n                    <li><em>\"กำแพงกันดินแบบมีสเตย์ แตกต่างจากกำแพงกันดินทั่วไปอย่างไร?\"</em></li>\n                    <li><em>\"ขั้นตอนการก่อสร้างที่ถูกต้องและได้มาตรฐาน มีวิธีอย่างไร?\"</em></li>\n                </ul>\n            </div>\n\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                วันนี้ทีมงาน <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> ได้ดำเนินการส่งมอบงานก่อสร้าง <strong>กำแพงกันดินแบบเสริมสเตย์ (Retaining Wall with Stay Beam)</strong> ณ หน้างานซอยไทรม้า เสร็จสิ้นอย่างสมบูรณ์ เราจึงขอใช้โอกาสนี้นำเสนอและเจาะลึกถึงเบื้องหลังการทำงาน เผยทุกขั้นตอนการก่อสร้างที่ได้มาตรฐาน เพื่อเป็นวิทยาทานและข้อมูลประกอบการตัดสินใจสำหรับท่านที่กำลังวางแผนทำเขื่อนหรือกำแพงกันดินครับ\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 35px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/271021/271021-5.webp\" alt=\"ภาพมุมสูง โครงสร้างกำแพงกันดินเสริมสเตย์ ซอยไทรม้า\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 6px 15px rgba(0,0,0,0.15);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพมุมสูง: โครงสร้างกำแพงกันดินริมคลองที่สร้างเสร็จสมบูรณ์ แข็งแกร่งด้วยระบบคานดึงรั้ง (สเตย์)</em></p>\n            </div>\n\n            <h2 style=\"color: #0056b3; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. ทำไมราคากำแพงกันดินถึงแตกต่างกัน? (ปัจจัยที่ใช้ประเมินราคา)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลายท่านมักจะสอบถามราคาประเมินเบื้องต้น แต่ในความเป็นจริง การตีราคางานกำแพงกันดินไม่สามารถระบุตายตัวเป็น \"ราคาต่อเมตร\" ได้ในทันที ผู้รับเหมามืออาชีพจะต้องลงพื้นที่ประเมินหน้างานอย่างละเอียด โดยพิจารณาจาก 3 อุปสรรคหลัก ซึ่งในโปรเจกต์ซอยไทรม้าแห่งนี้ เราต้องเผชิญและก้าวผ่านความท้าทายเหล่านี้มาได้สำเร็จครับ:\n            </p>\n            \n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-7\">\n                    <h4 style=\"font-weight: bold; color: #d9534f;\">อุปสรรคที่ 1: แนวหินแข็งใต้น้ำ (Underwater Rocks)</h4>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        การทำงานริมน้ำมักเจอเศษวัสดุหรือหินที่ถูกทิ้งไว้ในอดีต หินเหล่านี้คืออุปสรรคชิ้นใหญ่ในการกดเสาเข็มไมโครไพล์ (Micropile) หากฝืนกดลงไป เข็มอาจแตกหักหรือหนีศูนย์ได้ \n                    </p>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        <strong>การแก้ปัญหา:</strong> ทีมงานต้องใช้รถแบคโฮ (แมคโคร) ติดตั้งหัวขุด ลงไปทำการเคลียร์เศษหินและงมวัสดุใต้น้ำออก \"ทุกจุด\" ที่เป็นตำแหน่งลงเสาเข็ม ซึ่งขั้นตอนนี้ต้องใช้ความระมัดระวังสูงและทำให้งบประมาณหรือระยะเวลาดำเนินการเพิ่มขึ้นจากงานบนดินปกติ\n                    </p>\n                </div>\n                <div class=\"col-md-5 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/180921/180921-1.webp\" alt=\"เศษหินใต้น้ำ อุปสรรคในการกดเสาเข็มกำแพงกันดิน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-height: 400px; object-fit: cover; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>เศษหินและอุปสรรคใต้น้ำที่ต้องเคลียร์ก่อนกดเข็ม</em></p>\n                </div>\n            </div>\n\n            <div class=\"row\" style=\"margin-top: 40px;\">\n                <div class=\"col-md-5 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/1711139361714176.webp\" alt=\"รถแบคโฮเดินบนแผ่นเหล็กบนดินถมใหม่\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>การใช้แผ่นเหล็กปูทางเดินรถเครื่องจักรหนักบนดินอ่อน</em></p>\n                </div>\n                <div class=\"col-md-7\">\n                    <h4 style=\"font-weight: bold; color: #d9534f;\">อุปสรรคที่ 2: สภาพดินถมใหม่ที่ยังไม่เซ็ตตัว (Uncompacted Soil)</h4>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        พื้นที่หน้างานมีลักษณะเป็นดินที่เพิ่งถูกถมเข้ามาใหม่ และยังไม่ผ่านการบดอัด (Compaction) ทำให้ดินมีความร่วนซุยและรับน้ำหนักไม่ได้ รถเครื่องจักรหนักอย่างแบคโฮไม่สามารถขับเข้าไปทำงานได้โดยตรง เพราะเสี่ยงต่อการจมและเกิดอุบัติเหตุ\n                    </p>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        <strong>การแก้ปัญหา:</strong> เราต้องบริหารจัดการหน้างานโดยการเช่า <strong>\"แผ่นเหล็กปูทาง (Steel Plates)\"</strong> มาปูเป็นเส้นทางเดินรถ เพื่อกระจายน้ำหนักของเครื่องจักรให้ปลอดภัยที่สุด (สำหรับท่านที่สนใจรายละเอียดและราคาเกี่ยวกับการถมดิน สามารถอ่านเพิ่มเติมได้ <a href=\"https://www.theeraphong.com/landfill\" target=\"_blank\"><strong>ที่นี่</strong></a> ครับ)\n                    </p>\n                </div>\n            </div>\n\n            <p style=\"line-height: 1.8; font-size: 16px; margin-top: 25px;\">\n                <strong style=\"color: #d9534f;\">อุปสรรคที่ 3: สภาพอากาศ (Weather Conditions)</strong> <br>\n                ปัจจัยที่ไม่สามารถควบคุมได้อย่างพายุ ลม ฝน หรือระดับน้ำหลาก ล้วนส่งผลกระทบให้หน้างานต้องหยุดชะงัก ผู้รับเหมาจึงต้องมีความเชี่ยวชาญในการเผื่อเวลาและวางแผนสำรอง (Risk Management) ไว้ในใบเสนอราคาเสมอ\n            </p>\n\n\n            <h2 style=\"color: #0056b3; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. เจาะลึกขั้นตอน: วิธีสร้างกำแพงกันดินเสริมสเตย์ที่ได้มาตรฐาน\n            </h2>\n            \n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/271021/271021-1.webp\" alt=\"แบบแปลนโครงสร้างกำแพงกันดินและเสาเข็มสเตย์\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 700px; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>แบบแปลน (Blueprint) แสดงโครงสร้างการเชื่อมต่อระหว่างเสาเข็มหลักและเสาเข็มสเตย์</em></p>\n            </div>\n\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                โครงสร้างกำแพงกันดินที่ดี ไม่ใช่แค่การปักเสาลงไปแล้วจบ แต่คือการทำงานประสานกันของรากฐานหลายระบบ ดังนี้ครับ:\n            </p>\n\n            <ul class=\"list-group\" style=\"font-size: 16px; margin-top: 20px;\">\n                \n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\">ขั้นตอนที่ 1: การกดเสาเข็มหลัก (Main Pile) รับแนวกำแพง</h4>\n                    <p style=\"line-height: 1.6; margin-bottom: 15px;\">เริ่มจากการกดเสาเข็มหลักเพื่อกำหนดแนวกำแพง และเตรียมร่องสำหรับใส่แผ่นเสียบกันดิน เสาเข็มกลุ่มนี้จะทำหน้าที่รับน้ำหนักตัวกำแพงและต้านทานแรงดันดินด้านข้าง (Lateral Earth Pressure) ในระดับแรก</p>\n                    <div class=\"well well-sm\" style=\"background-color: #fcf8e3; border-color: #faebcc; color: #8a6d3b;\">\n                        <strong>สเปกวัสดุ:</strong> โปรเจกต์นี้เราเลือกใช้ <strong>เสาเข็มไมโครไพล์ (Micropile) รูปตัวไอ (I-Shape) ขนาด 18 เซนติเมตร ความยาว 10 เมตร</strong> โดยกดฝังลึกลงไปในดินประมาณ 8-9 เมตร เพื่อให้ปลายเข็มทะลุชั้นดินอ่อนไปยึดเกาะกับชั้นดินเหนียวแข็ง\n                    </div>\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/271021/271021-7.webp\" alt=\"ด้านหน้าแนวกำแพงกันดินหลัก\" class=\"img-responsive img-rounded\" style=\"margin-top: 15px; max-height: 300px;\">\n                </li>\n\n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\">ขั้นตอนที่ 2: การกดเสาเข็มสเตย์ (Stay Pile) หัวใจของความมั่นคง</h4>\n                    <p style=\"line-height: 1.6; margin-bottom: 15px;\">นี่คือจุดชี้เป็นชี้ตายของกำแพง! <strong>\"สเตย์\"</strong> คือระบบดึงรั้ง หากกำแพงกันดินริมคลองหรือที่ดินถมสูงไม่มีสเตย์ โอกาสที่กำแพงจะแบะล้มลงน้ำมีสูงถึง 90%</p>\n                    <p style=\"line-height: 1.6; margin-bottom: 15px;\">เราดำเนินการกดเสาเข็มสเตย์ (Micropile I-18 ยาว 10 เมตร กดลึก 9 เมตรเช่นกัน) โดยถอยร่นระยะเข้ามาบนฝั่ง <strong>ห่างจากแนวเสาเข็มหลักประมาณ 1.50 เมตร</strong> ทำหน้าที่เสมือน \"สมอเรือ\" ที่คอยดึงรั้งกำแพงหน้าไม่ให้ล้ม</p>\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/271021/271021-3.webp\" alt=\"แนวเสาเข็มสเตย์ดึงรั้งกำแพง\" class=\"img-responsive img-rounded\" style=\"margin-top: 15px; max-height: 300px;\">\n                </li>\n\n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 class=\"text-primary\" style=\"font-weight: bold; margin-top: 0;\">ขั้นตอนที่ 3-4: งานประกอบแผ่นเสียบและเทคานเชื่อม (Monolithic Casting)</h4>\n                    <p style=\"line-height: 1.6; margin-bottom: 10px;\">เมื่อฐานรากมั่นคงแล้ว เราจะดำเนินการ <strong>เสียบแผ่นพื้นคอนกรีต</strong> ลงไปตามร่องของเสาเข็มไอหลักเพื่อปิดกั้นดิน</p>\n                    <p style=\"line-height: 1.6; margin-bottom: 0;\">จากนั้นจึงเข้าสู่ขั้นตอนสำคัญ คือการ <strong>ผูกเหล็กและเทคอนกรีตคานทับหลัง (คานบน) พร้อมกับคานสเตย์ให้ประสานเข้าด้วยกันแบบไร้รอยต่อ (Monolithic)</strong> ทำให้เสาเข็มหน้า เข็มสเตย์ และแผ่นเสียบ กลายเป็นโครงสร้างเดียวกันที่แข็งแกร่งดุจหินผา</p>\n                </li>\n            </ul>\n\n            <h2 style=\"color: #0056b3; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. ต่อยอดฟังก์ชัน: การสร้างกำแพงรั้วบนคานเขื่อนกันดิน\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                นอกจากโครงสร้างใต้ดินที่แข็งแรงแล้ว <strong>คุณบ๊อบบี้</strong> (ลูกค้าคนสำคัญของเราในโปรเจกต์นี้) ยังได้มอบความไว้วางใจให้ทีมงานธีรพงษ์เซอร์วิส ดำเนินการออกแบบและก่อสร้าง \"รั้วด้านบนสันกำแพงกันดิน\" ต่อเนื่องไปเลย เพื่อให้ตอบโจทย์การใช้งานจริงในแต่ละโซนของบ้าน โดยแบ่งออกเป็น 3 รูปแบบหลักๆ คือ:\n            </p>\n            \n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-md-5 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/blogs/blogscontent/271021/271021-6.webp\" alt=\"กำแพงแบบทึบ สร้างบนฐานกำแพงกันดิน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>รั้วกำแพงแบบทึบ ก่ออิฐฉาบปูนบนสันกำแพงกันดิน</em></p>\n                </div>\n                <div class=\"col-md-7\">\n                    <ol style=\"font-size: 16px; line-height: 1.8; margin-top: 15px;\">\n                        <li style=\"margin-bottom: 15px;\"><strong>รั้วกำแพงแบบทึบ (Solid Fence):</strong> ก่ออิฐฉาบปูนปิดทึบ เหมาะสำหรับโซนที่ต้องการเพิ่มความเป็นส่วนตัวสูงสุด บังสายตาจากภายนอก และกันฝุ่นลม</li>\n                        <li style=\"margin-bottom: 15px;\"><strong>รั้วกำแพงเหล็ก (Steel Fence):</strong> ผสมผสานโครงเหล็กซี่โปร่ง ช่วยให้อากาศถ่ายเทได้ดี ลมพัดผ่านได้สบาย และเพิ่มความสวยงามโมเดิร์นให้กับตัวบ้าน</li>\n                        <li style=\"margin-bottom: 15px;\"><strong>รั้วกำแพงแบบเตี้ย (Low Wall):</strong> ออกแบบมาเพื่อโซนที่ติดริมแม่น้ำหรือริมคลองโดยเฉพาะ เพื่อให้เจ้าของบ้านสามารถนั่งพักผ่อนและชมทัศนียภาพริมน้ำได้โดยไม่ถูกบดบังสายตา</li>\n                    </ol>\n                    <div class=\"alert alert-success\" style=\"margin-top: 20px;\">\n                        <i class=\"fa fa-check-circle\"></i> <strong>มั่นใจได้ 100%:</strong> ด้วยรากฐานของเสาเข็มคู่ (หลัก+สเตย์) ที่กดลึกลงไปถึง 9 เมตร การรับน้ำหนักของรั้วด้านบนทั้ง 3 แบบนี้ จึงเป็นเรื่องง่ายดาย โครงสร้างนี้สามารถตั้งตระหง่านอยู่คู่บ้านคุณไปได้ยาวนานเป็นหลายสิบ หรือหลายร้อยปีอย่างแน่นอนครับ!\n                    </div>\n                </div>\n            </div>\n\n            <div style=\"background-color: #f9f9f9; padding: 30px; border-radius: 8px; margin-top: 50px; border: 1px solid #eaeaea;\">\n                <h3 style=\"color: #333; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> คำถามที่พบบ่อย (FAQ) เกี่ยวกับกำแพงกันดินสเตย์</h3>\n                <hr style=\"border-color: #ddd;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: ไม่ทำสเตย์ได้ไหม? เพื่อประหยัดงบประมาณ</h4>\n                <p style=\"margin-bottom: 20px;\">A: <strong style=\"color: #d9534f;\">ไม่แนะนำอย่างยิ่งครับ</strong> โดยเฉพาะพื้นที่ติดคลอง หรือพื้นที่ที่มีการถมดินสูงกว่าเพื่อนบ้านเกิน 1 เมตร หากไม่มีคานสเตย์ช่วยดึงรั้งไว้ แรงดันจากน้ำหนักดินและน้ำฝนจะดันให้กำแพงหลักหักหรือโค่นล้มในที่สุด เสียน้อยเสียยาก เสียมากเสียง่ายครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: การทำกำแพงกันดิน ใช้เวลาดำเนินการนานแค่ไหน?</h4>\n                <p>A: ขึ้นอยู่กับความยาวของหน้างานและอุปสรรคใต้ดินครับ แต่โดยทั่วไปสำหรับหน้างานความยาว 20-30 เมตร หากไม่มีอุปสรรคหินใต้น้ำ จะใช้เวลาดำเนินการตั้งแต่เริ่มกดเข็มจนถึงเทคานแล้วเสร็จ ประมาณ 15-20 วันทำการครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-left: 6px solid #0056b3; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #0056b3; font-weight: bold;\">วางรากฐานบ้านคุณ ให้มั่นคงอย่างมืออาชีพ</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    การก่อสร้างกำแพงกันดินคืองานวิศวกรรมที่ละเอียดอ่อน ต้องอาศัยประสบการณ์และความซื่อสัตย์ในการใช้วัสดุ <br>ทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> พร้อมเป็นที่ปรึกษาและดำเนินการแก้ปัญหาหน้างานให้ท่านอย่างตรงไปตรงมา\n                </p>\n                \n                <div style=\"font-size: 24px; color: #c9302c; font-weight: bold; margin-bottom: 20px;\">\n                    <i class=\"fa fa-phone-square\"></i> ปรึกษาและประเมินราคาฟรี โทร: 062-718-8847\n                </div>\n\n                <a href=\"https://www.theeraphong.com/retaining-wall\" class=\"btn btn-primary btn-lg\" style=\"padding: 15px 40px; font-weight: bold; border-radius: 30px; font-size: 18px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                    <i class=\"fa fa-info-circle\"></i> ดูรายละเอียดและผลงาน กำแพงกันดิน เพิ่มเติม\n                </a>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/blogs/1714793341402425.webp', 10, 'กำแพงกันดิน-ซอยไทรม้า19-ส่งงาน', '2021-10-27 17:06:07', '2021-10-27 17:13:27'),
(28, 'เทพื้นปูน ราคาต่อ ตาราง เมตร 2567 | รับเหมาเทพื้นคอนกรีต มืออาชีพ', 'เช็คราคาการเทพื้นปูนล่าสุดปี 2567 พร้อมข้อมูลเทพื้นคอนกรีต พื้นปูนขัดมัน ราคาค่าแรง ตารางเมตรละเท่าไหร่ บริการเทพื้นคุณภาพ ติดต่อทีมงานมืออาชีพได้ที่นี่', '<h2>💰 ราคาการเทพื้นปูนต่อ ตารางเมตร ปี 2567</h2><p>ราคาการเทพื้นปูนในปี 2567 มีความหลากหลายขึ้นอยู่กับความหนาของพื้นและประเภทของคอนกรีตที่ใช้ โดยทั่วไป ราคาจะอยู่ในช่วงดังนี้:</p><h3>🔹 ความหนา 10 ซม.</h3><ul><li><p>คอนกรีต 180 ksc: ประมาณ 390–420 บาท/ตร.ม.</p></li><li><p>คอนกรีต 210 ksc: ประมาณ 410–430 บาท/ตร.ม.</p></li><li><p>คอนกรีต 240 ksc: ประมาณ 440–460 บาท/ตร.ม.</p></li></ul><h3>🔹 ความหนา 15 ซม.</h3><ul><li><p>คอนกรีต 180 ksc: ประมาณ 490–520 บาท/ตร.ม.</p></li><li><p>คอนกรีต 210 ksc: ประมาณ 510–530 บาท/ตร.ม.</p></li><li><p>คอนกรีต 240 ksc: ประมาณ 540–560 บาท/ตร.ม.</p></li></ul><h3>🔹 ความหนา 20 ซม.</h3><ul><li><p>คอนกรีต 180 ksc: ประมาณ 790–820 บาท/ตร.ม.</p></li><li><p>คอนกรีต 210 ksc: ประมาณ 850–860 บาท/ตร.ม.</p></li></ul><p>คอนกรีต 240 ksc: ประมาณ 890–900 บาท/ตร.ม.</p><p>ราคาดังกล่าวเป็นราคาประมาณการและอาจเปลี่ยนแปลงได้ตามปัจจัยต่าง ๆ เช่น พื้นที่ที่ต้องการเทพื้น ความยากง่ายของงาน และต้นทุนวัสดุในแต่ละพื้นที่</p><hr><h2>🏡 ประเภทของพื้นปูนและการใช้งาน</h2><h3>✅ พื้นปูนขัดมัน</h3><p>พื้นปูนขัดมันเป็นที่นิยมในงานตกแต่งภายในและภายนอก เนื่องจากมีความเรียบเนียนและดูทันสมัย ราคาการเทพื้นปูนขัดมันอยู่ที่ประมาณ 450–500 บาท/ตร.ม. </p><img src=\"https://minio.speedynetloans.net/theeraphong/images/services/51ed6b20-f477-458d-a61d-411010457881.webp\"><h3>✅ <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://www.theeraphong.com/pour-concrete\">พื้นคอนกรีตเสริมเหล็ก</a></h3><p>เหมาะสำหรับพื้นที่ที่ต้องรับน้ำหนักมาก เช่น โรงงานหรือโรงจอดรถ ราคาจะสูงขึ้นตามความหนาและประเภทของเหล็กที่ใช้เสริม</p><hr><h2>📌 ปัจจัยที่มีผลต่อราคาการเทพื้นปูน</h2><ol><li><p><strong>ความหนาของพื้น</strong>: ยิ่งพื้นหนา ราคาจะยิ่งสูงขึ้นเนื่องจากต้องใช้วัสดุมากขึ้น</p></li><li><p><strong>ประเภทของคอนกรีต</strong>: คอนกรีตที่มีความแข็งแรงสูงจะมีราคาสูงกว่า</p></li><li><p><strong>พื้นที่ที่ต้องการเทพื้น</strong>: พื้นที่ขนาดใหญ่สามารถต่อรองราคาได้มากกว่าพื้นที่ขนาดเล็ก</p></li><li><p><strong>ความยากง่ายของงาน</strong>: พื้นที่ที่เข้าถึงยากหรือมีรูปทรงซับซ้อนจะมีค่าแรงสูงขึ้น</p></li></ol><hr><h2>📞 ติดต่อบริการเทพื้นปูนมืออาชีพ</h2><p>หากคุณกำลังมองหาผู้รับเหมาเทพื้นปูนที่มีประสบการณ์และเชื่อถือได้ สามารถติดต่อเราได้ที่:</p><ul><li><p><strong>โทรศัพท์</strong>: <strong>062-718-8847</strong></p></li><li><p><strong>LINE ID</strong>: <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"https://line.me/ti/p/h9SHumuTEB\"><strong>0627188847</strong></a></p></li><li><p><strong>อีเมล</strong>: <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"mailto:theeraphong.services@gmail.com\"><strong>theeraphong.services@gmail.com</strong></a></p></li></ul><p>เรามีทีมงานมืออาชีพพร้อมให้บริการคุณในทุกขั้นตอนของการเทพื้นปูน ตั้งแต่การวางแผนจนถึงการส่งมอบงาน</p><hr><h2>📝 สรุป</h2><p>การเทพื้นปูนเป็นงานที่ต้องการความชำนาญและการวางแผนที่ดี เพื่อให้ได้พื้นผิวที่มีคุณภาพและทนทานต่อการใช้งาน การเลือกใช้บริการจากผู้รับเหมาที่มีประสบการณ์จะช่วยให้คุณมั่นใจในคุณภาพของงานและความคุ้มค่าของงบประมาณ</p><p>หากคุณต้องการข้อมูลเพิ่มเติมหรือคำปรึกษาเกี่ยวกับการเทพื้นปูน สามารถติดต่อเราได้ตามข้อมูลที่ระบุไว้ข้างต้น เรายินดีให้บริการคุณด้วยความมืออาชีพและใส่ใจในทุกรายละเอียดของงาน</p>', 'images/services/6e825854-deb8-43c4-a02a-24e2dc9dab1f.webp', 27, 'เทพื้นปูน-ราคาต่อตารางเมตร-2567-รับเหมาเทพื้นคอนกรีต-มืออาชีพ', '2025-05-18 15:55:34', '2025-05-18 15:55:34'),
(29, 'เทปูน 1 คิว ใช้ปูนกี่ถุง? คำนวณวัสดุและต้นทุนอย่างมืออาชีพ', 'เรียนรู้วิธีคำนวณปริมาณปูน ทราย หิน สำหรับเทคอนกรีต 1 คิว พร้อมข้อมูลราคาปูนและพื้นที่ที่สามารถเทได้จากปูน 1 ถุง เพื่อวางแผนงานก่อสร้างอย่างมืออาชีพ', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    คู่มือช่างปี 2026: คอนกรีต 1 คิว ใช้ปูนกี่ถุง? สูตรผสมปูน 1:2:4 และเทคนิคการเทพื้นให้แข็งแรงไม่แตกร้าว\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-calculator\"></i> อัปเดตข้อมูลทางวิศวกรรมล่าสุด | <i class=\"fa fa-building\"></i> หมวดหมู่: ความรู้งานช่าง, เทคอนกรีต, คำนวณวัสดุ\n                </p>\n            </div>\n\n            <div class=\"lead\" style=\"line-height: 1.8; background-color: #fcf8f2; padding: 25px; border-left: 5px solid #d9534f; border-radius: 4px; margin-bottom: 30px;\">\n                <p style=\"margin-bottom: 0;\">\n                    ไม่ว่าคุณจะเป็นเจ้าของบ้านที่ต้องการปรับปรุงพื้นที่เล็กๆ เอง หรือผู้รับเหมาที่ต้องคุมต้นทุนโครงการใหญ่ คำถามสำคัญที่ต้องตอบให้ได้ก่อนเริ่มงานคือ <strong>\"คอนกรีต 1 คิว ใช้ปูนกี่ถุง?\"</strong> เพราะการกะปริมาณวัสดุที่แม่นยำคือหัวใจของการควบคุมงบประมาณ <br><br>\n                    บทความนี้ทีมงาน <strong>ธีรพงษ์เซอร์วิส (Theeraphong Service)</strong> จะพาคุณไปเจาะลึกสูตรการผสมคอนกรีตมาตรฐาน 240-280 ksc และสัดส่วน 1:2:4 พร้อมเผยเทคนิคการ <a href=\"https://www.theeraphong.com/pour-concrete\" target=\"_blank\" style=\"font-weight: bold; color: #d9534f; text-decoration: underline;\">เทคอนกรีต</a> ให้หน้างานออกมาเรียบเนียน แข็งแรง และไร้รอยแตกร้าวครับ\n                </p>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. คอนกรีต 1 คิว (m³) ต้องใช้วัสดุอะไรบ้าง? (สูตรผสมมาตรฐาน 280 ksc)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                คอนกรีต 1 คิว (หรือ 1 ลูกบาศก์เมตร) คือปริมาตรของคอนกรีตในทรงลูกบาศก์กว้าง 1 เมตร x ยาว 1 เมตร x หนา 1 เมตร สำหรับงานโครงสร้างทั่วไป เช่น พื้นบ้าน ลานจอดรถ หรือเสาเข็ม เรามักจะใช้กำลังอัดมาตรฐานที่ 280 ksc (กก./ตร.ซม.) ซึ่งต้องใช้สัดส่วนวัสดุดังนี้:\n            </p>\n            \n            <div class=\"table-responsive\" style=\"margin-top: 20px;\">\n                <table class=\"table table-bordered table-striped\" style=\"font-size: 16px;\">\n                    <thead style=\"background-color: #2c3e50; color: white;\">\n                        <tr>\n                            <th class=\"text-center\">รายการวัสดุ</th>\n                            <th class=\"text-center\">ปริมาณที่ใช้</th>\n                            <th class=\"text-center\">หน่วยนับ</th>\n                        </tr>\n                    </thead>\n                    <tbody>\n                        <tr>\n                            <td><strong>ปูนซีเมนต์ปอร์ตแลนด์ (โครงสร้าง)</strong></td>\n                            <td class=\"text-center\"><strong>6.5</strong></td>\n                            <td class=\"text-center\">ถุง (50 กก./ถุง)</td>\n                        </tr>\n                        <tr>\n                            <td><strong>ทรายหยาบ (ทรายน้ำจืดสะอาด)</strong></td>\n                            <td class=\"text-center\">820</td>\n                            <td class=\"text-center\">กิโลกรัม (ประมาณ 0.5-0.6 คิวทราย)</td>\n                        </tr>\n                        <tr>\n                            <td><strong>หินขนาด 3/4 นิ้ว (20 มม.)</strong></td>\n                            <td class=\"text-center\">1,120</td>\n                            <td class=\"text-center\">กิโลกรัม (ประมาณ 1.0-1.1 คิวหิน)</td>\n                        </tr>\n                        <tr>\n                            <td><strong>น้ำสะอาด (ไม่มีสารปนเปื้อน)</strong></td>\n                            <td class=\"text-center\">130-150</td>\n                            <td class=\"text-center\">ลิตร</td>\n                        </tr>\n                    </tbody>\n                </table>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. สูตรอมตะ 1:2:4 คืออะไร? และทำไมช่างถึงนิยมใช้\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หากคุณไม่มีตู้ชั่งน้ำหนักที่หน้างาน สูตรที่จดจำง่ายที่สุดคือ <strong>สัดส่วนโดยปริมาตร 1:2:4</strong> (ปูน 1 ส่วน : ทราย 2 ส่วน : หิน 4 ส่วน) โดยใช้ \"ถังปูน\" เป็นเกณฑ์วัด ซึ่งสูตรนี้จะให้กำลังอัดคอนกรีตที่เพียงพอสำหรับงานพื้นบ้านทั่วไป \n            </p>\n            <div class=\"panel panel-default\" style=\"border-top: 4px solid #31708f;\">\n                <div class=\"panel-body\">\n                    <p style=\"font-size: 16px; line-height: 1.6;\">\n                        <strong>เคล็ดลับมืออาชีพ:</strong> ปูนซีเมนต์ 1 ถุง (50 กก.) จะมีปริมาตรประมาณ 2 ถังปูน ดังนั้นหากใช้สูตร 1:2:4 ในการผสมปูน 1 ถุง คุณจะต้องใช้: <br>\n                        - ทราย 4 ถังปูน <br>\n                        - หิน 8 ถังปูน <br>\n                        และเติมน้ำให้พอดีสำหรับการทำงาน (ไม่แฉะจนเกินไป)\n                    </p>\n                </div>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. คอนกรีต 1 คิว เทได้กี่ตารางเมตร? (ตารางสรุปตามความหนา)\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                การประเมินพื้นที่ช่วยให้เราสั่งคอนกรีตผสมเสร็จหรือเตรียมปูนถุงได้ถูกต้อง พื้นที่ที่คุณจะเทได้จากคอนกรีต 1 คิว มีความสัมพันธ์โดยตรงกับความหนาดังนี้:\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 25px;\">\n                <div class=\"col-sm-4\">\n                    <div class=\"well text-center\" style=\"border-bottom: 4px solid #5cb85c;\">\n                        <h4>หนา 10 ซม.</h4>\n                        <p style=\"font-size: 28px; font-weight: bold; color: #5cb85c;\">10 ตร.ม.</p>\n                        <p class=\"text-muted\">เหมาะสำหรับพื้นบ้าน, ทางเดิน</p>\n                    </div>\n                </div>\n                <div class=\"col-sm-4\">\n                    <div class=\"well text-center\" style=\"border-bottom: 4px solid #f0ad4e;\">\n                        <h4>หนา 15 ซม.</h4>\n                        <p style=\"font-size: 28px; font-weight: bold; color: #f0ad4e;\">6.67 ตร.ม.</p>\n                        <p class=\"text-muted\">เหมาะสำหรับลานจอดรถยนต์</p>\n                    </div>\n                </div>\n                <div class=\"col-sm-4\">\n                    <div class=\"well text-center\" style=\"border-bottom: 4px solid #d9534f;\">\n                        <h4>หนา 20 ซม.</h4>\n                        <p style=\"font-size: 28px; font-weight: bold; color: #d9534f;\">5 ตร.ม.</p>\n                        <p class=\"text-muted\">เหมาะสำหรับลานจอดรถหนัก</p>\n                    </div>\n                </div>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                4. เทคนิคการเตรียมหน้างานและการเทคอนกรีตให้ได้คุณภาพ\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                การผสมปูนได้สัดส่วนที่ถูกต้องเป็นเพียงครึ่งเดียวของความสำเร็จ อีกครึ่งหนึ่งคือขั้นตอนการทำงานหน้างาน ซึ่งหากทำไม่ถูกวิธี พื้นที่เทปูนอาจเกิดการทรุดตัวหรือแตกร้าวในภายหลังได้ ทีมงาน <a href=\"https://www.theeraphong.com/pour-concrete\" target=\"_blank\" style=\"font-weight: bold; color: #0056b3;\">รับเทปูน</a> ของธีรพงษ์เซอร์วิส ขอแนะนำ 3 หัวใจสำคัญดังนี้:\n            </p>\n            \n            <ul class=\"list-group\" style=\"font-size: 16px;\">\n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 style=\"font-weight: bold; color: #333;\"><i class=\"fa fa-truck text-primary\"></i> 1. การบดอัดดินและการปรับระดับ</h4>\n                    <p style=\"line-height: 1.6; margin-top: 10px;\">ก่อนเทคอนกรีต ดินด้านล่างต้องถูกบดอัดให้แน่น และรองพื้นด้วยทรายหยาบพร้อมแผ่นพลาสติกกันความชื้น เพื่อป้องกันไม่ให้ดินดูดน้ำจากคอนกรีตเร็วเกินไปจนทำให้ปูนกรอบ</p>\n                </li>\n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 style=\"font-weight: bold; color: #333;\"><i class=\"fa fa-th text-primary\"></i> 2. การวางตะแกรงเหล็ก (Wire Mesh)</h4>\n                    <p style=\"line-height: 1.6; margin-top: 10px;\">ตะแกรงเหล็กต้องถูกยกสูงขึ้นจากพื้นดินประมาณ 3-5 ซม. (ลูกปูนรองเข็ม) เพื่อให้อยู่กึ่งกลางของชั้นคอนกรีต ทำหน้าที่รับแรงดึงและป้องกันรอยร้าวที่เกิดจากการยืดหดตัวของปูน</p>\n                </li>\n                <li class=\"list-group-item\" style=\"padding: 20px;\">\n                    <h4 style=\"font-weight: bold; color: #333;\"><i class=\"fa fa-tint text-primary\"></i> 3. การบ่มคอนกรีต (Curing)</h4>\n                    <p style=\"line-height: 1.6; margin-top: 10px;\">หลังจากเทเสร็จและปูนเริ่มเซ็ตตัว ต้องทำการฉีดน้ำเลี้ยงพื้นผิว (Wet Curing) ต่อเนื่องอย่างน้อย 7 วัน เพื่อให้ปูนทำปฏิกิริยาไฮเดรชั่นได้อย่างสมบูรณ์และได้ค่าความแข็งแรงตามสเปก</p>\n                </li>\n            </ul>\n\n            <div style=\"background-color: #f9f9f9; padding: 30px; border-radius: 8px; margin-top: 50px; border: 1px solid #eaeaea;\">\n                <h3 style=\"color: #333; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> ถาม-ตอบ (FAQ) เรื่องการผสมปูนเทพื้น</h3>\n                <hr style=\"border-color: #ddd;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: ใช้ปูนกาว หรือปูนฉาบ เทพื้นได้ไหม?</h4>\n                <p style=\"margin-bottom: 20px;\">A: <strong>ไม่ได้เด็ดขาดครับ</strong> ปูนแต่ละประเภทถูกออกแบบมาให้รับแรงต่างกัน ปูนฉาบเน้นการยึดเกาะผนังแต่รับแรงอัดไม่ได้เหมือนปูนโครงสร้าง พื้นจะแตกร่อนทันทีที่ใช้งานครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: ผสมเอง กับสั่งรถปูน อันไหนคุ้มกว่า?</h4>\n                <p>A: หากใช้ปริมาณมากกว่า 3-5 คิวขึ้นไป <strong>การสั่งรถปูน (Ready-Mixed) จะคุ้มกว่า</strong> ทั้งในแง่ของความเร็ว แรงงาน และความสม่ำเสมอของเนื้อคอนกรีตครับ แต่ถ้าเป็นงานซ่อมแซมเล็กน้อยไม่ถึง 1 คิว การผสมเองด้วยปูนถุงจะคล่องตัวกว่าครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-top: 5px solid #d9534f; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #2c3e50; font-weight: bold;\">วางแผนงานเทปูนอย่างมืออาชีพ ปรึกษาเราฟรี!</h3>\n                <p style=\"font-size: 16px; margin-bottom: 25px; color: #555;\">\n                    กะปริมาณไม่ถูก ไม่รู้จะเลือกค่า ksc เท่าไหร่ หรือต้องการทีมงานรับเหมาที่ซื่อสัตย์ ไม่ลดสเปกวัสดุ <br>\n                    <strong>ธีรพงษ์เซอร์วิส</strong> พร้อมให้บริการประเมินราคาและสำรวจหน้างานฟรี ในพื้นที่กรุงเทพฯ และปริมณฑล\n                </p>\n                \n                <a href=\"https://www.theeraphong.com/pour-concrete\" class=\"btn btn-danger btn-lg\" style=\"padding: 15px 40px; font-weight: bold; border-radius: 30px; font-size: 18px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                    <i class=\"fa fa-truck\"></i> ดูบริการเทคอนกรีต และขอใบเสนอราคา\n                </a>\n                \n                <div style=\"margin-top: 20px; font-size: 14px; color: #777;\">\n                    สอบถามเพิ่มเติมโทร: 062-718-8847 | <a href=\"https://line.me/ti/p/h9SHumuTEB\">\n                        <p>ไลน์ไอดี : 0627188847</p>\n                        <img class=\"img-rounded\" width=\"30%\" height=\"auto\"\n                            src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/lineid.webp\" alt=\"lineID\" />\n                    </a>\n\n                </div>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/services/cd2ec5b2-096b-46cd-bf8b-82a3bf655aed.webp', 27, 'เทปูน-1-คิว-ใช้ปูนกี่ถุง-คำนวณวัสดุและต้นทุนอย่างมืออาชีพ', '2025-05-23 09:15:37', '2025-05-29 14:23:26');
INSERT INTO `blogs` (`id`, `title`, `description`, `content`, `image`, `service_category_id`, `slug`, `created_at`, `updated_at`) VALUES
(30, 'ถมที่ด้วยเศษวัสดุก่อสร้าง ช่วยประหยัด เสริมพื้นแข็งแรง เหมาะกับงานสร้างกำแพงกันดิน', 'รู้จักการถมที่ด้วยเศษวัสดุก่อสร้าง พร้อมแนวทางเลือกใช้วัสดุให้ปลอดภัย ประหยัด และเตรียมพื้นที่สำหรับงานก่อสร้างกำแพงกันดินอย่างมีประสิทธิภาพ พร้อมบริการจากมืออาชีพ', '<div class=\"container-fluid\" style=\"padding: 0;\">\n    <div class=\"row\">\n        <div class=\"col-md-12\">\n            \n            <div class=\"page-header mt-0\" style=\"margin-top: 0;\">\n                <h1 style=\"font-size: 32px; line-height: 1.5; color: #2c3e50; font-weight: bold;\">\n                    เคล็ดลับงานฐานราก: ถมที่ด้วยเศษวัสดุก่อสร้าง ทางเลือกสุดประหยัด เตรียมพื้นที่ก่อนสร้างกำแพงกันดิน\n                </h1>\n                <p class=\"text-muted\" style=\"font-size: 15px;\">\n                    <i class=\"fa fa-cogs\"></i> หมวดหมู่: การเตรียมหน้างาน, งานฐานราก, วัสดุก่อสร้าง | <i class=\"fa fa-recycle\"></i> Eco-Friendly Construction\n                </p>\n            </div>\n\n            <div class=\"lead\" style=\"line-height: 1.8; background-color: #f8f9fa; padding: 25px; border-left: 5px solid #f0ad4e; border-radius: 4px; margin-bottom: 30px;\">\n                <p style=\"margin-bottom: 0;\">\n                    ในโปรเจกต์งานรับเหมาก่อสร้าง <a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\" style=\"color: #0056b3; font-weight: bold;\">กำแพงกันดิน (Retaining Wall)</a> โดยเฉพาะในโครงการขนาดกลางถึงขนาดใหญ่ที่มีสภาพเป็นดินอ่อน ดินเลน หรือมีน้ำขัง หนึ่งในขั้นตอนสำคัญที่หลายคนมักจะมองข้ามคือ <strong>\"การเตรียมพื้นที่หน้างาน (Site Preparation)\"</strong> เพื่อให้เครื่องจักรหนักสามารถเข้าไปทำงานได้อย่างปลอดภัย <br><br>\n                    การถมด้วยดินลูกรังหรือทรายล้วนอาจทำให้งบประมาณบานปลายโดยใช่เหตุ ปัจจุบันวิศวกรและผู้รับเหมาหลายโครงการจึงหันมาเลือกใช้ <strong>“การถมที่ด้วยเศษวัสดุก่อสร้าง (Construction Waste Fill)”</strong> ซึ่งเป็นอีกหนึ่งทางเลือกที่ทั้งคุ้มค่า แข็งแรง และเป็นมิตรกับสิ่งแวดล้อม (Recycle) หากเราเลือกใช้วัสดุและมีกระบวนการบดอัดอย่างถูกวิธีครับ\n                </p>\n            </div>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/services/0dcca921-8ae9-4259-8708-178f97ecc4e7.webp\" alt=\"ถมที่ด้วยเศษวัสดุก่อสร้าง เตรียมพื้นที่สร้างกำแพงกันดิน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 1: การนำเศษวัสดุก่อสร้างมาเกลี่ยเพื่อปรับระดับและเพิ่มความแข็งแรงให้พื้นผิวก่อนเริ่มงานฐานราก</em></p>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 40px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                1. ทำไมถึงต้องถมพื้นที่หน้างาน ก่อนเริ่มสร้างกำแพงกันดิน?\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                การก่อสร้างกำแพงกันดิน จำเป็นต้องใช้เครื่องจักรขนาดใหญ่ เช่น รถแบคโฮ (Excavator) รถปั้นจั่นตอกเสาเข็ม หรือรถกดเสาเข็มไมโครไพล์ หากหน้างานเดิมเป็นดินเหนียวอ่อน หรือพื้นที่ลุ่มต่ำ การนำเครื่องจักรเข้าไปเหยียบโดยตรงอาจทำให้เกิดปัญหา \"รถจมโคลน\" หรือ \"เครื่องจักรพลิกคว่ำ\" ได้ การถมพื้นที่หน้างานจึงมีประโยชน์เชิงวิศวกรรมดังนี้:\n            </p>\n            \n            <ul class=\"list-group\" style=\"font-size: 16px; margin-top: 20px;\">\n                <li class=\"list-group-item\" style=\"padding: 15px;\"><i class=\"fa fa-check-square-o text-success\"></i> <strong>เพิ่มกำลังรับน้ำหนัก (Bearing Capacity):</strong> ทำให้ผิวดินแข็งแรงพอที่จะรองรับน้ำหนักหลายสิบตันของเครื่องจักรหนักได้</li>\n                <li class=\"list-group-item\" style=\"padding: 15px;\"><i class=\"fa fa-check-square-o text-success\"></i> <strong>ปรับระดับพื้นที่ (Leveling):</strong> ช่วยลดความลาดชัน แก้ปัญหาพื้นที่สูง-ต่ำไม่เท่ากัน ทำให้กดเสาเข็มได้ตรง ดิ่งไม่หนีศูนย์</li>\n                <li class=\"list-group-item\" style=\"padding: 15px;\"><i class=\"fa fa-check-square-o text-success\"></i> <strong>ป้องกันปัญหาหน้าฝน:</strong> วัสดุประเภทเศษอิฐเศษปูน จะช่วยแก้ปัญหาน้ำขังและดินโคลนลื่น ทำให้ทีมช่างทำงานได้ต่อเนื่องไม่สะดุด</li>\n            </ul>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/services/57de4d73-ab3a-4871-9504-4e99b56798f1.webp\" alt=\"เครื่องจักรทำงานบนพื้นที่ถมด้วยเศษปูน\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 2: พื้นผิวที่ถูกถมและบดอัดด้วยเศษวัสดุก่อสร้าง จะมีความแน่น แข็งแรง รองรับการเคลื่อนที่ของเครื่องจักรได้ดีเยี่ยม</em></p>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                2. \"เศษวัสดุก่อสร้าง\" หรือ \"เศษวัสดุเหลือใช้\" มีอะไรบ้าง?\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                หลายคนมักมีคำถามว่า <em>เศษวัสดุเหลือใช้มีอะไรบ้าง?</em> หรือ <em>เศษวัสดุมีอะไรบ้างที่นำมาถมที่ได้?</em> ในทางวิศวกรรมก่อสร้าง เราจะแบ่ง <strong>เศษวัสดุก่อสร้าง (Construction and Demolition Waste - C&D)</strong> ออกเป็นประเภทที่ \"นำมาถมได้\" และ \"ห้ามนำมาถม\" ดังนี้ครับ:\n            </p>\n\n            <div class=\"row\" style=\"margin-top: 20px;\">\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-success\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title\" style=\"font-weight: bold;\"><i class=\"fa fa-thumbs-up\"></i> วัสดุที่เหมาะสำหรับนำมาถมที่</h4></div>\n                        <div class=\"panel-body\">\n                            <ul style=\"line-height: 1.8;\">\n                                <li><strong>เศษปูน / คอนกรีตเก่า:</strong> เศษเสาเข็มหัก พื้นคอนกรีตทุบ (แข็งแรงที่สุด)</li>\n                                <li><strong>อิฐหัก / อิฐมอญ / อิฐบล็อก:</strong> ระบายน้ำได้ดีเยี่ยม</li>\n                                <li><strong>กระเบื้องดินเผา หรือกระเบื้องหลังคาแตก</strong></li>\n                                <li><strong>เศษวัสดุธรรมชาติ:</strong> เช่น เศษหิน กรวด ดินทรายที่ปนมากับไซต์งาน</li>\n                            </ul>\n                        </div>\n                    </div>\n                </div>\n                <div class=\"col-md-6\">\n                    <div class=\"panel panel-danger\">\n                        <div class=\"panel-heading\"><h4 class=\"panel-title\" style=\"font-weight: bold;\"><i class=\"fa fa-ban\"></i> วัสดุที่ \"ห้าม\" นำมาถมที่เด็ดขาด</h4></div>\n                        <div class=\"panel-body\">\n                            <ul style=\"line-height: 1.8;\">\n                                <li><strong>เศษไม้ธรรมชาติ / เศษไม้แบบหล่อ:</strong> เพราะจะผุพังตามกาลเวลาและทำให้ดินทรุดเป็นโพรง รวมถึงเป็นแหล่งเพาะพันธุ์ปลวก</li>\n                                <li><strong>ขยะพลาสติก / โฟม / ถุงปูน:</strong> ไม่ย่อยสลาย และทำให้ชั้นดินไม่แน่น</li>\n                                <li><strong>เศษเหล็กยาว / เหล็กเส้น:</strong> อาจแทงทะลุล้อเครื่องจักร หรือเป็นอันตรายต่อทีมช่าง</li>\n                            </ul>\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/services/1b07cce0-4bea-4127-b399-6bd8d9fbd6c9.webp\" alt=\"เศษวัสดุก่อสร้าง เศษปูน อิฐหัก สำหรับถมที่\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 3: ลักษณะของเศษอิฐ เศษปูน และคอนกรีตหัก ที่ผ่านการคัดแยกขยะอันตรายออกแล้ว เหมาะแก่การทำชั้นฐานรากชั่วคราว</em></p>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                3. ไขข้อข้องใจ: \"เศษปูน\" ถมที่ได้ไหม? และเอาไปทำอะไรได้บ้าง?\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                สำหรับคำถามยอดฮิตที่ว่า <em>เศษปูนทำอะไรได้บ้าง?</em> หรือ <em>เศษปูนถมที่ได้หรือไม่?</em> คำตอบแบบฟันธงคือ <strong>\"ได้แน่นอนครับ และดีมากๆ ด้วย\"</strong> \n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เศษปูนที่ได้จากการทุบตึก หรือเศษคอนกรีตเหลือทิ้ง เมื่อนำมาถมที่จะทำหน้าที่เสมือน \"หินคลุก\" ขนาดใหญ่ โครงสร้างของคอนกรีตจะรับแรงกดทับได้มหาศาล (High Compressive Strength) แต่การนำเศษปูนมาถมที่ให้ได้มาตรฐาน จะต้องมีเทคนิคเล็กน้อยครับ:\n            </p>\n            \n            <div class=\"well\" style=\"background-color: #fdf7f7; border-color: #ebccd1;\">\n                <h4 style=\"color: #c9302c; font-weight: bold; margin-top: 0;\">💡 เทคนิคการถมที่ด้วยเศษปูน (Concrete Rubble Filling)</h4>\n                <ol style=\"line-height: 1.8; margin-bottom: 0;\">\n                    <li><strong>ต้องไม่มีสารเคมีปนเปื้อน:</strong> เพื่อไม่ให้เกิดผลกระทบต่อน้ำใต้ดิน</li>\n                    <li><strong>แยกเศษกระเบื้องแหลมคม:</strong> หากเป็นเศษปูนที่ติดกระเบื้อง ควรนำรถแบคโฮมาบดทับให้แตกละเอียดก่อน เพื่อป้องกันอันตราย</li>\n                    <li><strong>ต้องใช้ \"ดินหรือทราย\" กลบช่องว่าง:</strong> เศษปูนก้อนใหญ่มักจะมีช่องโหว่ (Voids) ระหว่างก้อน การถมที่ดีคือการเทเศษปูนลงไปก่อน แล้วนำทรายขี้เป็ดหรือดินมาเกลี่ยทับให้ไหลลงไปอุดช่องว่าง จากนั้นใช้รถบดอัดให้แน่น ผิวหน้างานจะเรียบและแข็งแกร่งสุดๆ ครับ</li>\n                </ol>\n            </div>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/services/72dcb8ff-71b2-414a-a564-7650a3e44778.webp\" alt=\"ข้อดีของการใช้เศษปูนถมที่\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 4: การนำเศษปูนมาใช้ถมที่ ไม่เพียงแต่แข็งแรง แต่ยังเป็นการนำวัสดุกลับมาใช้ใหม่ (Recycle) ช่วยลดภาวะโลกร้อน</em></p>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                4. อัปเดตราคา: ถมที่ด้วยเศษวัสดุก่อสร้าง และเศษปูน ราคาเท่าไหร่?\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เหตุผลหลักที่โครงการก่อสร้างนิยมใช้เศษวัสดุ คือ <strong>\"ความประหยัด (Cost-Effective)\"</strong> เมื่อเทียบกับการซื้อดินถมทั่วไป (ดินดำ, ดินลูกรัง) การถมที่ด้วยเศษปูนจะมีราคาที่ถูกกว่ามาก ลองมาดูตารางเปรียบเทียบ <em>เศษปูนราคา</em> และ <em>เศษปูนถมที่ราคา</em> เบื้องต้นกันครับ:\n            </p>\n\n            <div class=\"table-responsive\" style=\"margin-top: 20px;\">\n                <table class=\"table table-bordered table-striped table-hover\" style=\"font-size: 16px;\">\n                    <thead style=\"background-color: #2c3e50; color: white;\">\n                        <tr>\n                            <th class=\"text-center\" style=\"width: 50%;\">ประเภทวัสดุถมที่</th>\n                            <th class=\"text-center\" style=\"width: 50%;\">ราคาประเมินโดยประมาณ (บาท / คิว)*</th>\n                        </tr>\n                    </thead>\n                    <tbody>\n                        <tr>\n                            <td><strong>เศษปูนก้อนใหญ่ / คอนกรีตเก่าทุบ</strong></td>\n                            <td class=\"text-center text-primary\" style=\"font-weight: bold;\">100 – 200 บาท</td>\n                        </tr>\n                        <tr>\n                            <td><strong>อิฐหัก / เศษกระเบื้องบดละเอียด</strong></td>\n                            <td class=\"text-center text-primary\" style=\"font-weight: bold;\">80 – 150 บาท</td>\n                        </tr>\n                        <tr>\n                            <td><strong>เศษวัสดุผสม (ปนดิน / หิน / ทราย)</strong></td>\n                            <td class=\"text-center text-primary\" style=\"font-weight: bold;\">50 – 120 บาท</td>\n                        </tr>\n                        <tr style=\"background-color: #f2dede;\">\n                            <td><em>(เปรียบเทียบ) ดินลูกรัง / ทรายถม</em></td>\n                            <td class=\"text-center text-danger\" style=\"font-weight: bold;\">250 – 400+ บาท</td>\n                        </tr>\n                    </tbody>\n                </table>\n            </div>\n            <p class=\"text-muted\" style=\"font-size: 14px;\"><em>*หมายเหตุ: ราคาดังกล่าวเป็นเพียงราคาประเมินเฉพาะค่าวัสดุ อาจมีการเปลี่ยนแปลงขึ้นอยู่กับ \"ระยะทางในการขนส่ง\", \"ปริมาณที่สั่ง\", และ \"ค่าแรงเครื่องจักรในการเกลี่ยบดอัด\"</em></p>\n\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                5. ปัญหาโลกแตก: เศษวัสดุก่อสร้าง และ เศษปูน ทิ้งที่ไหน?\n            </h2>\n            \n            <div class=\"row\">\n                <div class=\"col-md-7\">\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        หากไซต์งานของคุณมีเศษปูนเหลือใช้ แต่ไม่ได้มีความจำเป็นต้องใช้ถมที่ หลายคนมักจะปวดหัวว่า <em>เศษปูนทิ้งที่ไหน?</em> หรือ <em>เศษวัสดุก่อสร้างทิ้งที่ไหนได้บ้างโดยไม่ผิดกฎหมาย?</em> \n                    </p>\n                    <p style=\"line-height: 1.8; font-size: 16px;\">\n                        การแอบนำเศษวัสดุก่อสร้างไปทิ้งตามที่สาธารณะหรือข้างทาง ถือเป็นความผิดตาม พ.ร.บ. รักษาความสะอาดฯ มีโทษปรับที่รุนแรงครับ วิธีการจัดการที่ถูกต้องและยั่งยืนคือ:\n                    </p>\n                    <ul style=\"line-height: 1.8; font-size: 16px;\">\n                        <li>ติดต่อ <strong>ศูนย์กำจัดขยะก่อสร้าง (C&D Waste Management)</strong> ของเอกชนที่มีใบอนุญาตถูกต้อง</li>\n                        <li>ส่งเข้า <strong>โรงงานรีไซเคิลคอนกรีต</strong> เพื่อบดย่อยนำกลับมาใช้เป็นมวลรวม (Aggregate)</li>\n                        <li><strong>ประกาศแจกฟรี / ขายถูก:</strong> ให้กับผู้รับเหมาหรือเจ้าของที่ดินที่กำลังมองหาวัสดุไปถมที่ลุ่มต่ำ (Win-Win Situation)</li>\n                    </ul>\n                </div>\n                <div class=\"col-md-5 text-center\">\n                    <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/services/2d1b89ab-fa0a-4c2a-a9e2-b2fd383da8c9.webp\" alt=\"เศษวัสดุก่อสร้างทิ้งที่ไหน การจัดการขยะก่อสร้าง\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; box-shadow: 0 4px 8px rgba(0,0,0,0.1);\">\n                    <p class=\"text-muted\" style=\"margin-top: 10px; font-size: 14px;\"><em>การจัดการเศษวัสดุก่อสร้างอย่างถูกวิธี ช่วยรักษาสิ่งแวดล้อมและไม่ผิดกฎหมาย</em></p>\n                </div>\n            </div>\n\n            <h2 style=\"color: #d9534f; margin-top: 50px; border-bottom: 2px solid #eee; padding-bottom: 10px;\">\n                6. ตัวอย่างผลงานจริง: ถมพื้นที่ด้วยเศษปูน เพื่อสร้างกำแพงกันดิน @นนทบุรี\n            </h2>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                เพื่อเห็นภาพที่ชัดเจนขึ้น ทีมงาน <strong>ธีรพงษ์เซอร์วิส</strong> ขอหยิบยกเคสตัวอย่างหน้างานที่จังหวัดนนทบุรี เราได้รับโจทย์ให้สร้างกำแพงกันดินริมคลอง แต่สภาพพื้นที่เป็นดินเลนอ่อนยวบยาบ ไม่สามารถนำรถกดเสาเข็มไมโครไพล์เข้าพื้นที่ได้ \n            </p>\n            <p style=\"line-height: 1.8; font-size: 16px;\">\n                ทางทีมวิศวกรจึงตัดสินใจใช้เทคนิค <strong>\"การถมด้วยเศษปูนบดละเอียด ร่วมกับเศษอิฐ-หิน\"</strong> บนพื้นที่กว่า 500 ตารางเมตร โดยนำรถแบคโฮมาทำการเกลี่ยและใช้กระบวยรถกดทับ (Compaction) ให้แน่น ควบคุมระดับดินตามมาตรฐานงานฐานราก\n            </p>\n\n            <div class=\"text-center\" style=\"margin: 30px 0;\">\n                <img src=\"https://pub-082f6213cffc4846aecb97f418c7c561.r2.dev/images/services/966a0419-99ac-4e8c-b6f9-d9bfaa8af967.webp\" alt=\"ผลงานถมพื้นที่หน้างานสร้างกำแพงกันดิน นนทบุรี\" class=\"img-responsive img-rounded\" style=\"display: inline-block; width: 100%; max-width: 800px; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n                <p class=\"text-muted\" style=\"margin-top: 12px; font-size: 14px;\"><em>ภาพที่ 6: ผลลัพธ์หน้างานจริง พื้นที่แน่น แข็งแรง เครื่องจักรเจาะเสาเข็มสามารถเข้าทำงานต่อได้ทันทีในวันรุ่งขึ้น โดยไม่มีปัญหาการทรุดตัวเลยแม้แต่น้อย</em></p>\n            </div>\n\n\n            <div style=\"background-color: #f9f9f9; padding: 30px; border-radius: 8px; margin-top: 50px; border: 1px solid #eaeaea;\">\n                <h3 style=\"color: #333; margin-top: 0;\"><i class=\"fa fa-question-circle\"></i> คำถามที่พบบ่อย (FAQ) เกี่ยวกับการถมดินด้วยเศษวัสดุ</h3>\n                <hr style=\"border-color: #ddd;\">\n                \n                <h4 style=\"font-weight: bold;\">Q: ถมที่ด้วยเศษปูนแล้ว อนาคตสามารถปลูกต้นไม้ได้ไหม?</h4>\n                <p style=\"margin-bottom: 20px;\">A: เศษปูนและเศษคอนกรีตมีความเป็นด่างสูงและไม่มีแร่ธาตุอาหาร หากถมจนถึงผิวดินชั้นบนสุดจะไม่เหมาะกับการปลูกต้นไม้ครับ หากวางแผนจะจัดสวน แนะนำให้ถมเศษปูนไว้ที่ชั้นล่าง (ทำเป็น Sub-base) แล้วนำ \"ดินหน้า (Topsoil)\" มาถมทับด้านบนสุดในความหนาอย่างน้อย 50-80 ซม. เพื่อให้รากต้นไม้เดินได้ครับ</p>\n\n                <h4 style=\"font-weight: bold;\">Q: จำเป็นต้องใช้รถบดอัด (Road Roller) หรือไม่?</h4>\n                <p>A: หากเป็นการถมเพื่อทำถนนหรือลานจอดรถถาวร จำเป็นต้องใช้รถบดสั่นสะเทือนเพื่อลดโพรงอากาศครับ แต่หากเป็นการถมชั่วคราวเพื่อให้เครื่องจักรเข้าไปทำกำแพงกันดิน การใช้แบคโฮเกลี่ยและตบให้แน่น (Track rolling) ก็ถือว่าเพียงพอแล้วครับ</p>\n            </div>\n\n            <div class=\"well text-center\" style=\"margin-top: 40px; background-color: #eaf3fd; border: none; border-top: 5px solid #d9534f; padding: 40px 20px;\">\n                <h3 style=\"margin-top: 0; color: #2c3e50; font-weight: bold;\">ทำไมต้องเลือก ธีรพงษ์เซอร์วิส?</h3>\n                <p style=\"font-size: 16px; margin-bottom: 20px; color: #555;\">\n                    <i class=\"fa fa-check text-success\"></i> ประสบการณ์ด้านงานถมที่และฐานรากกว่า 20 ปี <br>\n                    <i class=\"fa fa-check text-success\"></i> มีเครื่องจักรหนักเฉพาะทางครบวงจร (แบคโฮ, รถหกล้อ, เครื่องกดเข็ม) <br>\n                    <i class=\"fa fa-check text-success\"></i> ทีมงานเข้าใจหน้างานก่อสร้างจริง แก้ปัญหาหน้างานได้ตรงจุด <br>\n                    <i class=\"fa fa-check text-success\"></i> พร้อมลงพื้นที่ประเมินและให้คำปรึกษาฟรี!\n                </p>\n                \n                <div style=\"font-size: 24px; color: #c9302c; font-weight: bold; margin-top: 25px; margin-bottom: 20px;\">\n                    <i class=\"fa fa-phone\"></i> สนใจใช้บริการ หรือปรึกษางาน โทร: 062-718-8847, 087-700-7463\n                </div>\n\n                <a href=\"https://www.theeraphong.com/retaining-wall\" class=\"btn btn-danger btn-lg\" style=\"padding: 15px 40px; font-weight: bold; border-radius: 30px; font-size: 18px; box-shadow: 0 4px 6px rgba(0,0,0,0.1);\">\n                    <i class=\"fa fa-shield\"></i> ดูบริการรับทำกำแพงกันดินของเรา\n                </a>\n            </div>\n\n        </div>\n    </div>\n</div>', 'images/services/0dcca921-8ae9-4259-8708-178f97ecc4e7.webp', 10, 'ถมที่ด้วยเศษวัสดุก่อสร้าง-ช่วยประหยัด-เสริมพื้นแข็งแรง-เหมาะกับงานสร้างกำแพงกันดิน', '2025-05-29 15:12:08', '2025-05-29 15:29:00'),
(41, 'สรุปสเปกวัสดุและราคาก่อสร้างกำแพงกันดิน', 'งานก่อสร้างกำแพงกันดิน ตั้งแต่เริ่มต้น จนถึงส่งมอบงาน หน้างานซอยเพชรเกษม  69', '<h2 data-path-to-node=\"3\">สรุปสเปกวัสดุและราคาก่อสร้าง<a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\">กำแพงกันดิน</a></h2><p data-path-to-node=\"4\">สำหรับโครงการนี้ เรามีการแบ่งสเปกการทำงานออกเป็น 2 ส่วนหลักๆ ตามความเหมาะสมของหน้างานและการรับน้ำหนัก ดังนี้ครับ:</p><h3 data-path-to-node=\"5\">1. สเปกงานระยะ 46.6 เมตร (สำหรับพื้นที่รับแรงมาตรฐาน)</h3><p data-path-to-node=\"6\">พื้นที่ส่วนนี้ต้องการความแข็งแรงในระดับมาตรฐาน เหมาะสำหรับแนวรั้วหรือแนวเขตที่ดินทั่วไป</p><ul data-path-to-node=\"7\"><li><p data-path-to-node=\"7,0,0\"><b data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">เสาเข็มหลัก:</b> ใช้เสาเข็มรูปตัวไอ (I-Shape) ขนาด <b data-path-to-node=\"7,0,0\" data-index-in-node=\"47\">I18 x 6 เมตร</b> โดยทำการกดเสาเข็มที่ระยะห่าง <b data-path-to-node=\"7,0,0\" data-index-in-node=\"89\">1 เมตร/ต้น</b></p></li><li><p data-path-to-node=\"7,1,0\"><b data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">เสาเข็มสเตย์ (ดึงรั้ง):</b> ใช้เสาเข็ม <b data-path-to-node=\"7,1,0\" data-index-in-node=\"35\">I18 x 5 เมตร</b> เพื่อทำหน้าที่ดึงรั้งและกระจายแรง โดยกดที่ระยะห่าง <b data-path-to-node=\"7,1,0\" data-index-in-node=\"99\">2 เมตร/ต้น</b></p></li><li><p data-path-to-node=\"7,2,0\"><b data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">ราคาประเมิน:</b> ประมาณ <b data-path-to-node=\"7,2,0\" data-index-in-node=\"20\">7,xxx บาท / เมตร</b></p></li></ul><h3 data-path-to-node=\"8\">2. สเปกงานระยะ 11 เมตร (สำหรับพื้นที่รับแรงสูง)</h3><p data-path-to-node=\"9\">พื้นที่ช่วงนี้อาจมีระดับดินที่แตกต่างกันมาก หรือต้องรองรับน้ำหนักโครงสร้างในอนาคต จึงต้องอัปเกรดสเปกให้แน่นหนาขึ้น</p><ul data-path-to-node=\"10\"><li><p data-path-to-node=\"10,0,0\"><b data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">เสาเข็มหลัก:</b> ใช้เสาเข็มรูปตัวไอขนาดใหญ่ขึ้นเป็น <b data-path-to-node=\"10,0,0\" data-index-in-node=\"48\">I22 x 8 เมตร</b> (ลงลึกและรับน้ำหนักได้มากกว่า) กดที่ระยะห่าง <b data-path-to-node=\"10,0,0\" data-index-in-node=\"106\">1 เมตร/ต้น</b></p></li><li><p data-path-to-node=\"10,1,0\"><b data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">เสาเข็มสเตย์ (ดึงรั้ง):</b> ใช้เสาเข็ม <b data-path-to-node=\"10,1,0\" data-index-in-node=\"35\">I22 x 7 เมตร</b> กดที่ระยะห่าง <b data-path-to-node=\"10,1,0\" data-index-in-node=\"62\">2 เมตร/ต้น</b></p></li><li><p data-path-to-node=\"10,2,0\"><b data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">ราคาประเมิน:</b> ประมาณ <b data-path-to-node=\"10,2,0\" data-index-in-node=\"20\">15,xxx บาท / เมตร</b></p></li></ul><hr data-path-to-node=\"11\"><h2 data-path-to-node=\"12\">🗓️ ไทม์ไลน์และขั้นตอนการก่อสร้าง (Step-by-Step)</h2><p data-path-to-node=\"13\">เพื่อให้เห็นภาพรวมของการบริหารจัดการเวลา งานนี้ใช้ระยะเวลาดำเนินการตั้งแต่ต้นจนจบรวมทั้งสิ้นประมาณ <b data-path-to-node=\"13\" data-index-in-node=\"99\">65 วัน</b> โดยมีรายละเอียดแต่ละขั้นตอนดังนี้ครับ</p><h3 data-path-to-node=\"14\">ขั้นตอนที่ 1: เซ็นสัญญา และสั่งผลิตเสาเข็ม (ระยะเวลา 20 วัน)</h3><p data-path-to-node=\"15\">เริ่มต้นโครงการด้วยการสำรวจหน้างานจริง ทำการประเมิน ตกลงเงื่อนไข และเซ็นสัญญากับเจ้าของโครงการ หลังจากนั้นจะเข้าสู่กระบวนการสั่งผลิตเสาเข็มตามสเปก (I18 และ I22) จากโรงงานที่ได้มาตรฐาน มอก. เพื่อให้ได้อายุการใช้งานที่ยาวนาน</p><p data-path-to-node=\"15\"><br></p><h3 data-path-to-node=\"17\">ขั้นตอนที่ 2: ติดตั้ง และกดเสาเข็ม (ระยะเวลา 7 วัน)</h3><p data-path-to-node=\"18\">เมื่อเสาเข็มมาถึงหน้างาน ทีมงานจะใช้รถแม็คโครหรือเครื่องกดเสาเข็มไฮดรอลิก ทำการกดเสาเข็มหลักและเสาเข็มสเตย์ลงดินตามแนวและระยะที่วิศวกรกำหนดไว้ (1 เมตร/ต้น สำหรับเสาหลัก และ 2 เมตร/ต้น สำหรับเสาสเตย์) โดยต้องควบคุมให้ได้ดิ่งและได้ศูนย์กลางอย่างแม่นยำ</p><p data-path-to-node=\"18\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776583746_yi3irWMB1X.jpg?width=400&amp;format=webp\" style=\"width: 25%;\"><br></p><blockquote data-path-to-node=\"19\"><p data-path-to-node=\"19,0\"><i data-path-to-node=\"19,0\" data-index-in-node=\"0\">(ภาพประกอบ: แนวเสาเข็มตามแนวเอ็นที่ขึงไว้)</i></p></blockquote><h3 data-path-to-node=\"20\">ขั้นตอนที่ 3: ติดตั้งแผ่นพื้นรับแรง (ระยะเวลา 7 วัน)</h3><p data-path-to-node=\"21\">หลังจากได้แนวเสาเข็มที่มั่นคงแล้ว ขั้นตอนต่อไปคือการสอดและติดตั้งแผ่นพื้นคอนกรีตสำเร็จรูป (Plank) ลงในร่องของเสาเข็มรูปตัวไอ แผ่นพื้นเหล่านี้จะทำหน้าที่เป็นผนังรับแรงดันจากหน้าดินโดยตรง</p><p data-path-to-node=\"21\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776586239_TNOuz3lZK5.webp?width=400&amp;format=webp\" style=\"width: 25%;\">&nbsp; &nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776586239_944LPDa9ib.webp?width=400&amp;format=webp\" style=\"width: 25%;\"><br></p><blockquote data-path-to-node=\"22\"><p data-path-to-node=\"22,0\"><i data-path-to-node=\"22,0\" data-index-in-node=\"0\">(ภาพประกอบ: ทีมช่างกำลังหล่อแผ่นพื้นรับแรง และแผ่นพื้นรับแรงที่ถูกติดตั้งแล้ว)</i></p></blockquote><h3 data-path-to-node=\"23\">ขั้นตอนที่ 4: ประกอบไม้แบบ และติดตั้งเหล็กเสริม (ระยะเวลา 12 วัน)</h3><p data-path-to-node=\"24\">ขั้นตอนนี้ถือเป็นหัวใจสำคัญของความแข็งแรง! ทีมช่างจะทำการผูกเหล็กเสริมเพื่อทำ \"คานทับหลัง\" (Capping Beam) เพื่อยึดหัวเสาเข็มทุกต้นให้เป็นโครงสร้างเดียวกัน พร้อมทั้งผูกเหล็กเชื่อมไปยัง \"เสาเข็มสเตย์\" ด้านหลัง เพื่อป้องกันการล้มหรือเอียงของกำแพงในอนาคต จากนั้นจึงประกอบไม้แบบให้แน่นหนาเตรียมพร้อมสำหรับการเทปูน</p><p data-path-to-node=\"24\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776586293_LA88xn3DoL.webp?width=400&amp;format=webp\" style=\"width: 25%;\">&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776586293_3l3aIbvD78.webp?width=400&amp;format=webp\" style=\"width: 25%;\"><br></p><blockquote data-path-to-node=\"25\"><p data-path-to-node=\"25,0\"><i data-path-to-node=\"25,0\" data-index-in-node=\"0\">(ภาพประกอบ: งานผูกเหล็กคานทับหลังและเหล็กสเตย์ดึงรั้งที่ดูแน่นหนาได้มาตรฐาน มีะระยะหุ้มคอนกรีตที่เหมาะสม พร้อมการตีไม้แบบ)</i></p></blockquote><h3 data-path-to-node=\"26\">ขั้นตอนที่ 5: เทคอนกรีตคาน และสเตย์ (ระยะเวลา 10 วัน)</h3><p data-path-to-node=\"27\">เมื่อตรวจรับงานเหล็กเสริมและไม้แบบเรียบร้อย รถโม่ปูนจะเข้ามาทำการเทคอนกรีตลงในแบบที่เตรียมไว้ ทีมงานจะใช้เครื่องจี้ปูน (Vibrator) เพื่อไล่ฟองอากาศ ช่วยให้เนื้อคอนกรีตแน่น ไม่เป็นโพรง และหุ้มเหล็กเสริมได้อย่างสมบูรณ์แบบ</p><p data-path-to-node=\"27\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776586356_foVoPqQP8O.webp?width=400&amp;format=webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776586356_W3bAIjfg59.webp?width=400&amp;format=webp\" style=\"width: 25%;\"><br></p><blockquote data-path-to-node=\"28\"><p data-path-to-node=\"28,0\"><i data-path-to-node=\"28,0\" data-index-in-node=\"0\">(ภาพประกอบ: ภาพขณะรถโม่ปูนกำลังเทคอนกรีต และช่างกำลังใช้สายจี้ปูน)</i></p></blockquote><h3 data-path-to-node=\"29\">ขั้นตอนที่ 6: บ่มคอนกรีต แกะแบบ และส่งงาน (ระยะเวลา 9 วัน)</h3><p data-path-to-node=\"30\">หลังจากเทคอนกรีตเสร็จ จะต้องทิ้งไว้เพื่อบ่มคอนกรีตให้ได้ค่ากำลังอัด (Strength) ตามที่วิศวกรออกแบบไว้ เมื่อครบกำหนดเวลาจึงทำการแกะไม้แบบออก ทำความสะอาดพื้นที่ ตรวจสอบความเรียบร้อยของแนวกำแพง และทำการส่งมอบงานให้เจ้าของโครงการ</p><p data-path-to-node=\"31\">เมื่อเราได้กำแพงกันดินที่แข็งแรงสมบูรณ์พร้อมรับน้ำหนักแล้ว พื้นที่ด้านในกำแพงก็พร้อมสำหรับการพัฒนาต่อ ซึ่งขั้นตอนถัดไปในโปรเจกต์นี้จะมีการนำดินมาถมปรับระดับพื้นที่ก่อสร้าง สำหรับท่านใดที่สนใจหรือกำลังวางแผนปรับระดับที่ดิน สามารถตามไปอ่านรายละเอียดและขั้นตอนดีๆ เพิ่มเติมได้ที่บทความ 👉 <b data-path-to-node=\"31\" data-index-in-node=\"286\"><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><link-block _nghost-ng-c3026275334=\"\" class=\"ng-star-inserted\"><!----><!----><a _ngcontent-ng-c3026275334=\"\" target=\"_blank\" rel=\"noopener\" externallink=\"\" _nghost-ng-c1748752053=\"\" jslog=\"197247;track:generic_click,impression,attention;BardVeMetadataKey:[[\" r_ea124bfed83a1813\",\"c_7113d370e98da804\",null,\"rc_dc6f9137be7318e0\",null,null,\"th\",null,1,null,null,1,0]]\"=\"\" href=\"https://www.theeraphong.com/landfill\" class=\"ng-star-inserted\" data-hveid=\"0\" decode-data-ved=\"1\" data-ved=\"0CAAQ_4QMahcKEwihjOiqvPmTAxUAAAAAHQAAAAAQfQ\">งานถมดิน</a><!----></link-block><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></b> ของเราได้เลยครับ</p><p data-path-to-node=\"31\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776586437_l2i8707tgM.webp?width=400&amp;format=webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776586436_8InOGZOf9Q.webp?width=400&amp;format=webp\" style=\"width: 25%;\"><br></p><blockquote data-path-to-node=\"32\"><p data-path-to-node=\"32,0\"><i data-path-to-node=\"32,0\" data-index-in-node=\"0\">(ภาพประกอบ: ภาพผลงานกำแพงกันดินที่เสร็จสมบูรณ์ สวยงาม แข็งแรง และพร้อมสำหรับการถมดิน)</i></p></blockquote><hr data-path-to-node=\"33\"><p data-path-to-node=\"34\"><b data-path-to-node=\"34\" data-index-in-node=\"0\">สรุปท้ายบทความ:</b>\r\nการสร้างกำแพงกันดินไม่ใช่แค่งานนำเสามาปักและเอาแผ่นปูนมาเสียบ แต่ต้องอาศัยการคำนวณสเปกที่ถูกต้อง ระยะการตอกที่แม่นยำ และขั้นตอนการก่อสร้างที่ได้มาตรฐานวิศวกรรม เพื่อป้องกันปัญหาดินสไลด์หรือกำแพงพังทลายในอนาคต ซึ่งจะทำให้งบประมาณบานปลายได้ครับ หวังว่ารีวิวเคสนี้จะเป็นประโยชน์สำหรับผู้ที่กำลังหาข้อมูลนะครับ!</p><p data-path-to-node=\"34\"><br></p><p style=\"margin: 0px 0px 10px; color: rgb(76, 76, 76); font-family: \" segoe=\"\" ui\",=\"\" \"helvetica=\"\" neue\",=\"\" arial,=\"\" sans-serif;\"=\"\">📞 สนใจติดต่อสอบถามเพิ่มเติมได้ที่ 062-718-8846 หรือ Line ID : 0627188846</p><div><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/lineid.webp\" style=\"width: 25%;\"><br></div>', 'images/blogs/blog1776591070.jpg', 10, '2025-01-26-กำแพงกันดิน-เพชรเกษม69', '2026-04-19 02:31:11', '2026-04-19 23:55:26'),
(42, 'รีวิวผลงานระดับมาสเตอร์พีซ: ก่อสร้างกำแพงกันดินสเปคใหญ่ I26 ลึก 10 เมตร พร้อมระบบระบายน้ำ ครบจบในโปรเจกต์เดียว!', 'รีวิวงานก่อสร้างกำแพงกันดินสเปคไฮเอนด์ (เสาเข็ม I26 ลงลึก 10 ม.) ยาว 73 เมตร พร้อมระบบท่อระบายน้ำ คอนกรีต 300 Ksc จบปัญหาดินสไลด์และน้ำขัง ปรึกษาฟรี!', '<p data-path-to-node=\"8\"><span style=\"font-family: Tahoma;\">เวลาที่เราพูดถึง \"กำแพงกันดิน\" หลายคนอาจจะนึกถึงแค่การเอาแผ่นปูนมาเสียบๆ กั้นดินไว้ แต่สำหรับพื้นที่ที่มีความต่างระดับสูง หรือที่ดินแปลงใหญ่ที่ต้องรับแรงดันดินมหาศาล สเปคแบบทั่วไปอาจไม่เพียงพอครับ!</span></p><p data-path-to-node=\"9\"><span style=\"font-family: Tahoma;\">วันนี้ บริษัทธีรพงษ์เซอร์วิส จำกัด จะพามาเจาะลึกเบื้องหลังผลงานการก่อสร้าง&nbsp;</span><a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\"><span style=\"font-size: 16px;\"><i>กำแพงกันดิน</i></span></a><span style=\"font-family: Tahoma;\">&nbsp;ระยะทางยาวถึง </span><b data-path-to-node=\"9\" data-index-in-node=\"99\">73.676 เมตร</b><span style=\"font-family: Tahoma;\"> ที่เราจัดเต็มสเปคโครงสร้างแบบ \"Heavy Duty\" พร้อมแก้ปัญหาเรื่องน้ำขังด้วยการวางระบบท่อระบายน้ำไปพร้อมกันเลย โปรเจกต์นี้มีงบประมาณอยู่ที่ </span><b data-path-to-node=\"9\" data-index-in-node=\"247\">2x,xxx บาท / ตร.ม.</b><span style=\"font-family: Tahoma;\"> ซึ่งเมื่อเทียบกับอายุการใช้งานที่ยาวนานนับสิบปี ถือว่าคุ้มค่าทุกบาททุกสตางค์ครับ เรามาดูสเปคและขั้นตอนการทำงานหน้างานจริงกันเลย!</span></p><h2 data-path-to-node=\"10\"><span style=\"font-family: Tahoma;\">🏗️ เจาะลึกสเปคโครงสร้าง: ทำไมถึงต้องจัดเต็มขนาดนี้?</span></h2><p data-path-to-node=\"11\"><span style=\"font-family: Tahoma;\">งานนี้วิศวกรของเราออกแบบโครงสร้างเพื่อรับมือกับแรงดันดินและแรงสั่นสะเทือนในระยะยาวโดยเฉพาะ นี่คือสเปควัสดุไฮไลต์ที่เราเลือกใช้ครับ:</span></p><ul data-path-to-node=\"12\"><li><p data-path-to-node=\"12,0,0\"><b data-path-to-node=\"12,0,0\" data-index-in-node=\"0\"><span style=\"font-family: Tahoma;\">เสาเข็มหลัก (Main Pile):</span></b><span style=\"font-family: Tahoma;\"> อัปเกรดมาใช้เสาเข็มรูปตัวไอขนาดใหญ่ </span><b data-path-to-node=\"12,0,0\" data-index-in-node=\"61\">I26 x 10 เมตร</b><span style=\"font-family: Tahoma;\"> เสริม </span><b data-path-to-node=\"12,0,0\" data-index-in-node=\"81\">Dowel bar 6DB16 ยาวตลอดแนวเสาเข็ม</b><span style=\"font-family: Tahoma;\"> เพื่อป้องกันการหักกลางต้นเมื่อเจอแรงดันมหาศาล (กดระยะ 1 เมตร/ต้น)</span></p></li><li><p data-path-to-node=\"12,1,0\"><b data-path-to-node=\"12,1,0\" data-index-in-node=\"0\"><span style=\"font-family: Tahoma;\">เสาเข็มสเตย์ดึงรั้ง:</span></b><span style=\"font-family: Tahoma;\"> ใช้สเปคเดียวกับเสาหลัก </span><b data-path-to-node=\"12,1,0\" data-index-in-node=\"44\">I26 x 10 เมตร (เสริม Dowel 6DB16)</b><span style=\"font-family: Tahoma;\"> กดที่ระยะ 2 เมตร/ต้น กระจายแรงดึงให้สมดุล</span></p></li><li><p data-path-to-node=\"12,2,0\"><b data-path-to-node=\"12,2,0\" data-index-in-node=\"0\"><span style=\"font-family: Tahoma;\">สเตย์รูปตัววาย (Y-Shape Stay):</span></b><span style=\"font-family: Tahoma;\"> ออกแบบพิเศษเพื่อช่วยโอบรัดและกระจายแรงดึงรั้งได้ดีกว่าสเตย์แบบเส้นตรง</span></p></li><li><p data-path-to-node=\"12,3,0\"><b data-path-to-node=\"12,3,0\" data-index-in-node=\"0\"><span style=\"font-family: Tahoma;\">โครงสร้างเหล็กเสริม:</span></b><span style=\"font-family: Tahoma;\"> คานทับหลังใช้เหล็ก </span><b data-path-to-node=\"12,3,0\" data-index-in-node=\"40\">6DB16</b><span style=\"font-family: Tahoma;\">, คานสเตย์ใช้ </span><b data-path-to-node=\"12,3,0\" data-index-in-node=\"59\">4DB12</b><span style=\"font-family: Tahoma;\">, และแผ่นพื้นรับแรง คสล. เสริมเหล็ก </span><b data-path-to-node=\"12,3,0\" data-index-in-node=\"100\">RB9@0.10</b><span style=\"font-family: Tahoma;\"> (ถักตะแกรงถี่พิเศษ)</span></p></li><li><p data-path-to-node=\"12,4,0\"><b data-path-to-node=\"12,4,0\" data-index-in-node=\"0\"><span style=\"font-family: Tahoma;\">คอนกรีตกำลังอัดสูง:</span></b><span style=\"font-family: Tahoma;\"> เลือกใช้คอนกรีตผสมเสร็จกำลังอัด </span><b data-path-to-node=\"12,4,0\" data-index-in-node=\"52\">300 Ksc</b><span style=\"font-family: Tahoma;\"> เทตลอดแนวคาน แน่น แกร่ง ทนทานน้ำซึม</span></p></li></ul><hr data-path-to-node=\"13\"><h2 data-path-to-node=\"14\"><span style=\"font-family: Tahoma;\">🚧 8 ขั้นตอนการเนรมิตกำแพงกันดินสเปคยักษ์ (พร้อมระบบน้ำ)</span></h2><p data-path-to-node=\"15\"><span style=\"font-family: Tahoma;\">การบริหารจัดการหน้างานระดับนี้ต้องเป๊ะทุกขั้นตอน เพื่อให้งานเดินหน้าได้ตามไทม์ไลน์โดยไม่สะดุดครับ</span></p><p data-path-to-node=\"15\"><br></p><p data-path-to-node=\"16\"><b data-path-to-node=\"16\" data-index-in-node=\"0\"><span style=\"font-family: Tahoma;\">1. เซ็นสัญญา และสั่งผลิตเสาเข็ม (Custom Made)</span></b><span style=\"font-family: Tahoma;\">\r\nเนื่องจากเสาเข็มของเราเป็นสเปคพิเศษที่ต้องสั่งเสริม Dowel 6DB16 ยาวตลอดแนวจากโรงงาน เราจึงวางแผนสั่งผลิตล่วงหน้าทันทีที่เคลียร์แบบและเซ็นสัญญากับเจ้าของที่ดินเรียบร้อย\r\n</span><i data-path-to-node=\"16\" data-index-in-node=\"214\"><span style=\"font-family: Tahoma;\">[</span></i></p><p data-path-to-node=\"16\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776742327_GnZQYOyRVl.webp?width=400&amp;format=webp\" style=\"width: 25%;\"><i data-path-to-node=\"16\" data-index-in-node=\"214\"><br></i></p><p data-path-to-node=\"16\"><i data-path-to-node=\"16\" data-index-in-node=\"214\">ภาพ: ทีมวิศวกรผู้รบเหมา และที่ปรึกษาโครงการพูดคุยปรึกษาหน้างาน</i></p><p data-path-to-node=\"16\"><i data-path-to-node=\"16\" data-index-in-node=\"214\"><br></i></p><p data-path-to-node=\"17\"><b data-path-to-node=\"17\" data-index-in-node=\"0\">2. ขนส่งเสาเข็มเข้าสู่หน้างาน</b>\r\nการจัดการ Logistics สำหรับเสาเข็มขนาด I26 ยาว 10 เมตร จำนวนหลายสิบต้น ทีมงานต้องสำรวจเส้นทางและใช้รถบรรทุกขนาดใหญ่ทยอยลำเลียงเข้าพื้นที่อย่างระมัดระวัง&nbsp;</p><p data-path-to-node=\"17\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776738977_ATxWftEA9x.webp?width=400&amp;format=webp\" style=\"width: 25%;\"></p><p data-path-to-node=\"16\"><i data-path-to-node=\"16\" data-index-in-node=\"214\">ภาพ: รถพ่วงขนส่งเสาเข็ม</i></p><div><i data-path-to-node=\"16\" data-index-in-node=\"214\"><br></i></div><p data-path-to-node=\"18\"><b data-path-to-node=\"18\" data-index-in-node=\"0\">3. ติดตั้งเสาเข็ม (Pressing Process)</b>\r\nเราใช้แบคโฮ<a href=\"https://www.theeraphong.com/pile\" target=\"_blank\"><span style=\"font-size: 16px;\"><i>กดเสาเข็ม</i></span></a>หลักลงดินลึก 10 เมตร ที่ระยะห่างเป๊ะๆ ทุก 1 เมตร และกดเสาเข็มสเตย์ด้านหลังที่ระยะ 2 เมตร โดยมีวิศวกรควบคุมแนวดิ่งและศูนย์กลางด้วยกล้องเซอร์เวย์&nbsp;</p><p data-path-to-node=\"18\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776739985_6UtPS74eyq.webp?width=400&amp;format=webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776739985_aGAtlfMHmG.webp?width=400&amp;format=webp\" style=\"width: 25%;\"></p><p data-path-to-node=\"16\"><i data-path-to-node=\"16\" data-index-in-node=\"214\">ภาพ: รถแบคโฮกดเสาเข็มกำแพงกันดิน</i></p><div><i data-path-to-node=\"16\" data-index-in-node=\"214\"><br></i></div><p data-path-to-node=\"19\"><b data-path-to-node=\"19\" data-index-in-node=\"0\">4. ติดตั้งแผ่นพื้นรับแรง</b>\r\nเมื่อแนวเสาเข็มตั้งตระหง่านมั่นคง ทีมช่างทำการเสียบแผ่นพื้น คสล. (RB9@0.10) ลงไประหว่างร่องเสาเข็มตัวไอ เพื่อทำหน้าที่เป็นผนังรับแรงดันดินด่านแรก&nbsp;</p><p data-path-to-node=\"19\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740168_1rniXIcG1e.webp\" style=\"width: 25%;\">&nbsp; &nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740166_T7oQU7IQM9.webp?width=400&amp;format=webp\" style=\"width: 25%;\"> &nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740167_DueTRXG2R9.webp?width=400&amp;format=webp\" style=\"width: 25%;\"><br></p><p data-path-to-node=\"16\"><i data-path-to-node=\"16\" data-index-in-node=\"214\">ภาพ: หล่อแผ่นพื้นรับแรง และติดตั้งแผ่นพื้นรับแรง</i></p><p data-path-to-node=\"20\"><b data-path-to-node=\"20\" data-index-in-node=\"0\">5. วางท่อระบายน้ำ (จุดเด่นของโปรเจกต์!)</b>\r\nนี่คือคีย์เวิร์ดสำคัญของการรักษากำแพงกันดิน! ดินที่อุ้มน้ำจะสร้างแรงดันมหาศาล เราจึงขุดร่องและ<a href=\"https://www.theeraphong.com/pipe\" target=\"_blank\"><span style=\"font-size: 16px;\"><i>วางระบบท่อระบายน้ำขนานไปกับแนวกำแพง</i></span></a> เพื่อดึงน้ำใต้ดินและผิวดินออกไปทิ้ง ลดภาระโครงสร้างได้อย่างเด็ดขาด</p><p data-path-to-node=\"20\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776742648_mPmtsZpmzf.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776742648_LCiPom9pam.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776742647_s6YKdk2euP.webp\" style=\"width: 25%;\"><br></p><p data-path-to-node=\"16\"><i data-path-to-node=\"16\" data-index-in-node=\"214\">ภาพ: แนวท่อระบายน้ำหลังกำแพงกันดิน</i></p><p data-path-to-node=\"21\"><b data-path-to-node=\"21\" data-index-in-node=\"0\">6. ประกอบไม้แบบ และวางเหล็กเสริม</b>\r\nช่างเหล็กฝีมือดีเข้าหน้างาน ผูกเหล็กคานทับหลังเชื่อมต่อกับเหล็กคานสเตย์ เข้าสู่ \"สเตย์รูปตัววาย\" ให้เป็นโครงสร้างเนื้อเดียวกัน จากนั้นจึงประกอบไม้แบบให้แน่นหนา</p><p data-path-to-node=\"21\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740289_LNGMpUCUoT.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740289_lUpy0tIKiF.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740290_e8dVH6TkEv.webp\" style=\"width: 25%;\">&nbsp;&nbsp;</p><p data-path-to-node=\"21\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740290_HH9e3S2Sfz.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740289_VNlBB2TQAk.webp\" style=\"width: 25%;\"><br></p><p data-path-to-node=\"16\"><i data-path-to-node=\"16\" data-index-in-node=\"214\">ภาพ: เหล็กเสริมที่ใช้ในโครงการ</i></p><div><i data-path-to-node=\"16\" data-index-in-node=\"214\"><br></i></div><p data-path-to-node=\"22\"><b data-path-to-node=\"22\" data-index-in-node=\"0\">7. เทคอนกรีต คาน และสเตย์</b>\r\nระดมรถโม่ปูน เทคอนกรีตกำลังอัด 300 Ksc ลงในไม้แบบ ทีมงานใช้เครื่องจี้ปูนไล่ฟองอากาศอย่างละเอียด พร้อมพ่นน้ำยาบ่มคอนกรีต เพื่อให้คอนกรีตหุ้มเหล็กเสริมมิดชิด ป้องกันสนิมในระยะยาว&nbsp;</p><p data-path-to-node=\"22\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740291_pSV2ANQ77r.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740291_pFQESwG9iI.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740407_6C1ace98hR.webp\" style=\"width: 25%;\">&nbsp;&nbsp;</p><p data-path-to-node=\"22\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740407_X8Yrf6I47e.webp\" style=\"width: 25%;\"></p><p data-path-to-node=\"16\"><i data-path-to-node=\"16\" data-index-in-node=\"214\">ภาพ: เทคอนกรีต และพ่นน้ำยาบ่มคอนกรีต</i></p><div><i data-path-to-node=\"16\" data-index-in-node=\"214\"><br></i></div><p data-path-to-node=\"23\"><b data-path-to-node=\"23\" data-index-in-node=\"0\">8. แกะไม้แบบ บ่มคอนกรีต และส่งงาน</b>\r\nทิ้งระยะเวลาบ่มคอนกรีตให้ได้ค่าความแข็งแรงตามมาตรฐาน ทำการแกะไม้แบบ เคลียร์พื้นที่ เก็บรายละเอียดความเรียบร้อย และส่งมอบผลงานสุดอลังการนี้ให้กับลูกค้าครับ!</p><p data-path-to-node=\"23\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740475_RKypmyVsl4.webp\" style=\"width: 25%;\">&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740475_lyb9YP3m3o.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740474_F231aOXs8Q.webp\" style=\"width: 25%;\">&nbsp;&nbsp;</p><p data-path-to-node=\"23\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776740474_1N1dl3Kyzr.webp\" style=\"width: 25%;\"></p><p data-path-to-node=\"16\"><i data-path-to-node=\"16\" data-index-in-node=\"214\">ภาพ: กำแพงกันดิน</i></p><div><i data-path-to-node=\"16\" data-index-in-node=\"214\"><br></i></div><hr data-path-to-node=\"24\"><h2 data-path-to-node=\"25\">💬 คุยกับผู้เชี่ยวชาญ ธีรพงษ์เซอร์วิส</h2><p data-path-to-node=\"26\">จบไปแล้วครับสำหรับโปรเจกต์กำแพงกันดินสเปคเรือธงของเรา การลงทุนทำกำแพงกันดินพร้อมระบบท่อระบายน้ำมาตรฐานวิศวกรรมแบบนี้ คือการ <b data-path-to-node=\"26\" data-index-in-node=\"124\">\"เจ็บแต่จบ\"</b> ที่แท้จริงครับ เพราะคุณไม่ต้องมากังวลเรื่องกำแพงร้าว ดินสไลด์ หรือน้ำท่วมขังทำลายโครงสร้างในอีก 10-20 ปีข้างหน้า</p><p data-path-to-node=\"27\"><b data-path-to-node=\"27\" data-index-in-node=\"0\">แล้วที่ดินของคุณล่ะครับ กำลังเจอปัญหาแบบไหนอยู่?</b></p><ul data-path-to-node=\"28\"><li><p data-path-to-node=\"28,0,0\">เพิ่งซื้อที่ดินมาใหม่ ระดับดินต่ำกว่าถนน หรือต่างระดับกับเพื่อนบ้านเยอะไหม?</p></li><li><p data-path-to-node=\"28,1,0\">หน้าฝนทีไร น้ำขังในพื้นที่จนดินเละเทะ หรือเริ่มเห็นแนวดินสไลด์หรือเปล่า?</p></li><li><p data-path-to-node=\"28,2,0\">มีสเปคในใจ แต่ไม่แน่ใจว่างบประมาณจะบานปลายไหม?</p></li></ul><p data-path-to-node=\"29\">คอมเมนต์เล่าปัญหาที่ดินของคุณไว้ใต้โพสต์นี้ได้เลยครับ! หรือถ้าอยากได้คำปรึกษาแบบเจาะลึก ทัก Inbox หรือแอดไลน์มาคุยกับเรา \"ธีรพงษ์เซอร์วิส\" ได้เลย เรายินดีไปประเมินหน้างานและจัดสเปคที่ \"ใช่และคุ้มค่าที่สุด\" สำหรับพื้นที่กรุงเทพฯ และปริมณฑลของคุณให้ <b data-path-to-node=\"29\" data-index-in-node=\"229\">ฟรี! ไม่มีข้อผูกมัดครับ</b></p><p data-path-to-node=\"29\"><b data-path-to-node=\"29\" data-index-in-node=\"229\"><br></b></p><p segoe=\"\" ui\",=\"\" \"helvetica=\"\" neue\",=\"\" arial,=\"\" sans-serif;\"=\"\" style=\"color: rgb(76, 76, 76);\">📞 สนใจติดต่อสอบถามเพิ่มเติมได้ที่ 062-718-8846 หรือ Line ID : 0627188846</p><p data-path-to-node=\"29\"><b data-path-to-node=\"29\" data-index-in-node=\"229\"></b></p><div><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/lineid.webp\" style=\"width: 200.278px;\"></div>', 'images/blogs/blog1776744220.webp', 10, '2025-04-23-กำแพงกันดินยาว-73-อำเภอบางกรวย-จังหวัดนนทบุรี', '2026-04-20 21:03:40', '2026-04-20 21:03:40');
INSERT INTO `blogs` (`id`, `title`, `description`, `content`, `image`, `service_category_id`, `slug`, `created_at`, `updated_at`) VALUES
(43, 'รีวิวผลงานติดตั้งรั้วคอนกรีตสำเร็จรูป + รั้วลวดหนาม รอบบ้าน งบประมาณเท่าไหร่?', 'รวมขั้นตอนติดตั้งรั้วสำเร็จรูปและรั้วลวดหนาม พร้อมงบประมาณจริง ปัญหาหน้างาน และวิธีเลือกผู้รับเหมา อ่านจบตัดสินใจได้ทันที', '<h2 data-section-id=\"b79egd\" data-start=\"450\" data-end=\"481\">จุดเริ่มต้นของโปรเจกต์นี้</h2><p data-start=\"483\" data-end=\"565\">พื้นที่หน้างาน ต.โคกเริงรมย์ อ.บำเหน็จณรงค์ จ.ชัยภูมิ เจ้าของพื้นที่ต้องการ <strong data-start=\"505\" data-end=\"546\">ล้อมรั้วรอบบ้าน</strong> โดยมีโจทย์หลักคือ:</p><ul data-start=\"567\" data-end=\"697\">\r\n<li data-section-id=\"1oynfqi\" data-start=\"567\" data-end=\"604\">\r\nต้องการ <strong data-start=\"577\" data-end=\"604\">ความแข็งแรง + ประหยัดงบ</strong>\r\n</li>\r\n<li data-section-id=\"1dligd3\" data-start=\"605\" data-end=\"655\">\r\nอยากได้บางส่วนเป็น <strong data-start=\"626\" data-end=\"655\">รั้วทึบ เว้นช่องสำหรับติดตั้งระแนงภายหลัง (ความเป็นส่วนตัว+ความสวยงาม)</strong>\r\n</li>\r\n<li data-section-id=\"bn4sow\" data-start=\"656\" data-end=\"697\">\r\nและบางส่วนเป็น <strong data-start=\"673\" data-end=\"697\">รั้วสำเร็จรูป (ลดต้นทุน)</strong>\r\n</li>\r\n</ul><p data-start=\"699\" data-end=\"777\">👉 ทีมงานจึงแนะนำให้ใช้ “รั้วผสม” คือ<br data-start=\"736\" data-end=\"739\">\r\n<span data-start=\"739\" data-end=\"777\"><b>รั้วคอนกรีตสำเร็จรูป + รั้วทึบที่เว้นช่องไว้ติดตั้งระแนง</b><br>เพื่อให้ลูกค้าตัดสินใจ</span></p><hr data-start=\"779\" data-end=\"782\"><h2 data-section-id=\"a479m2\" data-start=\"784\" data-end=\"808\">📐 รายละเอียดโปรเจกต์</h2><div class=\"TyagGW_tableContainer\"><div tabindex=\"-1\" class=\"group TyagGW_tableWrapper flex flex-col-reverse w-fit\"><table data-start=\"810\" data-end=\"1043\" class=\"w-fit min-w-(--thread-content-width)\"><thead data-start=\"810\" data-end=\"829\"><tr data-start=\"810\" data-end=\"829\"><th data-start=\"810\" data-end=\"819\" data-col-size=\"sm\" class=\"\">รายการ</th><th data-start=\"819\" data-end=\"829\" data-col-size=\"sm\" class=\"\">ข้อมูล</th></tr></thead><tbody data-start=\"846\" data-end=\"1043\"><tr data-start=\"846\" data-end=\"901\"><td data-start=\"846\" data-end=\"858\" data-col-size=\"sm\">ประเภทงาน</td><td data-col-size=\"sm\" data-start=\"858\" data-end=\"901\">รับทำรั้วคอนกรีตสำเร็จรูป + รั้วทึบที่เว้นช่องไว้ติดตั้งระแนง</td></tr><tr data-start=\"902\" data-end=\"934\"><td data-start=\"902\" data-end=\"915\" data-col-size=\"sm\">พื้นที่รวม</td><td data-col-size=\"sm\" data-start=\"915\" data-end=\"934\">ประมาณ 95+ เมตร</td></tr><tr data-start=\"935\" data-end=\"965\"><td data-start=\"935\" data-end=\"954\" data-col-size=\"sm\">ระยะเวลาก่อสร้าง</td><td data-col-size=\"sm\" data-start=\"954\" data-end=\"965\">60 วัน</td></tr><tr data-start=\"966\" data-end=\"996\"><td data-start=\"966\" data-end=\"980\" data-col-size=\"sm\">งบประมาณรวม</td><td data-col-size=\"sm\" data-start=\"980\" data-end=\"996\">~3xx,xxx บาท</td></tr><tr data-start=\"997\" data-end=\"1043\"><td data-start=\"997\" data-end=\"1013\" data-col-size=\"sm\">ลักษณะพื้นที่</td><td data-col-size=\"sm\" data-start=\"1013\" data-end=\"1043\">ดินทั่วไป มีบางจุดไม่เรียบ</td></tr></tbody></table></div></div><hr data-start=\"1045\" data-end=\"1048\"><h2 data-section-id=\"shyd52\" data-start=\"1050\" data-end=\"1085\">🧱 ทำไมลูกค้าเลือก “รั้ว 2 แบบ”?</h2><h3 data-section-id=\"1n9l5ej\" data-start=\"1087\" data-end=\"1127\">✅ รั้วคอนกรีตสำเร็จรูป (สูง 1.25 ม.)</h3><p data-start=\"1128\" data-end=\"1137\">เหมาะกับ:</p><ul data-start=\"1138\" data-end=\"1214\">\r\n<li data-section-id=\"95f9d3\" data-start=\"1138\" data-end=\"1180\">\r\nด้านหน้าหรือจุดที่ต้องการความเป็นส่วนตัว</li>\r\n<li data-section-id=\"9q6948\" data-start=\"1181\" data-end=\"1214\">\r\nป้องกันสายตา + เพิ่มความปลอดภัย<br></li>\r\n</ul><h3 data-section-id=\"1q88fpf\" data-start=\"1216\" data-end=\"1244\">✅ รั้วก่อฉาบ (สูง 1 ม.)</h3><p data-start=\"1245\" data-end=\"1254\">เหมาะกับ:</p><ul data-start=\"1255\" data-end=\"1301\">\r\n<li data-section-id=\"zz0e0n\" data-start=\"1255\" data-end=\"1270\">\r\nด้านหน้า</li>\r\n<li data-section-id=\"1wv16xt\" data-start=\"1271\" data-end=\"1287\">\r\nลดต้นทุนได้มาก\r\n</li>\r\n<li data-section-id=\"1kdrwic\" data-start=\"1288\" data-end=\"1301\">รองรับติดตั้งระแนง เพื่อความสวยงาม</li>\r\n</ul><p data-start=\"1303\" data-end=\"1370\">👉 วิธีนี้ช่วย <strong data-start=\"1318\" data-end=\"1340\">ลดงบได้เป็นหลักแสน</strong> เมื่อเทียบกับทำรั้วทึบทั้งหมด</p><hr data-start=\"1372\" data-end=\"1375\"><h2 data-section-id=\"1yu6wz9\" data-start=\"1377\" data-end=\"1412\">⚙️ ขั้นตอนการทำงานจริง (หน้างาน)</h2><h3 data-section-id=\"5ms02i\" data-start=\"1414\" data-end=\"1440\">1. สำรวจพื้นที่หน้างาน</h3><ul data-start=\"1441\" data-end=\"1482\">\r\n<li data-section-id=\"14ymks3\" data-start=\"1441\" data-end=\"1454\">\r\nวัดระยะจริง\r\n</li>\r\n<li data-section-id=\"nmmgdw\" data-start=\"1455\" data-end=\"1469\">\r\nเช็คระดับดิน\r\n</li>\r\n<li data-section-id=\"ksxzvd\" data-start=\"1470\" data-end=\"1482\">\r\nวางแนวรั้ว\r\n</li>\r\n</ul><hr data-start=\"1484\" data-end=\"1487\"><h3 data-section-id=\"174owa5\" data-start=\"1489\" data-end=\"1516\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776831198_d0HoIjnRio.png\" style=\"width: 25%;\"><br></h3><h3 data-section-id=\"174owa5\" data-start=\"1489\" data-end=\"1516\">2. ออกแบบและประเมินราคา</h3><p data-start=\"1517\" data-end=\"1532\">ทีมงานเลือกใช้:</p><ul data-start=\"1533\" data-end=\"1578\">\r\n<li data-section-id=\"10oslf1\" data-start=\"1533\" data-end=\"1551\">ฟุตติ้งฐานแผ่</li>\r\n<li data-section-id=\"rqp3s2\" data-start=\"1552\" data-end=\"1578\">\r\nคานคอดินเพิ่มความแข็งแรง\r\n</li>\r\n</ul><hr data-start=\"1580\" data-end=\"1583\"><h3 data-section-id=\"7v2k2n\" data-start=\"1585\" data-end=\"1613\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776827196_pItYDQAb5r.webp\" style=\"width: 25%;\">  <img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776827195_AMjhpwpSZQ.webp\" style=\"width: 25%;\">  <br></h3><h3 data-section-id=\"7v2k2n\" data-start=\"1585\" data-end=\"1613\">3. งานฐานรากและโครงสร้าง</h3><p data-start=\"1615\" data-end=\"1634\"><strong data-start=\"1615\" data-end=\"1634\">รายละเอียดสำคัญ</strong></p><ul data-start=\"1635\" data-end=\"1742\">\r\n<li data-section-id=\"vy0mfj\" data-start=\"1635\" data-end=\"1668\">\r\nฐานราก: 0.60 × 0.60 × 0.25 ม.\r\n</li>\r\n<li data-section-id=\"15exnid\" data-start=\"1669\" data-end=\"1696\">\r\nระยะห่าง: ทุก 2.50 เมตร\r\n</li>\r\n<li data-section-id=\"1yurubn\" data-start=\"1697\" data-end=\"1717\">\r\nเหล็กเสริม: DB12\r\n</li>\r\n<li data-section-id=\"1k07y5z\" data-start=\"1718\" data-end=\"1742\">\r\nคานคอดิน: 0.20–0.40 ม.\r\n</li>\r\n</ul><p data-start=\"1744\" data-end=\"1792\">👉 จุดนี้สำคัญมาก เพราะเป็นตัวกำหนดอายุการใช้งาน</p><hr data-start=\"1794\" data-end=\"1797\"><h3 data-section-id=\"jc9plr\" data-start=\"1799\" data-end=\"1827\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776827493_rYF2xMvQEE.webp\" style=\"width: 25%;\">  <img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776827438_59SeFFXuK0.webp\" style=\"width: 25%;\">   <img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776827438_af7RiP0h1m.webp\" style=\"width: 25%;\"><br></h3><h3 data-section-id=\"jc9plr\" data-start=\"1799\" data-end=\"1827\">4. ติดตั้งเสาและแผ่นรั้ว</h3><ul data-start=\"1828\" data-end=\"1898\">\r\n<li data-section-id=\"3ad8dy\" data-start=\"1828\" data-end=\"1851\">\r\nเสาคอนกรีตสำเร็จรูป\r\n</li>\r\n<li data-section-id=\"1z0nhgs\" data-start=\"1852\" data-end=\"1879\">\r\nใส่แผ่นรั้ว 4 แผ่น/ช่วง\r\n</li>\r\n<li data-section-id=\"1d7hbmq\" data-start=\"1880\" data-end=\"1898\">\r\nปิดทับหลังด้านบน\r\n</li>\r\n</ul><hr data-start=\"1900\" data-end=\"1903\"><h3 data-section-id=\"1kyjoyi\" data-start=\"1905\" data-end=\"1926\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776827587_r71swWCknp.webp?width=400&format=webp\" style=\"width: 25%;\">  <img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776827587_5adivPqxPP.webp\" style=\"width: 25%;\">  <img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776827587_T3qG5Gb1vu.webp\" style=\"width: 25%;\"><br></h3><h3 data-section-id=\"1kyjoyi\" data-start=\"1905\" data-end=\"1926\">5. งานรั้วก่อฉาบ</h3><ul data-start=\"1927\" data-end=\"1982\">\r\n<li data-section-id=\"9z5vgq\" data-start=\"1927\" data-end=\"1946\">\r\nติดตั้งเสา คสล.\r\n</li>\r\n<li data-section-id=\"1ld32vc\" data-start=\"1947\" data-end=\"1968\">\r\nก่อฉาบโชว์บัว 2 ด้าน</li>\r\n<li data-section-id=\"1of5041\" data-start=\"1969\" data-end=\"1982\">\r\nเทคานรองรับ\r\n</li>\r\n</ul><hr data-start=\"1984\" data-end=\"1987\"><h3 data-section-id=\"1wl3fr2\" data-start=\"1989\" data-end=\"2015\">6. ติดตั้งประตูทางเข้า</h3><ul data-start=\"2016\" data-end=\"2098\">\r\n<li data-section-id=\"21m7ek\" data-start=\"2016\" data-end=\"2051\">\r\nเสาประตูขนาดใหญ่ 0.40 × 0.40 ม.\r\n</li>\r\n<li data-section-id=\"1ifn8ld\" data-start=\"2052\" data-end=\"2076\">\r\nบานประตูกว้าง 1 เมตร\r\n</li>\r\n<li data-section-id=\"1czzg25\" data-start=\"2077\" data-end=\"2098\">\r\nรองรับการใช้งานจริง\r\n</li>\r\n</ul><hr data-start=\"2100\" data-end=\"2103\"><h3 data-section-id=\"12v6nxy\" data-start=\"2105\" data-end=\"2136\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776827589_WZTxr9I1UO.webp\" style=\"width: 25%;\">  <img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1776827588_xstfE321kg.webp\" style=\"width: 25%;\"><br></h3><p><br></p><h3 data-section-id=\"12v6nxy\" data-start=\"2105\" data-end=\"2136\">7. งานเก็บรายละเอียด + ทาสี</h3><ul data-start=\"2137\" data-end=\"2185\">\r\n<li data-section-id=\"yvjvad\" data-start=\"2137\" data-end=\"2157\">\r\nทาสีรวม 68+ เมตร\r\n</li>\r\n<li data-section-id=\"1u0g3hg\" data-start=\"2158\" data-end=\"2185\">\r\nเพิ่มความสวยงาม + กันสนิม\r\n</li>\r\n</ul><hr data-start=\"2187\" data-end=\"2190\"><h2 data-section-id=\"o2q8ho\" data-start=\"2192\" data-end=\"2229\">⚠️ ปัญหาหน้างานที่เจอ (และวิธีแก้)</h2><h3 data-section-id=\"srhohh\" data-start=\"2231\" data-end=\"2265\">❌ ปัญหา: พื้นที่บางจุดไม่เรียบ</h3><p data-start=\"2266\" data-end=\"2276\">✔ วิธีแก้:</p><ul data-start=\"2277\" data-end=\"2324\">\r\n<li data-section-id=\"1lsytt2\" data-start=\"2277\" data-end=\"2297\">\r\nปรับระดับก่อนเทฐาน\r\n</li>\r\n<li data-section-id=\"7yo43t\" data-start=\"2298\" data-end=\"2324\">\r\nเพิ่มความลึกฐานรากบางจุด\r\n</li>\r\n</ul><hr data-start=\"2326\" data-end=\"2329\"><h3 data-section-id=\"tzdvrl\" data-start=\"2331\" data-end=\"2357\">❌ ปัญหา: แนวรั้วไม่ตรง</h3><p data-start=\"2358\" data-end=\"2368\">✔ วิธีแก้:</p><ul data-start=\"2369\" data-end=\"2402\">\r\n<li data-section-id=\"c6hd29\" data-start=\"2369\" data-end=\"2384\">\r\nใช้เอ็นดึงแนว\r\n</li>\r\n<li data-section-id=\"1umfp1o\" data-start=\"2385\" data-end=\"2402\">\r\nเช็คระยะทุกช่วง\r\n</li>\r\n</ul><hr data-start=\"2404\" data-end=\"2407\"><p data-start=\"2409\" data-end=\"2457\">👉 ประสบการณ์หน้างานจริงช่วยลดปัญหาระยะยาวได้มาก</p><hr data-start=\"2459\" data-end=\"2462\"><h2 data-section-id=\"9gq2s7\" data-start=\"2464\" data-end=\"2482\">💰 สรุปงบประมาณ</h2><div class=\"TyagGW_tableContainer\"><div tabindex=\"-1\" class=\"group TyagGW_tableWrapper flex flex-col-reverse w-fit\"><table data-start=\"2484\" data-end=\"2728\" class=\"w-fit min-w-(--thread-content-width)\"><thead data-start=\"2484\" data-end=\"2501\"><tr data-start=\"2484\" data-end=\"2501\"><th data-start=\"2484\" data-end=\"2493\" data-col-size=\"sm\" class=\"\">รายการ</th><th data-start=\"2493\" data-end=\"2501\" data-col-size=\"sm\" class=\"\">ราคา</th></tr></thead><tbody data-start=\"2518\" data-end=\"2728\"><tr data-start=\"2518\" data-end=\"2556\"><td data-start=\"2518\" data-end=\"2541\" data-col-size=\"sm\">รั้วคอนกรีตสำเร็จรูป</td><td data-col-size=\"sm\" data-start=\"2541\" data-end=\"2556\">1xx,xxx บาท</td></tr><tr data-start=\"2557\" data-end=\"2585\"><td data-start=\"2557\" data-end=\"2571\" data-col-size=\"sm\">รั้วลวดหนาม</td><td data-col-size=\"sm\" data-start=\"2571\" data-end=\"2585\">8x,xxx บาท</td></tr><tr data-start=\"2586\" data-end=\"2611\"><td data-start=\"2586\" data-end=\"2597\" data-col-size=\"sm\">ฐานประตู</td><td data-col-size=\"sm\" data-start=\"2597\" data-end=\"2611\">1x,xxx บาท</td></tr><tr data-start=\"2612\" data-end=\"2637\"><td data-start=\"2612\" data-end=\"2623\" data-col-size=\"sm\">บานประตู</td><td data-col-size=\"sm\" data-start=\"2623\" data-end=\"2637\">1x,xxx บาท</td></tr><tr data-start=\"2638\" data-end=\"2662\"><td data-start=\"2638\" data-end=\"2648\" data-col-size=\"sm\">งานทาสี</td><td data-col-size=\"sm\" data-start=\"2648\" data-end=\"2662\">3x,xxx บาท</td></tr><tr data-start=\"2663\" data-end=\"2689\"><td data-start=\"2663\" data-end=\"2674\" data-col-size=\"sm\">งานเพิ่ม</td><td data-col-size=\"sm\" data-start=\"2674\" data-end=\"2689\">~7x,xxx บาท</td></tr><tr data-start=\"2690\" data-end=\"2728\"><td data-start=\"2690\" data-end=\"2707\" data-col-size=\"sm\"><strong data-start=\"2692\" data-end=\"2706\">รวมทั้งหมด</strong></td><td data-col-size=\"sm\" data-start=\"2707\" data-end=\"2728\"><strong data-start=\"2709\" data-end=\"2726\">≈ 3x<span style=\"font-weight: 300;\">x,xxx</span><strong data-start=\"2709\" data-end=\"2726\" style=\"background-color: transparent;\"> บาท</strong><br></strong></td></tr></tbody></table></div></div><hr data-start=\"2730\" data-end=\"2733\"><h2 data-section-id=\"1br9hqb\" data-start=\"2735\" data-end=\"2769\">📊 สรุป: รั้วแบบนี้เหมาะกับใคร?</h2><p data-start=\"2771\" data-end=\"2786\">เหมาะมากสำหรับ:</p><ul data-start=\"2787\" data-end=\"2865\">\r\n<li data-section-id=\"ghq610\" data-start=\"2787\" data-end=\"2807\">เจ้าของบ้านที่กำลังมองหาช่างรับเหมาก่อสร้างรั้ว</li>\r\n<li data-section-id=\"rczvqn\" data-start=\"2825\" data-end=\"2865\">\r\nคนที่ต้องการ “ประหยัดงบ แต่ยังแข็งแรง”\r\n</li>\r\n</ul><hr data-start=\"2867\" data-end=\"2870\"><h2 data-section-id=\"l2nls\" data-start=\"2872\" data-end=\"2897\">❓ คำถามที่พบบ่อย (FAQ)</h2><h3 data-section-id=\"kxkpdm\" data-start=\"2899\" data-end=\"2925\">Q: รั้วสำเร็จรูปทนไหม?</h3><p data-start=\"2926\" data-end=\"2965\">A: ถ้าทำฐานรากถูกต้อง อยู่ได้ 10–20 ปี+</p><hr data-start=\"2967\" data-end=\"2970\"><h3 data-section-id=\"14wxu4f\" data-start=\"2972\" data-end=\"3001\">Q: ทำรั้วแบบไหนถูกที่สุด?</h3><p data-start=\"3002\" data-end=\"3045\">A: รั้วเมทัลชีท แต่ความแข็งแรง และความสวยงามน้อย</p><h3 data-section-id=\"rram4a\" data-start=\"3052\" data-end=\"3075\">Q: ใช้เวลาทำนานไหม?</h3><p data-start=\"3076\" data-end=\"3103\">A: งานขนาดนี้ประมาณ 60 วัน</p><hr data-start=\"3105\" data-end=\"3108\"><h3 data-section-id=\"msl9am\" data-start=\"3110\" data-end=\"3144\">Q: ราคา 3,500 บาท/เมตร แพงไหม?</h3><p data-start=\"3145\" data-end=\"3189\">A: ถือว่า “ราคากลาง” สำหรับงานมีฐานราก + คาน</p><hr data-start=\"3191\" data-end=\"3194\"><h2 data-section-id=\"e03dwg\" data-start=\"3196\" data-end=\"3227\">📞 สนใจติดตั้งรั้ว ปรึกษาฟรี</h2><p data-start=\"3229\" data-end=\"3321\">หากคุณกำลังมองหา<br data-start=\"3245\" data-end=\"3248\">\r\n✅ รับทำรั้วคอนกรีตสำเร็จรูป<br data-start=\"3275\" data-end=\"3278\">\r\n✅ รับทำรั้วลวดหนาม<br data-start=\"3296\" data-end=\"3299\">\r\n✅ ประเมินหน้างานจริง<br><a href=\"https://www.theeraphong.com/fence\" target=\"_blank\">ตรวจสอบราคาแบบรั้ว และรายละเอียดแบบอื่น ๆ ที่นี่</a></p><p data-start=\"3323\" data-end=\"3371\">👉 ติดต่อทีมงานเพื่อ <strong data-start=\"3344\" data-end=\"3362\">ประเมินราคาฟรี</strong> ได้เลย</p><ul data-start=\"3373\" data-end=\"3430\">\r\n<li data-section-id=\"k36tee\" data-start=\"3373\" data-end=\"3393\">\r\nมีทีมงานมืออาชีพ\r\n</li>\r\n<li data-section-id=\"rcw77l\" data-start=\"3394\" data-end=\"3410\">\r\nทำงานตรงเวลา\r\n</li>\r\n<li data-section-id=\"xx82ua\" data-start=\"3411\" data-end=\"3430\">\r\nรับประกันคุณภาพ\r\n</li>\r\n</ul><hr data-start=\"3432\" data-end=\"3435\"><h2 data-section-id=\"68kp9k\" data-start=\"3437\" data-end=\"3447\"> สรุป</h2><p data-start=\"3449\" data-end=\"3518\">โปรเจกต์นี้เป็นตัวอย่างที่ดีของการ<br data-start=\"3483\" data-end=\"3486\">\r\n👉 “เลือกใช้รั้วให้เหมาะกับงบ”</p><p data-start=\"3520\" data-end=\"3535\">การผสมระหว่าง</p><ul data-start=\"3536\" data-end=\"3585\">\r\n<li data-section-id=\"2k32ru\" data-start=\"3536\" data-end=\"3561\">\r\nรั้วทึบ (ความปลอดภัย)\r\n</li>\r\n<li data-section-id=\"4gxw6c\" data-start=\"3562\" data-end=\"3585\">\r\nรั้วโปร่ง (ประหยัด)\r\n</li>\r\n</ul><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p data-start=\"3587\" data-end=\"3622\">ช่วยให้ได้ทั้ง <strong data-start=\"3602\" data-end=\"3622\">คุณภาพ + คุ้มค่า</strong></p>', 'images/blogs/blog1776831684.webp', 28, '2025-02-02-รั้ว-ตำบลโคกเริงรมย์', '2026-04-21 21:21:24', '2026-04-21 21:29:49');
INSERT INTO `blogs` (`id`, `title`, `description`, `content`, `image`, `service_category_id`, `slug`, `created_at`, `updated_at`) VALUES
(44, 'สรุปผลงานก่อสร้าง กำแพงกันดินสูง 1.70 เมตร พร้อมข้อมูล กําแพงกันดิน ราคา อัปเดตล่าสุด', 'พาชมผลงานจริง! ขั้นตอนสร้างกำแพงกันดินสูง 1.70 เมตร จ.ชัยภูมิ ป้องกันดินสไลด์ พร้อมตั้งเสารอทำรั้ว เจาะลึกปัญหาหน้างานและอัปเดต กําแพงกันดิน ราคา โดยผู้รับเหมาตัวจริง', '<h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 28px;\">สรุปผลงานการก่อสร้างกำแพงกันดินสูง 1.70 เมตร (เจาะลึกขั้นตอน + กําแพงกันดิน ราคา อัปเดตล่าสุด)</span></h1><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"5\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">สวัสดีครับทุกท่าน! สำหรับใครที่มีที่ดินเปล่า กำลังมีแพลนจะถมดินเพื่อสร้างบ้านหรือสร้างโรงงาน สิ่งหนึ่งที่คุณ \"ห้ามมองข้ามเด็ดขาด\" คือเรื่องของการทำ&nbsp;<a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\">กำแพงกันดิน</a>&nbsp;ครับ เพราะถ้าถมดินสูงๆ แล้วไม่มีตัวกั้น อนาคตดินไหล ดินสไลด์ไปทับที่ข้างเคียง หรือทำให้โครงสร้างบ้านทรุด จะกลายเป็นฝันร้ายที่แก้ยากและเสียเงินบานปลายแน่นอน</p><p data-path-to-node=\"6\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">จากประสบการณ์การทำงานหน้างานก่อสร้างกำแพงกันดินและเขื่อนกันดินมากว่า 10 ปี วันนี้ผมจะขอหยิบยกเอาโปรเจกต์ล่าสุดมาเล่าให้ฟังแบบเจาะลึกทุกขั้นตอน เพื่อให้ทุกคนเห็นภาพการทำงานจริง พร้อมทั้งตอบคำถามยอดฮิตอย่าง <b data-path-to-node=\"6\" data-index-in-node=\"205\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">กําแพงกันดิน ราคา</b> เท่าไหร่? เพื่อให้คุณนำไปเป็นข้อมูลในการตัดสินใจครับ</p><hr data-path-to-node=\"7\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"></h1><h2 data-path-to-node=\"8\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 28px;\">ข้อมูลโปรเจกต์ (Project Overview)</span></h2><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><ul data-path-to-node=\"9\" style=\"padding-inline-start: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"9,0,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"9,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">สถานที่ก่อสร้าง:</b> ตำบลท่าใหญ่ อำเภอหนองบัวแดง จังหวัดชัยภูมิ</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"9,1,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"9,1,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">รายละเอียดงาน:</b> ก่อสร้างกำแพงกันดิน ความยาวรวม 56 เมตร</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"9,2,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"9,2,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ความสูง:</b> 1.70 เมตร (นับจากฐานราก)</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"9,3,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"9,3,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">งานโครงสร้างต่อเนื่อง:</b> มีการเตรียมโครงสร้างเพื่อรองรับการทำ \"รั้วก่อฉาบ\" ใน Phase ถัดไป</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"9,4,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"9,4,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">งบประมาณรวม:</b> 4xx,xxxx บาท</p></li></ul><hr data-path-to-node=\"10\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"></h1><h2 data-path-to-node=\"11\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 28px;\">ความต้องการของลูกค้า (Client\'s Pain Points &amp; Needs)</span></h2><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"12\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">โจทย์ของงานนี้เริ่มจาก เจ้าของที่ดินต้องการทำรั้วรอบที่ดินเปล่าเพื่อเตรียมสร้างบ้านในอนาคต แต่เนื่องจากระดับที่ดินเดิมต่ำกว่าถนนมาก จึงต้องมีการถมดินสูงขึ้นมาเกือบ 2 เมตร ทำให้ \"ต้องทำกำแพงกันดินก่อน\" เพื่อป้องกันดินสไลด์</p><p data-path-to-node=\"13\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">ลูกค้ามีความกังวลใจและแชร์ให้ผมฟังตรงๆ ว่า:</p><ul data-path-to-node=\"14\" style=\"padding-inline-start: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"14,0,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"14,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">เคยมีประสบการณ์ไม่ดีกับช่าง:</b> อยากได้ผู้รับเหมาที่ไว้ใจได้ ซื่อสัตย์ ไม่ทิ้งงานกลางทาง</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"14,1,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"14,1,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ต้องการงานคุณภาพ:</b> โครงสร้างต้องแข็งแรงจริง เพราะดินที่ถมใหม่มีแรงดันสูงมาก ถ้าร้าวหรือล้มมาจะเรื่องใหญ่</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"14,2,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"14,2,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">วางแผนเผื่ออนาคต:</b> อยากให้ทำฐานรากและเสารอไว้เลย สำหรับงานรั้วทึบในอนาคต จะได้ไม่ต้องมาทุบหรือรื้อทำใหม่ให้เปลืองเงิน</p></li></ul><hr data-path-to-node=\"15\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"></h1><h2 data-path-to-node=\"16\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 28px;\">วิธีแก้ปัญหาและแนวทางการออกแบบของทีมงาน</span></h2><h1 data-path-to-node=\"4\" style=\"line-height: 1.15 !important;\"><p data-path-to-node=\"17\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">ในฐานะคนทำงานหน้างาน เมื่อเจอโจทย์กำแพงที่สูงถึง 1.70 เมตร เราจะใช้โครงสร้างแบบทั่วไปไม่ได้ครับ แรงดันดินด้านข้าง (Lateral Earth Pressure) จะมหาศาลมาก</p><p data-path-to-node=\"18\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"18\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">แนวทางของเราคือ:</b></p><p data-path-to-node=\"18\" style=\"line-height: 1.15 !important;\"><font face=\"Google Sans Text, sans-serif\"><b>1. ใช้ระบบกำแพงกันดินแบบมีสเตย์รั้ง: </b>เพื่อถ่ายน้ำหนักและยึดรั้งไม่ให้กำแพงเอนหรือล้ม</font></p><p data-path-to-node=\"18\" style=\"line-height: 1.15 !important;\"><font face=\"Google Sans Text, sans-serif\"><b><span data-path-to-node=\"18\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\"></span></b></font></p><p data-path-to-node=\"18\" style=\"line-height: 1.15 !important;\"><font face=\"Google Sans Text, sans-serif\"><b>2. ออกแบบโครงสร้างแบบ 2 in 1: </b>ในเมื่อลูกค้าจะทำรั้วต่อใน Phase ถัดไป เราจึงออกแบบให้มีการ \"ฝากเสา i15\" (เสาเข็มรูปตัวไอขนาด 15 ซม.) ซึ่งเป็นเสาสำหรับทำรั้วสำเร็จรูป เสียบตั้งรอไว้ในคานคอดิน (สเตย์) ของกำแพงกันดินเลย วิธีนี้จะทำให้รั้วในอนาคตแข็งแรงเป็นเนื้อเดียวกันกับกำแพงกันดิน และประหยัดงบลูกค้าในระยะยาวครับ</font></p><hr data-path-to-node=\"20\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"></h1><h2 data-path-to-node=\"21\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 28px;\">ขั้นตอนการทำงานจริง (แบ่งการทำงานเป็น 6 งวดงาน)</span></h2><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"22\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">เพื่อให้ลูกค้าเห็นภาพการทำงานและงบประมาณที่โปร่งใส ทีมงานของเราบริหารจัดการหน้างานโดยแบ่งเป็นงวดงานที่ชัดเจน ดังนี้ครับ:</p></h1><h3 data-path-to-node=\"23\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 24px;\">งวดที่ 1: เซ็นสัญญา สั่งผลิตเสาเข็ม และดำเนินการส่วนแรก</span></h3><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"24\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">เริ่มต้นด้วยการลงพื้นที่สำรวจหน้างานอย่างละเอียด เช็กแนวเขตโฉนดให้เป๊ะ จากนั้นร่วมกันตรวจสอบสเปควัสดุและเซ็นสัญญาก่อสร้าง เมื่อเอกสารเรียบร้อย ทีมงานจะเริ่มนำเครื่องจักร (รถแม็คโคร) เข้าเคลียร์พื้นที่ (Clearing) ปรับระดับ และทำการสั่งผลิตเสาเข็ม แผ่นพื้นรับแรง และเสา i15 จากโรงงานที่ได้มาตรฐาน มอก. เตรียมพร้อมสำหรับงานโครงสร้าง</p><p data-path-to-node=\"24\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777003081_bpRVdDWrkJ.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777003081_9HjaRFsvsT.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777003080_wJ6hZgcuEg.webp\" style=\"width: 25%;\"><br></p></h1><h3 data-path-to-node=\"25\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><br></h3><h3 data-path-to-node=\"25\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\">งวดที่ 2: ติดตั้งเสาเข็ม</h3><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"26\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">เมื่อวัสดุมาถึงหน้างาน เราเริ่มทำการตอกเสาเข็มสำหรับฐานรากกำแพงกันดินและเสาเข็มสำหรับสเตย์รั้ง (Stay) ขั้นตอนนี้ต้องใช้ความแม่นยำสูง ระยะห่างของเข็มแต่ละต้นต้องเป๊ะตามแบบที่วิศวกรคำนวณไว้ เพื่อให้สามารถรับแรงดันดินสูง 1.70 เมตรได้อย่างปลอดภัย ไม่เกิดการทรุดตัวหรือเอนเอียงในอนาคต</p><p data-path-to-node=\"26\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777003594_zacbo9zVxw.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777003594_MUh1FRyDeC.webp\" style=\"width: 25%;\"><br></p><p data-path-to-node=\"26\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><br></p></h1><h3 data-path-to-node=\"27\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\">งวดที่ 3: ติดตั้งแผ่นพื้นรับแรง</h3><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"28\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">หลังจากจัดการระบบเสาเข็มและฐานรากเรียบร้อย เราจะเริ่มติดตั้ง \"แผ่นพื้นคอนกรีตอัดแรง\" (Plank) ลงไปตามแนวเสาเข็ม แผ่นพื้นนี้จะทำหน้าที่เป็นผนังรับแรงดันดินโดยตรง การเลือกใช้แผ่นพื้นสำเร็จรูปช่วยให้งานก่อสร้างรวดเร็วขึ้น แข็งแรงทนทาน และควบคุมคุณภาพได้ดีกว่าการก่ออิฐบล็อกธรรมดาหลายเท่าครับ</p><p data-path-to-node=\"28\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777005424_8s5VgefAid.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777005424_cHpuhETjAr.webp\" style=\"width: 25%;\">&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777005424_WqNMvpI0NV.webp\" style=\"width: 25%;\"><br></p><p data-path-to-node=\"28\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><br></p></h1><h3 data-path-to-node=\"29\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\">งวดที่ 4: ประกอบไม้แบบ และติดตั้งเหล็กเสริม (พร้อมตั้งเสารอ)</h3><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"30\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">ขั้นตอนนี้เป็นจุดปราบเซียนและสำคัญมาก! ช่างจะทำการผูกเหล็กข้ออ้อยเพื่อทำคานทับหลังและคานสเตย์รั้งกำแพง พร้อมกับการประกอบไม้แบบ ไฮไลต์อยู่ที่การ <b data-path-to-node=\"30\" data-index-in-node=\"144\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\"ตั้งเสา i15 รอรัว\"</b> เราต้องนำเสา i15 เสียบเข้ากับโครงสร้างคาน จับดิ่งให้ตั้งฉากและวัดระยะห่างให้แม่นยำระดับมิลลิเมตร เพื่อให้ช่างทำรั้วใน Phase ถัดไปสามารถนำแผ่นรั้วมาเสียบลงร่องได้พอดีโดยไม่ต้องทุบแก้</p><p data-path-to-node=\"30\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777005503_LPrA5pX0dX.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777005503_ZjWSFZeDLS.webp\" style=\"width: 25%;\"><br></p><p data-path-to-node=\"30\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><br></p></h1><h3 data-path-to-node=\"31\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\">งวดที่ 5: เทคอนกรีตคาน และสเตย์</h3><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"32\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">เมื่อตรวจสอบความแข็งแรงของเหล็กเสริมและแนวดิ่งของเสา i15 เรียบร้อยแล้ว เราสั่งคอนกรีตผสมเสร็จ (Ready Mix) มาเทหล่อคานทับหลังและสเตย์ ระหว่างเทต้องใช้เครื่องจี้ปูน (Vibrator) เพื่อไล่ฟองอากาศ ให้คอนกรีตอัดแน่นเต็มร่องไม้แบบ ไม่มีโพรง ป้องกันน้ำซึมเข้าเหล็กเสริมซึ่งเป็นสาเหตุของการเกิดสนิม</p><p data-path-to-node=\"32\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777006057_GEPXppbyyv.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777006109_J15aLJkfgm.webp\" style=\"width: 25%;\"><br></p><p data-path-to-node=\"32\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><br></p></h1><h3 data-path-to-node=\"33\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\">งวดที่ 6: แกะไม้แบบ บ่มคอนกรีต และส่งมอบงาน</h3><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"34\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">เมื่อคอนกรีตเซ็ตตัวและได้อายุ เราจะทำการแกะไม้แบบออก ตรวจสอบความเรียบร้อยของผิวคอนกรีต และทำการบ่มคอนกรีตเพื่อให้โครงสร้างได้กำลังอัดสูงสุด จากนั้นทีมงานจะเคลียร์ขยะ เก็บกวาดหน้างานให้สะอาด และเดินตรวจงานร่วมกับลูกค้าก่อนทำการส่งมอบงานอย่างเป็นทางการ</p><p data-path-to-node=\"34\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><br></p><hr data-path-to-node=\"35\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"></h1><h2 data-path-to-node=\"36\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 28px;\">อุปสรรคหน้างาน + วิธีแก้ปัญหา (Challenges &amp; Solutions)</span></h2><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"37\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">ทำงานก่อสร้าง ไม่มีคำว่าราบรื่น 100% ครับ งานนี้เราเจออุปสรรคสำคัญคือ:</p><ul data-path-to-node=\"38\" style=\"padding-inline-start: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"38,0,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"38,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ปัญหา:</b> ช่วงงวดที่ 2 (ตอกเข็มและขุดร่อง) มีฝนตกลงมาอย่างหนัก ทำให้ดินสไลด์ลงมาในหลุม และหน้างานเละมาก รถปูนเข้าทำงานลำบาก</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"38,1,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"38,1,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">วิธีแก้:</b> เราต้องใช้รถแม็คโครจกดินที่สไลด์ออกทั้งหมด ตีผังไม้กั้นดินชั่วคราว และลงหินคลุกบดอัดทางเข้าหน้างานเพื่อให้รถปูนสามารถถอยเข้าฉีดปูนในงวดที่ 5 ได้ตรงจุด โดยไม่ต้องผสมปูนเองให้เสียกำลังอัด แม้จะเสียเวลาและต้นทุนเพิ่มขึ้น แต่เพื่อให้งานออกมาดี ทีมเราพร้อมลุยแก้ปัญหาให้จบครับ</p></li></ul><hr data-path-to-node=\"39\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"></h1><h2 data-path-to-node=\"40\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 28px;\">ผลลัพธ์หลังติดตั้ง (Before / After)</span></h2><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><blockquote data-path-to-node=\"41\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"41,0\" style=\"line-height: 1.15 !important;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777012045_Vl0250lJkq.webp\" style=\"width: 25%;\"><br></p><p data-path-to-node=\"41,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"41,0\" data-index-in-node=\"103\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Before:</b> สภาพที่ดินเดิมที่เสี่ยงต่อการที่ดินจะไหลลงร่องน้ำด้านข้าง หากก่อสร้างบ้านจะเกิดปัญหาในอนาคตแน่นอน</p></blockquote><p><br></p><blockquote data-path-to-node=\"41\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"41,0\" style=\"line-height: 1.15 !important;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777005424_cHpuhETjAr.webp\" style=\"color: inherit; width: 25%;\"></p></blockquote><blockquote data-path-to-node=\"42\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"42,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"42,0\" data-index-in-node=\"130\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">After:</b> กำแพงกันดินโครงสร้างแข็งแรงทนทานสูง 1.70 เมตร แนวดิ่งตรงเป๊ะ พร้อมเสา i15 ที่ตั้งรอไว้อย่างเป็นระเบียบ เตรียมพร้อมสำหรับการก่อสร้างรั้วก่อฉาบในสเต็ปต่อไป ดินที่จะถมใหม่ถูกกั้นไว้อย่างแน่นหนา</p></blockquote><hr data-path-to-node=\"43\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"></h1><h2 data-path-to-node=\"44\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 28px;\">สรุปงบประมาณ (Budget Summary</span>)</h2><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"45\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">สำหรับโปรเจกต์นี้ งบประมาณรวมอยู่ที่ <b data-path-to-node=\"45\" data-index-in-node=\"37\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">4xx,xxxx บาท</b> (เฉลี่ยแล้วคุ้มค่ามากเมื่อเทียบกับความแข็งแรงและโครงสร้างรั้วที่ได้เผื่อไว้แล้ว) ซึ่งหากใครที่กำลังเปรียบเทียบราคา ผมขอสรุปเรทราคาตลาดคร่าวๆ ไว้ให้ดูเป็นไอเดียครับ:</p><table data-path-to-node=\"46\" style=\"margin-bottom: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><thead style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><tr style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important; margin-bottom: 0px !important;\"><span style=\"font-size: 20px;\">รายการ / สเปคความสูง</span></strong></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important; margin-bottom: 0px !important;\"><span style=\"font-size: 20px;\">รูปแบบงาน</span></strong></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important; margin-bottom: 0px !important;\"><span style=\"font-size: 20px;\">การประเมินราคาเบื้องต้น</span></strong></td></tr></thead><tbody style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><tr style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"46,1,0,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important; font-size: 14px;\"><b data-path-to-node=\"46,1,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">กำแพงกันดิน สูง 1 เมตร ราคา</b></span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"46,1,1,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important; font-size: 14px;\">เหมาะสำหรับถมดินไม่สูงมาก</span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"46,1,2,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important; font-size: 14px;\">ราคาถูกที่สุด โครงสร้างไม่ซับซ้อนมาก</span></td></tr><tr style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"46,2,0,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important; font-size: 14px;\"><b data-path-to-node=\"46,2,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">กำแพงกันดิน สูง 1.5 เมตร ราคา</b></span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"46,2,1,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important; font-size: 14px;\">มาตรฐานทั่วไปสำหรับสร้างบ้าน</span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"46,2,2,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important; font-size: 14px;\">ราคาระดับกลาง ต้องเริ่มเน้นฐานรากและสเตย์ยึด</span></td></tr><tr style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"46,3,0,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important; font-size: 14px;\"><b data-path-to-node=\"46,3,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">กำแพงกันดิน สูง 1.70 เมตร (โปรเจกต์นี้)</b></span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"46,3,1,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important; font-size: 14px;\">สูงพิเศษ + ฝากเสา i15 ทำรั้ว</span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"46,3,2,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important; font-size: 14px;\"><b data-path-to-node=\"46,3,2,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">งานนี้ตกอยู่ที่ 4xx,xxxx บาท (ความยาว 56 ม.)</b></span></td></tr><tr style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"46,4,0,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important; font-size: 14px;\"><b data-path-to-node=\"46,4,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">กำแพงกันดิน สูง 2 เมตร ราคา</b></span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"46,4,1,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important; font-size: 14px;\">สำหรับถมที่สูงมาก / ใกล้แหล่งน้ำ</span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"46,4,2,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important; font-size: 14px;\">ราคาสูงที่สุด ต้องใช้วิศวกรออกแบบโครงสร้างพิเศษ</span></td></tr></tbody></table><p data-path-to-node=\"47\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><i data-path-to-node=\"47\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">(หมายเหตุ: <b data-path-to-node=\"47\" data-index-in-node=\"11\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">กำแพงกันดิน ราคา ต่อ เมตร</b> จะแปรผันตามสภาพดิน พื้นที่หน้างาน และสเปควัสดุ แนะนำให้ประเมินหน้างานจริงจะแม่นยำที่สุดครับ)</i></p><hr data-path-to-node=\"48\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"></h1><h2 data-path-to-node=\"49\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\">⭐ รีวิวและความพึงพอใจจากลูกค้า</h2><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"50\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><i data-path-to-node=\"50\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\"ตอนแรกกังวลมากว่าจะโดนทิ้งงานไหม เพราะเห็นข่าวเยอะ แต่พอได้เห็นทีมช่างวางแผนการทำงานเป็นงวดๆ ชัดเจนก็รู้สึกอุ่นใจ ช่างอธิบายละเอียดว่าแต่ละงวดต้องทำอะไร การเตรียมเสา i15 ไว้ให้เลยคือตอบโจทย์มาก ช่วยประหยัดเงินทำรั้วไปได้เยอะ หน้างานช่างก็ทำงานเป็นระเบียบ มีปัญหาฝนตกช่างก็ลุยแก้ให้ งานออกมาแข็งแรงสวยงามตามแบบเป๊ะๆ รอเรียกใช้บริการทำรั้วก่อฉาบต่อแน่นอน\"</i> – <b data-path-to-node=\"50\" data-index-in-node=\"365\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">คุณนิภาพร เจ้าของที่ดิน จ.ชัยภูมิ</b></p><hr data-path-to-node=\"51\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"></h1><h2 data-path-to-node=\"52\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 28px;\">FAQ คำถามที่พบบ่อยเกี่ยวกับกำแพงกันดิน</span></h2><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"53\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"53\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">1. จำเป็นต้องตอกเสาเข็มไหม ถ้าทำกำแพงกันดินแค่ 1 เมตร?</b></p><p data-path-to-node=\"53\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"53\" data-index-in-node=\"55\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ตอบ:</b> ขึ้นอยู่กับสภาพดินครับ ถ้าดินเดิมแข็งมากและถมดินไม่สูง อาจใช้ระบบฐานแผ่ได้ แต่ถ้าเป็นดินอ่อน การตอกเสาเข็มจะช่วยป้องกันการเลื่อนไถลและทรุดตัวได้ชัวร์กว่าครับ</p><p data-path-to-node=\"54\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"54\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">2. กำแพงกันดิน สูง 1.5 เมตร ราคา ต่างกับ 2 เมตร เยอะไหม?</b></p><p data-path-to-node=\"54\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"54\" data-index-in-node=\"57\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ตอบ:</b> ค่อนข้างเยอะครับ เพราะความสูงที่เพิ่มขึ้น แรงดันดินจะทวีคูณ โครงสร้างเสาเข็ม คาน และแผ่นพื้นต้องขยายขนาดและเพิ่มความถี่ขึ้นทั้งหมด ทำให้ <b data-path-to-node=\"54\" data-index-in-node=\"199\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">กำแพงกันดิน สูง 2 เมตร ราคา</b> จะสูงกว่า 1.5 เมตรอย่างเห็นได้ชัดครับ</p><p data-path-to-node=\"55\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"55\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">3. ทำกำแพงกันดินเสร็จแล้ว ถมดินเลยได้ไหม?</b></p><p data-path-to-node=\"55\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"55\" data-index-in-node=\"42\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ตอบ:</b> แนะนำให้รอคอนกรีตคานและสเตย์เซ็ตตัวได้กำลังอัดสูงสุดก่อน (ประมาณ 14-28 วัน) จากนั้นค่อยเริ่มงานถมดินและบดอัด เพื่อป้องกันไม่ให้โครงสร้างรับภาระหนักเกินไปในขณะที่ยังไม่แข็งแรงเต็มที่ครับ</p><hr data-path-to-node=\"56\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"></h1><h2 data-path-to-node=\"57\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 28px;\">สนใจทำกำแพงกันดิน ปรึกษาเราได้ฟรี!</span></h2><h1 data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"58\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">จบไปแล้วครับสำหรับรีวิวงานก่อสร้างกำแพงกันดินสูง 1.70 เมตร ที่ จ.ชัยภูมิ และสำหรับใครที่ติดตามอ่านมาถึงตรงนี้ <b data-path-to-node=\"58\" data-index-in-node=\"110\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ในบทความต่อไป ผมจะพาไปดู Phase ที่ 2 ของโปรเจกต์นี้ นั่นคือ \"การก่อสร้างรั้วก่อฉาบ\" โดยใช้เสา i15 ที่เราเสียบรอไว้นี่แหละครับ</b> มาดูกันว่างานจะออกมาสวยงามเนียนตาแค่ไหน รอติดตามได้เลย!</p><p data-path-to-node=\"59\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">หากคุณกำลังมองหาผู้รับเหมาที่มีประสบการณ์ บริหารงานเป็นระบบไม่ทิ้งงาน หรืออยากทราบข้อมูล <b data-path-to-node=\"59\" data-index-in-node=\"89\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">กําแพงกันดิน ราคา</b> สำหรับที่ดินของคุณ ไม่ว่าจะเป็นขนาด 1 เมตร, 1.5 เมตร หรือ 2 เมตร ทักมาพูดคุยให้เราช่วยประเมินราคาหน้างานเบื้องต้นได้ ฟรี! ไม่มีค่าใช้จ่ายครับ</p><ul data-path-to-node=\"60\" style=\"padding-inline-start: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"60,0,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"60,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">โทร:</b>&nbsp;<span style=\"color: rgb(76, 76, 76); font-family: &quot;Segoe UI&quot;, &quot;Helvetica Neue&quot;, Arial, sans-serif; text-align: center;\">062-718-8847&nbsp;</span>(ช่างรัก)</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"60,1,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"60,1,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Line ID:</b>&nbsp;<span style=\"color: rgb(76, 76, 76); font-family: &quot;Segoe UI&quot;, &quot;Helvetica Neue&quot;, Arial, sans-serif; text-align: center;\">0627188847<br></span></p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"60,2,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"60,2,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Facebook Page:</b>&nbsp;<a href=\"https://www.facebook.com/TheeraphongRetainingwall\"><i>กำแพงกันดิน ธีรพงษ์ 062-718-8847</i></a></p></li></ul><p data-path-to-node=\"61\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"61\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\"เรื่องดินเรื่องใหญ่ ให้ผู้เชี่ยวชาญตัวจริงดูแลดีกว่าครับ\"</b></p></h1>', 'images/blogs/blog1777012815.webp', 10, '2025-07-28-กำแพงกันดิน-56-จังหวัดชัยภูมิ', '2026-04-23 23:40:15', '2026-04-23 23:40:15');
INSERT INTO `blogs` (`id`, `title`, `description`, `content`, `image`, `service_category_id`, `slug`, `created_at`, `updated_at`) VALUES
(45, 'สร้าง รั้วสำเร็จรูป ราคาเมตรละ เริ่มต้น 2,xxx บาท | รีวิวผลงานจริง จ.ชัยภูมิ จากผู้รับเหมาประสบการณ์ 15 ปี', 'กำลังมองหาผู้รับเหมาทำรั้ว? ชมผลงานจริง ติดตั้งรั้วสำเร็จรูป ราคาเมตรละ เริ่มต้น 2,xxx บาท และรั้วก่ออิฐฉาบปูน พร้อมเจาะลึกขั้นตอน สเปควัสดุแบบไม่มีกั๊ก หมดปัญหาผู้รับเหมาทิ้งงาน', '<h1 data-path-to-node=\"2\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 28px;\">รีวิวผลงานสร้างกำแพง และ รั้วสำเร็จรูป ราคาเมตรละ เริ่มต้น 2,xxx บาท (จบงานจริงที่ชัยภูมิ)</span></h1><p data-path-to-node=\"3\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\">สวัสดีครับทุกคน! หากคุณกำลังปวดหัวกับการหาผู้รับเหมาทำรั้วบ้าน รั้วโรงงาน หรือกำลังวางแผนอยากล้อมรั้วที่ดินให้เป็นสัดส่วน ปลอดภัย และดูสวยงาม วันนี้ผมในฐานะผู้รับเหมาที่มีประสบการณ์ด้านกำแพงกันดินและงานรั้วมามากกว่า 15 ปี จะพามาเจาะลึกการทำงานจริงหน้างานครับ</p><p data-path-to-node=\"4\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">บทความนี้ผมจะมาเล่าให้ฟังแบบหมดเปลือกว่า <b data-path-to-node=\"4\" data-index-in-node=\"41\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">รั้วสำเร็จรูป ราคาเมตรละ</b> เท่าไหร่? สเปคเหล็ก สเปคปูนที่ใช้เป็นยังไง? โดยจะเป็นการรีวิวผลงานที่ทีมงานของเราเพิ่งส่งมอบไปหมาดๆ เป็นการทำรั้วต่อจาก <a href=\"https://www.theeraphong.com/blogs/2025-07-28-%E0%B8%81%E0%B8%B3%E0%B9%81%E0%B8%9E%E0%B8%87%E0%B8%81%E0%B8%B1%E0%B8%99%E0%B8%94%E0%B8%B4%E0%B8%99-56-%E0%B8%88%E0%B8%B1%E0%B8%87%E0%B8%AB%E0%B8%A7%E0%B8%B1%E0%B8%94%E0%B8%8A%E0%B8%B1%E0%B8%A2%E0%B8%A0%E0%B8%B9%E0%B8%A1%E0%B8%B4\" target=\"_blank\">กำแพงกันดินที่พึ่งก่อสร้างเสร็จ</a> ครับ ใครกำลังหาข้อมูล <b data-path-to-node=\"4\" data-index-in-node=\"238\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ราคารั้วบ้าน</b> หรือเปรียบเทียบวัสดุอยู่ ห้ามพลาดเด็ดขาด!</p><hr data-path-to-node=\"5\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><h2 data-path-to-node=\"6\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 22px;\">📍 ข้อมูลโปรเจกต์: งานสร้างรั้วมาตรฐานระดับโครงการ</span></h2><ul data-path-to-node=\"7\" style=\"padding-inline-start: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"7,0,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"7,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">สถานที่ตั้ง:</b> ตำบลท่าใหญ่ อำเภอหนองบัวแดง จังหวัดชัยภูมิ</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"7,1,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"7,1,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ลักษณะพื้นที่:</b> ที่ดินปรับระดับใหม่ มีการทำกำแพงกันดินไว้ก่อนแล้วรอบพื้นที่</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"7,2,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"7,2,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ระยะเวลาดำเนินการ:</b>&nbsp;70 วัน (รวมระยะเวลาเซ็ตตัวของคอนกรีต)</p><p data-path-to-node=\"7,2,0\" style=\"line-height: 1.15 !important;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777263251_nMtJzOPCej.webp\" style=\"width: 25%;\"><br></p></li></ul><p data-path-to-node=\"8\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><code data-path-to-node=\"8\" data-index-in-node=\"0\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\">ภาพ: ภาพรวมของพื้นที่หน้างานก่อนเริ่มทำรั้ว เห็นแนวรอยต่อกำแพงกันดิน</code></p><hr data-path-to-node=\"9\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><h2 data-path-to-node=\"10\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 22px;\">🛠 รายละเอียดงานและสเปควัสดุ (แบบฉบับช่างมืออาชีพ)</span></h2><p data-path-to-node=\"11\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\">สำหรับงานที่หนองบัวแดง ชัยภูมิ ไซต์นี้ ลูกค้าต้องการรั้วที่มีความแข็งแรงทนทาน ผสมผสานระหว่างความสวยงามด้านหน้าบ้าน และความรวดเร็วคุ้มค่าในโซนด้านข้างและด้านหลัง เราจึงแบ่งการทำงานออกเป็น 3 ส่วนหลักๆ ดังนี้ครับ:</p><h3 data-path-to-node=\"12\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 20px;\">1. รั้วก่อฉาบ (ด้านหน้าเน้นความสวยงาม) - ระยะ 27 เมตร</span></h3><p data-path-to-node=\"13\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><b data-path-to-node=\"13\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ราคา:</b> 4,xxx บาทต่อเมตร</p><p data-path-to-node=\"13\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">โซนนี้ลูกค้าอยากได้ความพรีเมียมครับ จึงเลือกเป็นงานก่ออิฐฉาบปูน พร้อมตกแต่งบัว สเปคโครงสร้างที่เราจัดให้คือระดับ \"กันแผ่นดินไหว\" (Over-spec นิดๆ เพื่อความสบายใจของลูกค้าครับ)</p><ul data-path-to-node=\"14\" style=\"padding-inline-start: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"14,0,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"14,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ฟุตติ้งฐานแผ่:</b> ใช้เหล็ก DB12 @0.25 ขนาด 0.60 x 0.60 x 0.25 ม. รับน้ำหนักได้สบายๆ</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"14,1,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"14,1,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">คาน คสล. (คอนกรีตเสริมเหล็ก):</b> ใช้เหล็กข้ออ้อย 5 เส้น (5DB12) ขนาดคาน 0.30 x 0.30 ม. ใหญ่และแข็งแรงมาก</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"14,2,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"14,2,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">เสา คสล.:</b> ใช้เหล็ก 4DB12 ขนาด 0.20 x 0.40 ม. ความสูง 2 เมตร</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"14,3,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"14,3,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">งานผนัง:</b> ก่ออิฐบล็อกมาตรฐาน พร้อมทำเซาะร่อง โชว์บัวตกแต่ง 2 ด้าน (หน้า-หลัง)</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"14,4,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"14,4,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ทับหลัง คสล.:</b> ใช้เหล็ก 2RB9 ขนาด 0.20 x 0.15 ม. ป้องกันรอยร้าวของผนัง</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"14,5,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"14,5,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">งานตกแต่ง:</b> ติดตั้งบัวหัวเสา เพิ่มความหรูหรา</p></li></ul><h3 data-path-to-node=\"15\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 20px;\">2. รั้วสำเร็จรูป บนสันกำแพงกันดิน - ระยะ 47 เมตร</span></h3><p data-path-to-node=\"16\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><b data-path-to-node=\"16\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ราคา:</b> เริ่มต้น 2,xxx บาทต่อเมตร</p><p data-path-to-node=\"16\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">ส่วนนี้คือไฮไลท์ของความคุ้มค่าครับ! เนื่องจากเรามีฐานกำแพงกันดินที่แข็งแรงอยู่แล้ว การใช้แผ่น <b data-path-to-node=\"16\" data-index-in-node=\"126\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">รั้วสําเร็จรูป ราคา</b> จะถูกลงมาก เพราะไม่ต้องทำฟุตติ้งใหม่</p><ul data-path-to-node=\"17\" style=\"padding-inline-start: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"17,0,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"17,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">เสารั้ว:</b> ใช้เสาตัวไอ (I-section) i15 ความสูง 2.50 ม. ฝังลึกลงในสเตย์ของกำแพงกันดิน ระยะห่างเสา 3 เมตร</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"17,1,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"17,1,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">แผ่นผนัง:</b> แผ่นผนังรั้วสำเร็จรูปอัดแรง จำนวน 7 แผ่น (ความสูงรวม 2 เมตร)</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"17,2,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"17,2,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">แผ่นทับหลัง:</b> แผ่นทับหลังสำเร็จรูป จำนวน 1 แผ่น ปิดด้านบนให้สวยงามและรัดแผ่นให้แน่นหนา</p></li></ul><h3 data-path-to-node=\"18\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 20px;\">3. รั้วสำเร็จรูป (ตั้งบนพื้นดินใหม่) - ระยะ 81.6 เมตร</span></h3><p data-path-to-node=\"19\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><b data-path-to-node=\"19\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ราคา:</b> 4,xxx บาทต่อเมตร</p><p data-path-to-node=\"19\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">หลายคนสงสัยว่า ทำไม <b data-path-to-node=\"19\" data-index-in-node=\"43\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ราคารั้วสําเร็จรูป</b> โซนนี้ถึงแพงกว่าโซนที่ 2? คำตอบคือ \"โครงสร้างใต้ดิน\" ครับ โซนนี้เป็นดินเดิม ไม่มีกำแพงกันดินรองรับ เราจึงต้องทำโครงสร้างรากฐานใหม่ทั้งหมด เพื่อไม่ให้รั้วล้มในอนาคต</p><ul data-path-to-node=\"20\" style=\"padding-inline-start: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"20,0,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"20,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ฟุตติ้งฐานแผ่:</b> เหล็ก DB12 @0.25 ขนาด 0.60 x 0.60 x 0.25 ม.</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"20,1,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"20,1,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">คาน คสล.:</b> เหล็กข้ออ้อย 5DB12 ขนาด 0.30 x 0.30 ม. วางบนดินเพื่อรับน้ำหนักแผ่นรั้ว</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"20,2,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"20,2,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">เสารั้ว:</b> เสา i15 ความสูง 2.50 ม. ระยะห่าง 3 เมตร</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"20,3,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"20,3,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">แผ่นผนัง &amp; ทับหลัง:</b> แผ่นผนังรั้วสำเร็จรูป 7 แผ่น + แผ่นทับหลัง 1 แผ่น (ได้ความสูง 2 เมตรพอดี)</p><p data-path-to-node=\"20,3,0\" style=\"line-height: 1.15 !important;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777263175_mn39e8bsOM.webp\" style=\"width: 25%;\"><br></p></li></ul><p data-path-to-node=\"21\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><code data-path-to-node=\"21\" data-index-in-node=\"0\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\">ภาพ: ภาพ Close-up สเปคเหล็กคาน และฟุตติ้งก่อนเทปูน</code></p><hr data-path-to-node=\"22\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><h2 data-path-to-node=\"23\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\">🤝 ความต้องการและ Pain Point ของลูกค้า</h2><p data-path-to-node=\"24\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\">ก่อนเริ่มงาน เจ้าของบ้านได้เข้ามาปรึกษาผมด้วยความกังวลใจครับ ท่านเล่าว่า:</p><blockquote data-path-to-node=\"25\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"25,0\" style=\"line-height: 1.15 !important;\"><i data-path-to-node=\"25,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\"ช่างครับ ผมตามหาผู้รับเหมามาหลายเจ้า บางเจ้าเสนอราคาถูกมาก แต่พอขอดูสเปคเหล็กกลับบ่ายเบี่ยง บางเจ้าทำกำแพงเพื่อนบ้านล้ม แล้วก็ทิ้งงานหนีไปเลย... ผมขอแค่ผู้รับเหมาที่ไว้ใจได้ ไม่ทิ้งงาน คุณภาพงานดี ซื่อสัตย์ และใช้วัสดุตรงตามตกลง\"</i></p></blockquote><p data-path-to-node=\"26\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">นี่คือสิ่งที่เรายึดถือมาตลอด 15 ปีครับ \"รับเหมาด้วยความซื่อสัตย์\" เราจึงทำสัญญาระบุสเปควัสดุ (ตามที่แจ้งไปด้านบน) อย่างชัดเจนทุกตัวอักษร</p><hr data-path-to-node=\"27\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><h2 data-path-to-node=\"28\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"><span style=\"font-size: 22px;\">🏗 ขั้นตอนการทำงานจริง (Step-by-Step)</span></h2><p data-path-to-node=\"29\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\">การทำงานของเราเน้นความเป็นระบบ ตรวจสอบได้ทุกขั้นตอนครับ</p><p data-path-to-node=\"30\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"30\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">1. เซ็นสัญญา และดำเนินการเตรียมพื้นที่ (Mobilization)</b></p><p data-path-to-node=\"30\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">หลังจากตกลงราคาและเซ็นสัญญา เราเข้าเคลียร์พื้นที่ เช็คระดับดิน เล็งแนวกล้องระดับ (Leveling) เพื่อกำหนดจุดขุดหลุมฟุตติ้งให้เป๊ะที่สุด</p><p data-path-to-node=\"30\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777003081_iOJEEcfJWw.webp\" style=\"width: 25%;\"><br></p><p data-path-to-node=\"30\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><code data-path-to-node=\"30\" data-index-in-node=\"187\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\">ภาพ: ทีมช่างกำลังส่องกล้องระดับ และขุดหลุม</code></p><p data-path-to-node=\"30\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><code data-path-to-node=\"30\" data-index-in-node=\"187\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><br></code></p><p data-path-to-node=\"31\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"31\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">2. หล่อคานคอนกรีตเสริมเหล็ก และติดตั้งเสารั้ว</b></p><p data-path-to-node=\"31\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">สำหรับรั้วสำเร็จรูปที่ตั้งบนดิน และรั้วก่อฉาบ เราผูกเหล็กฟุตติ้งและเทคอนกรีตฐานราก จากนั้นตั้งเสา (ไม่ว่าจะเป็นเสา คสล. หรือเสา i15) ให้ได้ดิ่ง 90 องศาเป๊ะๆ ก่อนเทคานรัดคอเสา</p><p data-path-to-node=\"31\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777003595_sLzgEJxKir.webp\" style=\"width: 25%;\"><br></p><p data-path-to-node=\"31\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><code data-path-to-node=\"31\" data-index-in-node=\"221\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\">ภาพ: การตั้งเสา i15 ให้ได้แนวดิ่ง และการเทปูนคาน</code></p><p data-path-to-node=\"31\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><code data-path-to-node=\"31\" data-index-in-node=\"221\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><br></code></p><p data-path-to-node=\"32\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"32\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">3. ติดตั้งแผ่นรั้ว ก่ออิฐและฉาบปูน</b></p><ul data-path-to-node=\"33\" style=\"padding-inline-start: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"33,0,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"33,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">โซนรั้วสำเร็จรูป:</b> เราใช้เครนยกแผ่นรั้วเสียบลงในร่องเสาทีละแผ่น รวดเร็ว และแนวสวยงาม</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"33,1,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"33,1,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">โซนรั้วก่อฉาบ:</b> ช่างก่ออิฐและจับเซี้ยมอย่างประณีต ดึงเอ็นให้ผนังเรียบตรง ไม่เป็นคลื่น และทำบัวประดับตามแบบ</p><p data-path-to-node=\"33,1,0\" style=\"line-height: 1.15 !important;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777263251_CwU439LGl7.webp?width=400&amp;format=webp\" style=\"width: 25%;\"><br></p><p data-path-to-node=\"33,1,0\" style=\"line-height: 1.15 !important;\"><code data-path-to-node=\"33,1,0\" data-index-in-node=\"106\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\">รูปภาพ: รถเครนกำลังยกแผ่นรั้วสำเร็จรูปใส่ร่องเสา</code></p><p data-path-to-node=\"33,1,0\" style=\"line-height: 1.15 !important;\"><code data-path-to-node=\"33,1,0\" data-index-in-node=\"106\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><br></code></p></li></ul><p data-path-to-node=\"34\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"34\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">4. ทาสี สูตรทนทาน 10 ปี และส่งมอบงาน</b></p><p data-path-to-node=\"34\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">เราไม่ได้ทาสีแค่ให้จบๆ ไป แต่เราใช้สีรองพื้นปูนเก่า/ใหม่ เกรดพรีเมียม และทาสีทับหน้าสูตรทนทาน 10 ปี ป้องกันตะไคร่น้ำและเชื้อรา ก่อนทำการเคลียร์เศษวัสดุ และพาเจ้าของบ้านตรวจรับงาน</p><p data-path-to-node=\"34\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777263364_5MrZK835D0.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777263365_dhQFe8N9FK.webp\" style=\"width: 25%;\"><br></p><p data-path-to-node=\"34\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><code data-path-to-node=\"34\" data-index-in-node=\"216\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\">[แทรกรูปภาพ: ภาพช่างกำลังกลิ้งสีรั้ว และภาพการส่งมอบงานรอยยิ้มลูกค้า]</code></p><hr data-path-to-node=\"35\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><h2 data-path-to-node=\"36\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\"></h2><h2 data-path-to-node=\"39\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\">✨ ผลลัพธ์หลังติดตั้ง (Before &amp; After)</h2><ul data-path-to-node=\"40\" style=\"padding-inline-start: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"40,0,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"40,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Before:</b> ที่ดินโล่งๆ ดินลูกรังปรับระดับใหม่ ดูไม่ปลอดภัย และไม่มีขอบเขตที่ชัดเจน</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"40,1,0\" style=\"line-height: 1.15 !important;\"><b data-path-to-node=\"40,1,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">After:</b> รั้วบ้านตั้งตระหง่าน โซนด้านหน้าเป็นรั้วก่อฉาบทาสีขาวตัดกับบัวสวยงามดูภูมิฐาน ส่วนด้านข้างและด้านหลังเป็นแผ่นรั้วสำเร็จรูปเรียบเนียน สีสม่ำเสมอ แข็งแรงทนทาน ช่วยให้บ้านดูมีอาณาเขตและปลอดภัยขึ้น 100%</p><p data-path-to-node=\"40,1,0\" style=\"line-height: 1.15 !important;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777003081_etyvDbt7Rz.webp\" style=\"width: 25%;\">&nbsp;&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777263364_jZH5LFnpYO.webp?width=400&amp;format=webp\" style=\"width: 25%;\"><br></p></li></ul><p data-path-to-node=\"41\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><code data-path-to-node=\"41\" data-index-in-node=\"0\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\">รูปภาพ: รูป Before/After</code></p><hr data-path-to-node=\"42\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><h2 data-path-to-node=\"43\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\">💰 สรุปงบประมาณการก่อสร้าง</h2><p data-path-to-node=\"44\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\">เพื่อให้เห็นภาพรวม <b data-path-to-node=\"44\" data-index-in-node=\"19\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ราคารั้วบ้าน</b> โปรเจกต์นี้ ผมสรุปมาให้ดูง่ายๆ ในตารางครับ (ราคานี้รวมค่าของและค่าแรงแล้ว)</p><table data-path-to-node=\"45\" style=\"margin-bottom: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><thead style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><tr style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important; margin-bottom: 0px !important;\">ประเภทของรั้ว</strong></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important; margin-bottom: 0px !important;\">ความยาว (เมตร)</strong></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important; margin-bottom: 0px !important;\">ราคาโดยประมาณ (บาท/เมตร)</strong></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><strong style=\"line-height: 1.15 !important; margin-top: 0px !important; margin-bottom: 0px !important;\">หมายเหตุ</strong></td></tr></thead><tbody style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><tr style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"45,1,0,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><b data-path-to-node=\"45,1,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">1. รั้วก่ออิฐฉาบปูน (โชว์บัว)</b></span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"45,1,1,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">27 ม.</span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"45,1,2,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">4,xxx บาท</span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"45,1,3,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ทำฟุตติ้ง+คานใหม่ เน้นความสวยงามหน้าบ้าน</span></td></tr><tr style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"45,2,0,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><b data-path-to-node=\"45,2,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">2. รั้วสำเร็จรูป (บนกำแพงกันดิน)</b></span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"45,2,1,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">47 ม.</span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"45,2,2,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">2,xxx บาท</span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"45,2,3,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><b data-path-to-node=\"45,2,3,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">คุ้มค่าที่สุด</b> เพราะใช้โครงสร้างกำแพงกันดินเดิม</span></td></tr><tr style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"45,3,0,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><b data-path-to-node=\"45,3,0,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">3. รั้วสำเร็จรูป (ตั้งบนดินใหม่)</b></span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"45,3,1,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">81.6 ม.</span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"45,3,2,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">4,xxx บาท</span></td><td style=\"border-color: currentcolor; line-height: 1.15 !important; margin-top: 0px !important;\"><span data-path-to-node=\"45,3,3,0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ต้องขุดทำฟุตติ้งและเทคาน คสล. ใหม่ทั้งหมด</span></td></tr></tbody></table><p data-path-to-node=\"46\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><i data-path-to-node=\"46\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">(หมายเหตุ: ราคาขึ้นอยู่กับสภาพพื้นที่ การปรับระดับดิน และระยะทางขนส่ง รบกวนประเมินหน้างานอีกครั้งครับ)</i></p><hr data-path-to-node=\"47\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><h2 data-path-to-node=\"48\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\">⭐ รีวิวจากลูกค้า (ความพึงพอใจ)</h2><blockquote data-path-to-node=\"49\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><p data-path-to-node=\"49,0\" style=\"line-height: 1.15 !important;\"><i data-path-to-node=\"49,0\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">\"ประทับใจทีมงานมากคะ ตอนแรกกังวลเรื่อง ราคารั้วสําเร็จรูป ว่าจะบานปลายไหม แต่ช่างประเมินราคาจบตั้งแต่ก่อนเซ็นสัญญา ทำงานเร็วมาก วัสดุที่เอามาลงก็ตรงตามที่คุยกันไว้หมด แผ่นรั้วเรียบสวย รั้วด้านหน้าก็ฉาบเนียนมาก ช่างเก็บกวาดขยะหน้างานให้สะอาดเรียบร้อย แนะนำเลยครับ ไม่ผิดหวังจริงๆ\"</i> – คุณนิภาพร (เจ้าของโปรเจกต์ จ.ชัยภูมิ)</p></blockquote><hr data-path-to-node=\"50\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><h2 data-path-to-node=\"51\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\">❓ คำถามที่พบบ่อย (FAQ)</h2><p data-path-to-node=\"52\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><b data-path-to-node=\"52\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">1. ทำไม ราคารั้วสําเร็จรูป ถึงถูกกว่าและเสร็จเร็วกว่ารั้วก่ออิฐ?</b></p><p data-path-to-node=\"52\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">ตอบ: เพราะรั้วสำเร็จรูปถูกหล่อชิ้นส่วนมาแล้วจากโรงงานครับ เมื่อถึงหน้างานสามารถใช้เครนยกประกอบเข้ากับเสาได้เลย ลดขั้นตอนการก่ออิฐ ฉาบปูน และรอปูนแห้งไปได้มหาศาล ประหยัดทั้งค่าแรงและเวลาครับ</p><p data-path-to-node=\"53\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"53\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">2. กำลังตัดสินใจระหว่าง รั้วสำเร็จรูป กับ ราคารั้วคาวบอย แบบไหนดีกว่ากัน?</b></p><p data-path-to-node=\"53\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">ตอบ: ขึ้นอยู่กับการใช้งานครับ <b data-path-to-node=\"53\" data-index-in-node=\"104\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ราคารั้ว คาวบอย</b> (รั้วโปร่งๆ 3-4 ชั้น) จะเหมาะกับงานล้อมสวน ฟาร์ม หรือแบ่งเขตที่ดินแบบโปร่งตา ราคาจะย่อมเยากว่า แต่ถ้าต้องการความเป็นส่วนตัว กันสุนัข กันคนมองเข้ามา หรือป้องกันลม/ฝุ่น รั้วสำเร็จรูปแบบทึบจะตอบโจทย์กว่าครับ</p><p data-path-to-node=\"54\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"54\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">3. ใช้แผ่นรั้วของอะไร? รั้วสําเร็จรูป SCG ราคา ต่างจากแบรนด์ท้องถิ่นไหม?</b></p><p data-path-to-node=\"54\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">ตอบ: ทางเรามีให้ลูกค้าเลือกครับ แบรนด์ระดับประเทศอย่าง SCG จะมีราคาสูงกว่าแบรนด์โรงงานท้องถิ่นประมาณ 15-20% เนื่องจากมีมาตรฐานการทดสอบและการรับประกันจากแบรนด์แม่ที่ชัดเจน แต่ปัจจุบันโรงงานหล่อแผ่นรั้วท้องถิ่น (ที่ได้มาตรฐาน มอก.) ก็มีคุณภาพความแข็งแรงและอัดแรงลวดได้ดีเยี่ยมไม่แพ้กัน ทางเราคัดกรองเฉพาะโรงงานที่ได้มาตรฐานมาใช้งานเท่านั้นครับ</p><p data-path-to-node=\"55\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"55\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">4. มีการรับประกันผลงานหรือไม่?</b></p><p data-path-to-node=\"55\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\">ตอบ: แน่นอนครับ! งานโครงสร้างและฐานรากทุกชิ้น เรารับประกันผลงาน 1 ปีเต็ม หากมีการทรุดหรือร้าวที่เกิดจากโครงสร้าง เราดูแลให้ฟรีครับ</p><hr data-path-to-node=\"56\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\"><h2 data-path-to-node=\"57\" style=\"font-family: &quot;Google Sans&quot;, sans-serif !important; line-height: 1.15 !important;\">📞 สนใจสร้างรั้ว ปรึกษาฟรี! (Call to Action)</h2><p data-path-to-node=\"58\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important; margin-top: 0px !important;\">หากคุณกำลังมองหาทีมงานมืออาชีพ รับ<a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\">ทำกำแพงกันดิน</a> และ <b data-path-to-node=\"58\" data-index-in-node=\"52\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">รั้วสำเร็จรูป ราคาเมตรละ</b> คุ้มค่า งบไม่บานปลาย วัสดุเต็มสเปคแบบนี้ ไม่ว่าจะเป็นงานบ้าน งานโครงการ หรือโรงงาน เราพร้อมให้บริการครับ</p><p data-path-to-node=\"59\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><i data-path-to-node=\"59\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ให้ประสบการณ์ 15 ปีของเรา ดูแลความปลอดภัยให้บ้านคุณ</i></p><p data-path-to-node=\"60\" style=\"font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><b data-path-to-node=\"60\" data-index-in-node=\"0\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">ช่องทางการติดต่อ:</b></p><ul data-path-to-node=\"61\" style=\"padding-inline-start: 32px; font-family: &quot;Google Sans Text&quot;, sans-serif !important; line-height: 1.15 !important;\"><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"61,0,0\" style=\"line-height: 1.15 !important;\">📲 <b data-path-to-node=\"61,0,0\" data-index-in-node=\"3\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">โทร:</b> 062-718-8847 นายธีรพงษ์ (ช่างรัก)</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"61,1,0\" style=\"line-height: 1.15 !important;\">💬 <b data-path-to-node=\"61,1,0\" data-index-in-node=\"3\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">LINE ID:</b>&nbsp;0627188847</p></li><li style=\"line-height: 1.15 !important; margin-top: 0px !important;\"><p data-path-to-node=\"61,2,0\" style=\"line-height: 1.15 !important;\">📩 <b data-path-to-node=\"61,2,0\" data-index-in-node=\"3\" style=\"line-height: 1.15 !important; margin-top: 0px !important;\">Inbox Facebook:</b>&nbsp;<a href=\"https://www.facebook.com/TheeraphongRetainingwall\">กำแพง กันดินธีรพงษ์ 062-718-8847</a></p></li></ul>', 'images/blogs/blog1777265865.webp', 28, '2025-11-05-รั้ว-หนองบัวแดง-ชัยภูมิ', '2026-04-26 21:57:45', '2026-04-26 21:57:45');
INSERT INTO `blogs` (`id`, `title`, `description`, `content`, `image`, `service_category_id`, `slug`, `created_at`, `updated_at`) VALUES
(46, 'รีวิวก่อสร้างกำแพงกันดิน & รั้วสำเร็จรูป ชัยภูมิ งบ 5 แสน (อัปเดต 2026)', 'กำลังหาผู้รับเหมาทำกำแพงกันดิน ชัยภูมิ? พาชมรีวิวงานจริง ต.ชีลอง เจาะลึกสเปคเสาเข็มสเตย์และรั้วสำเร็จรูป โครงสร้างแข็งแรง ไม่ทรุด จบในงบ 5xx,xxx บาท', '<h2 data-path-to-node=\"3\">🏗️ เจาะลึก 6 ขั้นตอนการทำงานก่อสร้าง (Step-by-Step Construction Process)&nbsp;รีวิวผลงานก่อสร้างกำแพงกันดินและรั้วสำเร็จรูป ต.ชีลอง อ.เมือง จ.ชัยภูมิ&nbsp;(งบ 5xx,xxx บาท)</h2><p data-path-to-node=\"8,0\">หากคุณกำลังมองหา ผู้รับเหมาสร้างกำแพงกันดินและรั้วบ้านในจังหวัดชัยภูมิ ที่ได้มาตรฐาน โครงสร้างแข็งแรงทนทาน และราคาโปร่งใส วันนี้เราขอนำเสนอรีวิวผลงานจริงจากหน้างาน ตำบลชีลอง อำเภอเมือง จังหวัดชัยภูมิ โปรเจคนี้ครอบคลุมตั้งแต่งานหล่อคาน เทฟุตติ้ง วางแผ่นกันดิน ไปจนถึงการติดตั้งรั้วสำเร็จรูปและประตูรั้วแบบครบวงจร ในงบประมาณรวมตลอดโครงการเพียง 5xx,xxx บาท เท่านั้น!</p><p data-path-to-node=\"8,1\">งานนี้เราจัดเต็มด้วยวัสดุคุณภาพสูง เสาเข็มได้มาตรฐาน พร้อมการควบคุมงานอย่างเป็นระบบ <i data-path-to-node=\"8,1\" data-index-in-node=\"84\">(สำหรับท่านที่ต้องการศึกษาข้อมูลราคาตลาดเพิ่มเติมเพื่อประเมินงบ สามารถอ่านได้ที่ <response-element class=\"\" ng-version=\"0.0.0-PLACEHOLDER\"><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><link-block _nghost-ng-c2830248547=\"\" class=\"ng-star-inserted\"><!----><a href=\"https://www.theeraphong.com/retaining-wall\" target=\"_blank\">กําแพง กัน ดิน ราคา ต่อ เมตร 2026 (พ.ศ. 2569)</a><!----><!----></link-block><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></response-element>)</i> มาเจาะลึกรายละเอียดและสเปคของงานก่อสร้างในโปรเจคนี้กันครับ</p><p data-path-to-node=\"4\">เพื่อให้ลูกค้ามั่นใจในทุกกระบวนการก่อสร้าง เราบริหารจัดการหน้างานอย่างเป็นระบบ โปร่งใส และสามารถตรวจสอบความคืบหน้าได้ในทุกงวดงาน ดังนี้:</p><p data-path-to-node=\"5\"><b data-path-to-node=\"5\" data-index-in-node=\"0\">1. งวดที่ 1: การสำรวจพื้นที่ เซ็นสัญญา และการเตรียมหน้างาน (Site Preparation)</b></p><ul data-path-to-node=\"6\"><li><p data-path-to-node=\"6,0,0\"><b data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">รายละเอียดการทำงาน:</b> ก่อนเริ่มงานจริง ทีมช่างผู้ชำนาญการจะลงพื้นที่เพื่อประเมินสภาพหน้าดินและระดับความลาดเอียง จากนั้นจึงทำการเซ็นสัญญาก่อสร้างเพื่อให้ลูกค้ามั่นใจในงบประมาณที่ไม่บานปลาย ขั้นตอนต่อไปคือการนำเครื่องจักรเข้าเคลียร์ริ่ง (Clearing) พื้นที่ กำจัดวัชพืช เศษหิน และปรับระดับหน้าดิน พร้อมทั้ง <b data-path-to-node=\"6,0,0\" data-index-in-node=\"301\">\"การตีผังและหาแนวระดับ\"</b> เพื่อกำหนดจุดตอกเสาเข็มให้แม่นยำตามแบบแปลน 100%</p></li></ul><blockquote data-path-to-node=\"7\"><p data-path-to-node=\"7,0\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1780473707_pNxcXqW3E8.webp\" alt=\"การสำรวจพื้นที่และตีผังเตรียมหน้างานก่อสร้างกำแพงกันดิน ต.ชีลอง ชัยภูมิ 01\" style=\"width: 25%;\">&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1780473706_i2IycKTknl.webp\" alt=\"การสำรวจพื้นที่และตีผังเตรียมหน้างานก่อสร้างกำแพงกันดิน ต.ชีลอง ชัยภูมิ 02\" style=\"width: 25%;\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1780473707_T4y0lSkKIJ.webp\" alt=\"การสำรวจพื้นที่และตีผังเตรียมหน้างานก่อสร้างกำแพงกันดิน ต.ชีลอง ชัยภูมิ 02\" style=\"width: 25%;\">&nbsp;</p></blockquote><p data-path-to-node=\"8\"><b data-path-to-node=\"8\" data-index-in-node=\"0\">2. งวดที่ 2: งานกดตอกเสาเข็มหลักและเสาเข็มสเตย์ (Piling Installation)</b></p><ul data-path-to-node=\"9\"><li><p data-path-to-node=\"9,0,0\"><b data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">รายละเอียดการทำงาน:</b> ขั้นตอนนี้คือหัวใจสำคัญของความแข็งแรง เราใช้ปั้นจั่นหรือรถแบ็คโฮในการกดเสาเข็มรูปพรรณ i22 ลงสู่ชั้นดิน โดยแบ่งเป็น <b data-path-to-node=\"9,0,0\" data-index-in-node=\"135\">เสาเข็มหลัก (รับน้ำหนักแนวดิ่ง)</b> ลึก 2.50 และ 3.00 เมตร และที่ขาดไม่ได้คือ <b data-path-to-node=\"9,0,0\" data-index-in-node=\"209\">เสาเข็มสเตย์ (รับแรงดึง)</b> ลึก 2.00 และ 2.50 เมตร ที่ตอกเยื้องออกไปด้านหลัง ทีมงานจะทำการเช็คระดับดิ่ง (Plumbness) ของเสาเข็มทุกต้นอย่างเข้มงวด เพื่อให้โครงสร้างตั้งตรงและพร้อมสำหรับการรับน้ำหนักของมวลดิน</p></li></ul><blockquote data-path-to-node=\"10\"><p data-path-to-node=\"10,0\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777538042_i8HLxfvAU0.webp\" alt=\"งานตอกเสาเข็ม i22 พร้อมดึงแนวเสาเข็ม ป้องกันกำแพงทรุด 01\" style=\"width: 25%;\">&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1777538041_VyGWLsn001.webp\" alt=\"งานตอกเสาเข็ม i22 พร้อมดึงแนวเสาเข็ม ป้องกันกำแพงทรุด 01\" style=\"width: 25%;\"><br></p></blockquote><p data-path-to-node=\"11\"><b data-path-to-node=\"11\" data-index-in-node=\"0\">3. งวดที่ 3: งานติดตั้งแผ่นกันดินสำเร็จรูป (Retaining Wall Panel Installation)</b></p><ul data-path-to-node=\"12\"><li><p data-path-to-node=\"12,0,0\"><b data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">รายละเอียดการทำงาน:</b> เมื่อเสาเข็มได้แนวที่มั่นคง เราจะดำเนินการนำแผ่นกันดินคอนกรีตอัดแรง (ขนาด 0.35 x 1.94 ม. และ 0.35 x 1.44 ม. ความหนา 5 ซม.) เสียบลงในร่องของเสาเข็มรูปพรรณ i22 อย่างระมัดระวัง ในจุดที่มีการรับน้ำหนักดินมาก (ส่วนที่ 2) จะใช้แผ่นกันดินซ้อนกันถึง 3 แผ่นต่อช่องเพื่อเพิ่มความแข็งแกร่ง พร้อมตรวจสอบความแนบสนิทของรอยต่อเพื่อป้องกันปัญหาดินสไลด์หรือน้ำพัดพาดินลอดผ่านร่องในอนาคต</p></li></ul><blockquote data-path-to-node=\"13\"><p data-path-to-node=\"13,0\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1778133559_VU0sdCjdCn.webp\" alt=\"งานเสียบแผ่นกันดินคอนกรีตสำเร็จรูปเข้ากับแนวเสาเข็มอย่างแน่นหนา 01\" style=\"width: 25%;\">&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1778133559_6NQs6KAnoG.webp\" alt=\"งานเสียบแผ่นกันดินคอนกรีตสำเร็จรูปเข้ากับแนวเสาเข็มอย่างแน่นหนา 02\" style=\"width: 25%;\">&nbsp;</p></blockquote><p data-path-to-node=\"14\"><b data-path-to-node=\"14\" data-index-in-node=\"0\">4. งวดที่ 4: งานผูกเหล็กโครงสร้างและประกอบไม้แบบ (Reinforcement &amp; Formwork)</b></p><ul data-path-to-node=\"15\"><li><p data-path-to-node=\"15,0,0\"><b data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">รายละเอียดการทำงาน:</b> ขั้นตอนการสร้างเครือข่ายความแข็งแรง ทีมช่างจะเริ่มทำการสกัดหัวเข็มและผูกเหล็กเสริมตามสเปควิศวกรรม ได้แก่ <b data-path-to-node=\"15,0,0\" data-index-in-node=\"125\">เหล็ก 5DB12 สำหรับคานหลัก (Beam)</b>, <b data-path-to-node=\"15,0,0\" data-index-in-node=\"159\">เหล็ก 4DB12 สำหรับคานสเตย์</b> ที่เชื่อมระหว่างเสาหลักและเสาสเตย์ และ <b data-path-to-node=\"15,0,0\" data-index-in-node=\"225\">เหล็ก 12RB9 สำหรับฟุตติ้ง (ฐานรากขนาด 0.40x0.40 ม.)</b> การผูกเหล็กจะทำอย่างแน่นหนาเพื่อให้สามารถรับแรงดึงและแรงกดทับได้อย่างสมบูรณ์แบบ จากนั้นจึงทำการประกอบไม้แบบให้ได้ดิ่งและฉาก เตรียมความพร้อมสำหรับการเทคอนกรีต</p></li></ul><blockquote data-path-to-node=\"16\"><p data-path-to-node=\"16,0\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1780469785_1phcrzVhdq.webp\" alt=\"านผูกเหล็กเสริมคานและฟุตติ้งกำแพงกันดินด้วยเหล็ก DB12 ตามมาตรฐาน 01\" style=\"width: 25%;\">&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1780469786_j6Kfmczg8z.webp\" alt=\"านผูกเหล็กเสริมคานและฟุตติ้งกำแพงกันดินด้วยเหล็ก DB12 ตามมาตรฐาน 02\" style=\"width: 25%;\">&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1780469788_2jyWO7CwSN.webp\" alt=\"านผูกเหล็กเสริมคานและฟุตติ้งกำแพงกันดินด้วยเหล็ก DB12 ตามมาตรฐาน 03\" style=\"width: 25%;\">&nbsp;</p></blockquote><p data-path-to-node=\"17\"><b data-path-to-node=\"17\" data-index-in-node=\"0\">5. งวดที่ 5: งานเทคอนกรีตคาน และเริ่มติดตั้งรั้วสำเร็จรูป (Concrete Pouring &amp; Precast Fence)</b></p><ul data-path-to-node=\"18\"><li><p data-path-to-node=\"18,0,0\"><b data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">รายละเอียดการทำงาน:</b> ดำเนินการเทคอนกรีตผสมเสร็จ (Ready-Mix Concrete) ลงในแบบคานและฟุตติ้ง พร้อมใช้เครื่องจี้คอนกรีต (Concrete Vibrator) เพื่อไล่ฟองอากาศ ทำให้เนื้อปูนสม่ำเสมอ ไม่มีโพรง (Honeycomb) ช่วยให้เหล็กเส้นไม่เกิดสนิม เมื่อคอนกรีตเซ็ตตัวและถอดไม้แบบออก จะเข้าสู่งานรั้วด้านบน โดยการตั้งเสารั้ว i15x1.25 ม. และเสียบแผ่นรั้วสำเร็จรูป (ขนาด 2.90x0.25 ม. จำนวน 4 แผ่น/ช่อง) พร้อมปิดหัวด้วยทับหลังรูปตัวที เพื่อล็อคโครงสร้างรั้วทั้งหมดให้เป็นผืนเดียวกัน</p></li></ul><blockquote data-path-to-node=\"19\"><p data-path-to-node=\"19,0\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1780470111_BrQkEQcJ5e.webp\" alt=\"เทคอนกรีตคานกำแพงกันดิน และการติดตั้งรั้วสำเร็จรูป จ.ชัยภูมิ 01\" style=\"width: 25%;\">&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1780470111_H3s3AFN5RP.webp\" alt=\"เทคอนกรีตคานกำแพงกันดิน และการติดตั้งรั้วสำเร็จรูป จ.ชัยภูมิ 02\" style=\"width: 25%;\">&nbsp;</p></blockquote><p data-path-to-node=\"20\"><b data-path-to-node=\"20\" data-index-in-node=\"0\">6. งวดที่ 6: งานเก็บรายละเอียด ทาสี ติดตั้งประตู และส่งมอบงาน (Finishing &amp; Handover)</b></p><ul data-path-to-node=\"21\"><li><p data-path-to-node=\"21,0,0\"><b data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">รายละเอียดการทำงาน:</b> ขั้นตอนสุดท้ายคือการสร้างความสวยงามและสมบูรณ์แบบ ทีมงานจะทำการเก็บรอยต่อ ฉาบแต่งผิวคอนกรีตให้เรียบเนียน และดำเนินการทาสีรั้วด้วยสีรองพื้นและสีทับหน้าที่ทนทานต่อสภาพอากาศ (Weather Resistance) จากนั้นทีมช่างเหล็กจะเข้าติดตั้ง <b data-path-to-node=\"21,0,0\" data-index-in-node=\"244\">ประตูเล็กพร้อมซุ้มประตู</b> และ <b data-path-to-node=\"21,0,0\" data-index-in-node=\"272\">ประตูบานเลื่อนใหญ่ทางเข้าหลัก</b> โดยปรับตั้งบานพับ รางเลื่อน และทดสอบการเปิด-ปิดให้ลื่นไหล ปิดท้ายด้วยการทำความสะอาดพื้นที่ (Clean up) และส่งมอบผลงานคุณภาพให้แก่ลูกค้า</p></li></ul><blockquote data-path-to-node=\"22\"><p data-path-to-node=\"22,0\"><img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1780470112_NbYhSwC0RA.webp\" alt=\"ส่งมอบงานกำแพงกันดินและรั้วสำเร็จรูปพร้อมประตู ต.ชีลอง จ.ชัยภูมิ 01\" style=\"width: 25%;\">&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1780470113_Wid1UAXkFY.webp\" alt=\"ส่งมอบงานกำแพงกันดินและรั้วสำเร็จรูปพร้อมประตู ต.ชีลอง จ.ชัยภูมิ 02\" style=\"width: 25%;\">&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1780470112_OSepONPzgw.webp\" alt=\"ส่งมอบงานกำแพงกันดินและรั้วสำเร็จรูปพร้อมประตู ต.ชีลอง จ.ชัยภูมิ 03\" style=\"width: 25%;\">&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1780470112_Rw9cimekTq.webp\" alt=\"ส่งมอบงานกำแพงกันดินและรั้วสำเร็จรูปพร้อมประตู ต.ชีลอง จ.ชัยภูมิ 04\" style=\"width: 25%;\">&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1780470111_qMsdaRrC33.webp\" alt=\"ส่งมอบงานกำแพงกันดินและรั้วสำเร็จรูปพร้อมประตู ต.ชีลอง จ.ชัยภูมิ 05\" style=\"width: 25%;\">&nbsp;<img src=\"https://pub-68154224aa0d447b83de9bf218e76277.r2.dev/images/gallery/1780470111_BrQkEQcJ5e.webp\" alt=\"ส่งมอบงานกำแพงกันดินและรั้วสำเร็จรูปพร้อมประตู ต.ชีลอง จ.ชัยภูมิ 06\" style=\"width: 25%;\"></p></blockquote><p><b data-path-to-node=\"25\" data-index-in-node=\"31\">สนใจประเมินราคาฟรี! หรือสอบถามบริการรับเหมาก่อสร้างในจังหวัดชัยภูมิ</b>\r\nโทร:&nbsp;<a href=\"tel:0627188847\" style=\"background-color: rgb(247, 247, 247); color: rgb(105, 105, 105); text-decoration: none; font-family: \" segoe=\"\" ui\",=\"\" \"helvetica=\"\" neue\",=\"\" arial,=\"\" sans-serif;=\"\" font-size:=\"\" 12px;=\"\" font-weight:=\"\" 400;\"=\"\">062-718-8847</a>&nbsp;| Line ID:&nbsp;<a href=\"https://line.me/ti/p/h9SHumuTEB\" style=\"background-color: rgb(243, 176, 7); color: rgb(250, 250, 250); text-decoration: none; font-family: \" segoe=\"\" ui\",=\"\" \"helvetica=\"\" neue\",=\"\" arial,=\"\" sans-serif;=\"\" font-weight:=\"\" 300;=\"\" letter-spacing:=\"\" normal;\"=\"\">0627188847</a>&nbsp;| Facebook:&nbsp;<a href=\"https://www.facebook.com/TheeraphongRetainingwall\" target=\"_blank\">Facebook-กำแพง กันดินธีรพงษ์</a></p>', 'images/blogs/blog1780475098.webp', 10, 'chaiyaphum-retaining-wall-review-2026-06-01', '2026-06-03 01:24:58', '2026-06-03 02:02:25'),
(47, 'เทพื้นคอนกรีต และติดตั้งรั้วเหล็ก อ.บำเหน็จณรงค์ จ.ชัยภูมิ', 'รับเหมาติดตั้งรั้วเหล็ก เทพื้นคอนกรีต อ.บำเหน็จณรงค์ ชัยภูมิ ผลงานคุณภาพ งบไม่บานปลาย การันตีด้วยรีวิวความพึงพอใจจากลูกค้าจริง สนใจประเมินราคาฟรี คลิกเลย!', '<div style=\"font-family: \'Kanit\', sans-serif; color: #333; line-height: 1.8; font-size: 16px;\">\n    \n    <p>กลับมาอัปเดตผลงานการต่อเติมและปรับภูมิทัศน์รอบบ้านกันต่อครับ! หลังจากคราวที่แล้วทีมงานของเราได้เข้าไปส่งมอบ <strong><a href=\"https://www.theeraphong.com/blogs/2025-02-02-%E0%B8%A3%E0%B8%B1%E0%B9%89%E0%B8%A7-%E0%B8%95%E0%B8%B3%E0%B8%9A%E0%B8%A5%E0%B9%82%E0%B8%84%E0%B8%81%E0%B9%80%E0%B8%A3%E0%B8%B4%E0%B8%87%E0%B8%A3%E0%B8%A1%E0%B8%A2%E0%B9%8C\" target=\"_blank\">โปรเจกต์เฟส 1: งานติดตั้งรั้วสำเร็จรูปและรั้วอิฐก่อฉาบ</a></strong> ให้กับลูกค้าที่ อ.บำเหน็จณรงค์ จ.ชัยภูมิ ไปเป็นที่เรียบร้อย</p>\n    \n    <p>วันนี้เราลุยกันต่อใน <strong>โปรเจกต์เฟส 2</strong> ซึ่งเป็นขั้นตอนของการตกแต่งและเสริมฟังก์ชันการใช้งานให้กับตัวบ้าน นั่นคือ <strong>งานติดตั้งรั้วเหล็ก</strong> เพื่อความสวยงามปลอดภัย และ <strong><a href=\"https://www.theeraphong.com/pour-concrete\" target=\"_blank\">งานเทพื้นคอนกรีต</a></strong> รอบบริเวณบ้านเพื่อเพิ่มพื้นที่ใช้สอยครับ มาดูกันว่ารายละเอียดงานในเฟสนี้มีอะไรบ้าง</p>\n\n    <h2 style=\"color: #0A2540; font-weight: 600; margin-top: 30px; margin-bottom: 15px; border-left: 5px solid #F6821F; padding-left: 15px;\">1. งานติดตั้งรั้วเหล็ก (ต่อยอดจากฐานรั้วอิฐก่อฉาบ)</h2>\n    <p>จากเฟสแรกที่เราได้ทำฐานรั้วด้วยอิฐก่อฉาบไว้เรียบร้อยแล้ว ในเฟสนี้เราได้ทำการติดตั้งแผงรั้วเหล็กด้านบนเพื่อเพิ่มความโปร่งโล่ง แต่ยังคงความปลอดภัยและเป็นส่วนตัวให้กับตัวบ้าน</p>\n    <ul>\n        <li style=\"margin-bottom: 8px;\"><strong>วัสดุที่เลือกใช้:</strong> เราใช้เหล็กกล่องกัลวาไนซ์ (Galvanized Steel) ที่มีคุณสมบัติป้องกันสนิมได้ดีเยี่ยม เหมาะสำหรับงานกลางแจ้ง</li>\n        <li style=\"margin-bottom: 8px;\"><strong>การดีไซน์และการทำสี:</strong> จัดช่องไฟของซี่รั้วให้มีระยะห่างที่พอดี ดูโมเดิร์น พร้อมพ่นสีดำด้านทับอีกชั้นเพื่อความเรียบหรูและทนทานต่อสภาพอากาศ</li>\n        <li style=\"margin-bottom: 8px;\"><strong>การติดตั้ง:</strong> เชื่อมประกอบอย่างแน่นหนาเข้ากับเสารั้วเดิม เก็บความเรียบร้อยของรอยเชื่อมและแต้มสีกันสนิมทุกจุด</li>\n    </ul>\n\n    <h2 style=\"color: #0A2540; font-weight: 600; margin-top: 30px; margin-bottom: 15px; border-left: 5px solid #F6821F; padding-left: 15px;\">2. งานเทพื้นคอนกรีต ปรับระดับรอบบ้าน</h2>\n    <p>เพื่อให้พื้นที่รอบบ้านใช้งานได้จริง ไม่ว่าจะเป็นการจอดรถ หรือเป็นลานซักล้าง เราได้ดำเนินการเทพื้นคอนกรีตตามมาตรฐานงานช่าง</p>\n    <ul>\n        <li style=\"margin-bottom: 8px;\"><strong>การเตรียมพื้นที่:</strong> ปรับระดับหน้าดินให้เรียบและบดอัดให้แน่น เพื่อป้องกันปัญหาดินทรุดตัวในอนาคต</li>\n        <li style=\"margin-bottom: 8px;\"><strong>การผูกเหล็ก:</strong> ปูตะแกรงเหล็กฉีก (Wire Mesh) อย่างหนา เพื่อเพิ่มความสามารถในการรับน้ำหนักของพื้นคอนกรีต ป้องกันการแตกร้าว</li>\n        <li style=\"margin-bottom: 8px;\"><strong>การเทคอนกรีต:</strong> ใช้คอนกรีตผสมเสร็จ (Ready-Mixed Concrete) ที่ได้มาตรฐาน กำหนดความหนาและปรับระดับความลาดเอียง (Slope) เพื่อให้น้ำระบายออกได้ดี ไม่เกิดน้ำขังรอบบ้าน</li>\n    </ul>\n\n    <hr style=\"margin: 40px 0; border-top: 2px dashed #E3E9F0;\">\n\n    <h2 style=\"color: #0A2540; font-weight: 600; text-align: center; margin-bottom: 15px;\">🎥 เสียงตอบรับจากลูกค้า (Customer Review)</h2>\n    <p style=\"text-align: center;\">\"ทีมช่างทำงานเป็นอย่างไร? ทิ้งงานไหม? งานละเอียดแค่ไหน?\" สำหรับโปรเจกต์ที่ อ.บำเหน็จณรงค์ นี้ เราได้รับเกียรติจากเจ้าของบ้านมาแชร์ความรู้สึกหลังจากการส่งมอบงานทั้ง 2 เฟสครับ</p>\n    \n    <div class=\"embed-responsive embed-responsive-16by9\" style=\"margin: 20px 0; border-radius: 8px; overflow: hidden; box-shadow: 0 4px 10px rgba(0,0,0,0.1);\">\n        <iframe class=\"embed-responsive-item\" src=\"https://www.youtube.com/embed/NoYADiGCyhY\" allowfullscreen></iframe>\n    </div>\n\n    <div style=\"border: 1px solid #F6821F; border-radius: 4px; margin-top: 20px;\">\n        <div style=\"background-color: #FFF7F0; border-bottom: 1px solid #F6821F; padding: 10px 15px;\">\n            <h3 style=\"margin: 0; color: #E0700F; font-size: 16px; font-weight: bold;\">📌 สรุปประเด็นหลักจากบทสัมภาษณ์</h3>\n        </div>\n        <div style=\"padding: 15px;\">\n            <ul style=\"margin-bottom: 0;\">\n                <li>คุณภาพผลงาน: ลูกค้ามีความพึงพอใจอย่างมาก โดยระบุว่าทีมงานทำงานได้ดีเยี่ยม ผลงานออกมาประณีต (เนี้ยบ) และได้รูปแบบที่สวยงามตรงตามที่ตกลงกันไว้ (ตรงปก)</li>\n                <li>การสื่อสารและการบริการ: ทีมช่างทำงานด้วยความใส่ใจ พูดคุยง่าย รับฟังความต้องการของเจ้าของบ้าน และมีการให้คำแนะนำหรือปรึกษาหารือร่วมกัน เพื่อให้ได้ผลลัพธ์ที่ดีที่สุด</li>\n                <li>ความไว้วางใจในอนาคต: จากความประทับใจดังกล่าว ลูกค้ายืนยันอย่างชัดเจนว่า หากมีโอกาสสร้างงานอื่นเพิ่มเติม จะกลับมาเรียกใช้บริการจากทีมงานนี้อีกแน่นอน</li>\n            </ul>\n        </div>\n    </div>\n\n    <div style=\"background-color: #f8fafc; border: 1px solid #e2e8f0; border-radius: 8px; padding: 20px; margin: 30px 0;\">\n\n<div style=\"background-color: #0A2540; color: #ffffff; padding: 10px 15px; border-radius: 8px; border-bottom-left-radius: 0; margin-bottom: 15px; display: inline-block; max-width: 90%;\">\n            <strong style=\"color: #F6821F;\">ทีมงาน:</strong> \"มีความรู้สึกยังไงบ้างครับกับการทำงานของทีมงานของเรานะครับ\"\n        </div>\n        \n        <div style=\"background-color: #ffffff; border: 1px solid #F6821F; color: #333; padding: 10px 15px; border-radius: 8px; border-bottom-right-radius: 0; margin-bottom: 15px; max-width: 90%; margin-left: auto; display: block;\">\n            <strong style=\"color: #0A2540;\">เจ้าของบ้าน:</strong> \"ทีมงานเวิร์คมาก ทำผลงานออกมาเยี่ยม เนี้ยบจริงๆ ค่ะ\"\n        </div>\n        \n        <div style=\"background-color: #0A2540; color: #ffffff; padding: 10px 15px; border-radius: 8px; border-bottom-left-radius: 0; margin-bottom: 15px; display: inline-block; max-width: 90%;\">\n            <strong style=\"color: #F6821F;\">ทีมงาน:</strong> \"ผลงานออกมาตรงปกไหมครับ\"\n        </div>\n        \n        <div style=\"background-color: #ffffff; border: 1px solid #F6821F; color: #333; padding: 10px 15px; border-radius: 8px; border-bottom-right-radius: 0; margin-bottom: 15px; max-width: 90%; margin-left: auto; display: block;\">\n            <strong style=\"color: #0A2540;\">เจ้าของบ้าน:</strong> \"ตรงปกค่ะ และอันนี้ต้องชมเลย ช่างเข้างานตรงเวลาทุกวัน ไม่มีการทิ้งงานเลย ทำงานเสร็จแต่ละวันก็เก็บกวาดเศษวัสดุให้เรียบร้อย พื้นคอนกรีตที่เทก็เรียบเนียน ปรับสโลปน้ำไหลได้ดีเยี่ยม ไม่มีน้ำขังเลยครับ ที่สำคัญคือคุยง่าย ให้คำแนะนำดี และงบไม่บานปลายครับ\"\n        </div>\n\n        <div style=\"background-color: #0A2540; color: #ffffff; padding: 10px 15px; border-radius: 8px; border-bottom-left-radius: 0; margin-bottom: 15px; display: inline-block; max-width: 90%;\">\n            <strong style=\"color: #F6821F;\">ทีมงาน:</strong> \"ถ้ามีโอกาส หน้าเหมือนว่ามีโอกาสที่จะสร้างอีก จะเรียกเรามาทำงานอีกไหมครับ\"\n        </div>\n    </div>\n\n    <div style=\"background-color: #0A2540; color: white; padding: 40px 20px; border-radius: 12px; text-align: center; margin-top: 40px;\">\n        <h3 style=\"color: #FFC02E; margin-top: 0; margin-bottom: 15px; font-weight: 600;\">สนใจต่อเติมบ้าน ทำรั้ว เทพื้น ปรึกษาเราได้ฟรี!</h3>\n        <p style=\"color: #A9C0D6; margin-bottom: 25px;\">หากคุณกำลังมองหาทีมช่างมืออาชีพที่รับผิดชอบงาน ไม่ทิ้งงาน และใช้วัสดุที่ได้มาตรฐาน สามารถติดต่อสอบถามและประเมินราคาเบื้องต้นกับเราได้เลยครับ</p>\n        \n        <div style=\"margin-bottom: 15px;\">\n            <a href=\"tel:0627188847\" style=\"display: inline-block; background-color: #ffffff; color: #0A2540; font-weight: bold; padding: 10px 20px; border-radius: 4px; text-decoration: none; margin: 5px;\">📞 062-718-8847</a>\n            <a href=\"https://line.me/ti/p/h9SHumuTEB\" style=\"display: inline-block; background-color: #F6821F; color: #ffffff; font-weight: bold; padding: 10px 20px; border-radius: 4px; text-decoration: none; margin: 5px;\">💬 LINE ID: 0627188847</a>\n        </div>\n    </div>\n\n</div>', 'images/blogs/blog1781422269.webp', 27, '2026-06-14-concrete-flooring-chaiyaphum', '2026-06-14 00:31:10', '2026-06-14 00:40:54');
