INSERT INTO `faqs` (`id`, `service_id`, `question`, `answer`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES
(2, 10, 'กำแพงกันดิน สูง 1.5 เมตร ราคาเท่าไหร่', 'ราคาเริ่มต้นที่ 5,500 บาท ขึ้นอยู่กับพื้นที่หน้างาน เพราะจะสัมพันธ์กันกับวัสดุ และอุปกรณ์ที่ใช้ในการก่อสร้าง', 0, 1, '2026-03-27 07:16:47', '2026-03-27 08:02:08'),
(4, 10, 'กำแพงกันดิน สูง 2 เมตร ราคา ราคาเท่าไหร่', 'ราคาเริ่มต้นที่ 6,800 บาท ขึ้นอยู่กับพื้นที่หน้างาน เพราะจะสัมพันธ์กันกับวัสดุ และอุปกรณ์ที่ใช้ในการก่อสร้าง', 0, 1, '2026-03-27 08:35:55', '2026-03-27 08:36:37'),
(5, 10, 'กำ แพง กันดิน สูง 4 เมตร ราคาเท่าไหร่', 'ราคาเริ่มต้นที่ 17,000 บาท ขึ้นอยู่กับพื้นที่หน้างาน เพราะจะสัมพันธ์กันกับวัสดุ และอุปกรณ์ที่ใช้ในการก่อสร้าง', 0, 1, '2026-03-27 08:38:35', '2026-03-27 08:38:35'),
(6, 10, 'กำแพงกันดิน สูง 3 เมตร ราคาเท่าไหร่', 'ราคาเริ่มต้นที่ 11,000 บาท ขึ้นอยู่กับพื้นที่หน้างาน เพราะจะสัมพันธ์กันกับวัสดุ และอุปกรณ์ที่ใช้ในการก่อสร้าง', 0, 1, '2026-03-27 08:39:19', '2026-03-27 08:39:19'),
(7, 10, 'กำ แพง กัน ดิน สูง 2.5 เมตร ราคา', 'ราคาเริ่มต้นที่ 8,000 บาท ขึ้นอยู่กับพื้นที่หน้างาน เพราะจะสัมพันธ์กันกับวัสดุ และอุปกรณ์ที่ใช้ในการก่อสร้าง', 0, 1, '2026-03-27 08:39:59', '2026-03-27 08:39:59'),
(8, 10, 'กำแพงกันดินก่อสร้างใช้เวลาเท่าไหร่', 'ระยะเวลาก่อสร้างขึ้นอยู่กับขนาดและความซับซ้อนของโครงการ โดยทั่วไปกำแพงกันดินขนาดกลางใช้เวลาประมาณ 2-4 สัปดาห์ ตั้งแต่กดเสาเข็มจนถึงบ่มคอนกรีตเสร็จสมบูรณ์ แต่ถ้าเป็นโครงการขนาดใหญ่ที่มีความลึกมาก อาจใช้เวลา 1-2 เดือน', 0, 1, '2026-04-02 02:29:07', '2026-04-02 02:29:07'),
(9, 10, 'เสาเข็ม I-Beam ขนาดไหนเหมาะกับกำแพงกันดิน', 'ขนาดเสาเข็มที่ใช้ขึ้นอยู่กับความลึกของการขุดดินและแรงดันด้านข้าง โดยทั่วไป I-18 ถึง I-22 ใช้กับงานขนาดเล็กถึงกลาง ส่วน I-26 ใช้กับงานขนาดใหญ่ที่ต้องรับแรงดันดินสูง วิศวกรจะเป็นผู้คำนวณและกำหนดขนาดที่เหมาะสมจากข้อมูลดินและแบบก่อสร้าง', 0, 1, '2026-04-02 02:29:55', '2026-04-02 02:29:55'),
(10, 10, 'ค่าใช้จ่ายก่อสร้างกำแพงกันดินประมาณเท่าไหร่?', 'ค่าใช้จ่ายขึ้นอยู่กับหลายปัจจัย ได้แก่ ความยาวของกำแพง ความลึกขุดดิน สภาพดิน ขนาดเสาเข็มที่ใช้ และค่าขนส่งเครื่องจักร แนะนำให้ส่งแบบแปลนเพื่อประเมินราคาที่แม่นยำ เราให้บริการประเมินราคาฟรีหากอยู่ในพื้นที่เขตกรุงเทพฯ ปริมณฑลโดยไม่มีข้อผูกมัด', 0, 1, '2026-04-02 02:30:44', '2026-04-02 02:30:44'),
(11, 10, 'กำแพงกันดินต้องมีใบอนุญาตก่อสร้างไหม?', 'ในกรณีที่เป็นงานก่อสร้างขนาดใหญ่หรืออยู่ในเขตที่กฎหมายกำหนด อาจต้องขอใบอนุญาตก่อสร้างจากหน่วยงานท้องถิ่น นอกจากนี้ยังต้องมีวิศวกรผู้ออกแบบและวิศวกรผู้ควบคุมงานที่มีใบอนุญาตประกอบวิชาชีพ (ใบ กว.) ตามกฎหมาย', 0, 1, '2026-04-02 02:31:00', '2026-04-02 02:31:00'),
(12, 10, 'ต้องเตรียมอะไรก่อนเริ่มงานก่อสร้างกำแพงกันดิน?', 'สิ่งที่ต้องเตรียม ได้แก่ แบบก่อสร้างและแบบวิศวกรรม, ผลเจาะสำรวจดิน (Soil Boring Report), ข้อมูลสาธารณูปโภคใต้ดิน, ใบอนุญาตก่อสร้าง (ถ้าจำเป็น) และการจัดเตรียมพื้นที่ทำงานให้เครื่องจักรเข้าถึงได้ ทีมงานของเราพร้อมให้คำปรึกษาตั้งแต่ขั้นตอนการวางแผน', 0, 1, '2026-04-02 02:31:16', '2026-04-02 02:31:16'),
(13, 10, 'ทำไมต้องบ่มคอนกรีต? ข้ามขั้นตอนนี้ได้ไหม?', 'การบ่มคอนกรีตเป็นขั้นตอนที่ขาดไม่ได้ เพราะช่วยให้ปฏิกิริยาไฮเดรชันในคอนกรีตดำเนินไปอย่างสมบูรณ์ ส่งผลให้คอนกรีตมีกำลังอัดตามที่ออกแบบไว้ หากข้ามขั้นตอนนี้ คอนกรีตอาจแตกร้าว แข็งแรงไม่เต็มที่ และส่งผลต่ออายุการใช้งานของโครงสร้างในระยะยาว', 0, 1, '2026-04-02 02:31:34', '2026-04-02 02:31:34'),
(14, 28, 'รั้วเมทัลชีท ราคาเมตรละ เท่าไหร่', 'เริ่มต้นเมตรละ1,000 บาท ขึ้นอยู่กับสภาพพื้นที่หน้างาน และวัสดุอุปกรณ์ ที่ใช้ในการก่อสร้าง', 0, 1, '2026-04-08 04:42:40', '2026-04-08 04:42:40'),
(15, 28, 'ทำรั้วบ้านราคาเท่าไหร่', '1. วัสดุที่ใช้นี่คือปัจจัยหลักที่มีผลมากที่สุด เช่น\r\nคอนกรีตสำเร็จรูป — ราคาปานกลาง ทนทาน นิยมมาก\r\nอิฐมอญ/บล็อก — ราคาสูงกว่า เพราะใช้แรงงานมาก\r\nเหล็กดัด/อลูมิเนียม — ราคาขึ้นอยู่กับดีไซน์และความหนา\r\nไม้ — ราคาแปรผันสูง บำรุงรักษามาก\r\nPVC/Vinyl — ราคาถูก แต่ทนแดดร้อนในไทยได้จำกัด\r\n2. ความสูงและความหนายิ่งสูงและหนา → ใช้วัสดุมากขึ้น → ราคาสูงขึ้นตามสัดส่วน\r\n3. ความยาวรอบพื้นที่ (เมตร)ราคามักคิดเป็น บาท/เมตร ดังนั้นพื้นที่ที่ดินใหญ่ = ต้นทุนรวมสูง\r\n4. ฐานรากและดินที่ตั้ง\r\nดินอ่อน/ดินเหนียว → ต้องเจาะเสาเข็มเพิ่ม → ราคาสูงขึ้น\r\nพื้นที่ลาดเอียงหรือมีระดับต่างกัน → งานซับซ้อนขึ้น\r\n5. ดีไซน์และความซับซ้อน\r\nรั้วเรียบ vs. มีลวดลาย/โค้ง/ฉลุ\r\nมีประตูรั้ว (บานเดี่ยว/คู่/สไลด์) → เพิ่มต้นทุนมาก\r\n6. ค่าแรงงานแต่\r\nละพื้นที่ในไทยมีค่าแรงต่างกัน (กทม. vs. ต่างจังหวัด)\r\nช่วงเทศกาลหรือแรงงานขาดแคลน → ค่าแรงสูงขึ้น\r\n7. ราคาวัสดุตลาด ณ ช่วงเวลานั้น\r\nราคาปูนซีเมนต์ เหล็ก และพลังงาน มีความผันผวนตามตลาดโลก\r\n8. การเดินระบบเพิ่มเติมติดกล้องวงจรปิด / ระบบไฟ / รั้วไฟฟ้า → เพิ่มต้นทุนทั้งวัสดุและแรงงาน', 0, 1, '2026-04-08 05:07:54', '2026-04-08 05:07:54'),
(16, 28, 'ราคา รั้วบ้านแบบ ต่างๆ ราคาเท่าไหร่', 'รั้วก่อฉาบ(ลงเสาเข็ม) สูง 2 เมตร เริ่มต้น 4,000 บาท/เมตร\r\nรั้วเหล็ก  สูง 1.50 เมตร เริ่มต้น 1,700 บาท/เมตร\r\nรั้วเมทัลชีท เริ่มต้น 1,000 บาท/เมตร', 0, 1, '2026-04-08 05:57:36', '2026-04-08 05:57:36'),
(17, 4, 'วิธี ถมดิน ให้แน่น มีวิธีการอย่างไร', '1. เตรียมพื้นที่ \r\nก่อนถม ห้ามถมทับหญ้าหรือขยะเด็ดขาด เพราะเมื่ออินทรีย์สารเหล่านี้เน่าเปื่อย จะเกิดช่องว่างใต้ดินทำให้ดินทรุดตัวเป็นหลุม\r\n2. เลือกชนิดดินให้เหมาะกับงาน\r\n- ดินถมทั่วไป/ดินซีแลนด์: ราคาถูก เหมาะกับการปรับระดับพื้นที่กว้างๆ\r\n- ดินดาน (Lateritic Soil): ตัวนี้คือพระเอกสำหรับการถมเพื่อสร้างอาคาร เพราะมีส่วนผสมของหินกรวดและดินเหนียว เมื่อบดอัดแล้วจะมีความหนาแน่นสูงมากและแข็งตัวเร็ว\r\n- ทรายถม: ใช้ในกรณีที่ต้องการการระบายน้ำดี แต่บดอัดให้แน่นยากกว่าดินดานหากไม่มีเครื่องมือเฉพาะทาง\r\n3. ถมแบบแบ่งชั้น\r\n- ความหนาต่อชั้น: ควรลงดินทีละชั้นหนาไม่เกิน 20-30 เซนติเมตร\r\n- การบดอัด: ใช้รถบด (Vibratory Roller) วิ่งทับให้แน่นในแต่ละชั้นก่อนจะลงชั้นถัดไป\r\n- การควบคุมความชื้น (Optimum Moisture Content): ดินที่แห้งเกินไปหรือแฉะเกินไปจะบดอัดไม่ขึ้น ดินต้องมีความชื้นพอเหมาะ (ลองกำดูแล้วจับตัวเป็นก้อนแต่ไม่แฉะติดมือ)\r\n4. ระยะเวลาการ \"เซ็ตตัว\"\r\n- ถ้าถมเพื่อสร้างบ้าน: ควรทิ้งไว้ให้ผ่านฤดูฝนอย่างน้อย 1 รอบ (ประมาณ 6 เดือน - 1 ปี)\r\n- ถ้าต้องสร้างทันที: ต้องใช้การตอกเสาเข็มปูพรมหรือเสาเข็มปูพรมแบบปูพื้น (Slab on Pile) เพื่อถ่ายน้ำหนักลงสู่ชั้นดินที่แข็งแรงกว่า\r\n5. การป้องกันดินไหล (Soil Retention)\r\nถ้าที่ดินคุณอยู่สูงกว่าเพื่อนบ้าน ต้องทำ \"กำแพงกันดิน\" ครับ มิฉะนั้นเวลาฝนตก ดินที่คุณถมไว้จะไหลไปบ้านคนอื่น หรือทำให้ขอบที่ดินเราทรุดตัวลง\r\n- ควรออกแบบให้มีช่องระบายน้ำ (Weep holes) เพื่อลดแรงดันน้ำหลังกำแพง', 0, 1, '2026-04-21 02:51:34', '2026-04-21 02:51:34'),
(18, 4, 'ถมดินแล้ว สร้างบ้านได้เลยไหม', 'ควรทิ้งให้ผ่านฤดูฝนอย่างน้อย 1 รอบ (6-12 เดือน)', 0, 1, '2026-04-21 02:55:42', '2026-04-21 02:55:42');
